export const ACCOUNTING_FAQ: AccountingFaqEntry[] = [
  {id: "faq-001", question: "erp k ho?", questionNormalized: "erp k ho", questionType: "definition", topic: "software", answerNe: "ERP = Enterprise Resource Planning. Yo ek software ho jasle company ko sabai kaam (accounting, inventory, sales, purchase, HR, payroll) ek thau ma manage garchha. Nepal ma Busy, Tally, Sutra ERP jasta software use hunchha.", answerEn: "ERP = Enterprise Resource Planning. Software that manages all company operations (accounting, inventory, sales, HR) in one place. In Nepal, Busy, Tally, Sutra ERP are commonly used.", answerShortNe: "ERP = Business ko sabai kaam ek software ma garne system.", relatedQuestions: ["erp software k ho", "accounting software k ho", "tally k ho"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-002", question: "accounting software k ho?", questionNormalized: "accounting software k ho", questionType: "definition", topic: "software", answerNe: "Accounting software ek computer program ho jo company ko financial records (debit, credit, income, expense) manage garchha. Yo ledger, journal, trial balance, financial statements automatically banau ta.", answerEn: "Accounting software is a computer program that manages financial records including debits, credits, income, and expenses. It automatically creates ledgers, journals, trial balances, and financial statements.", answerShortNe: "Yo software company ko paise ko record rakhne program ho.", relatedQuestions: ["tally k ho", "busy software k ho", "accounting kya garnu"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-003", question: "tally software k ho?", questionNormalized: "tally software k ho", questionType: "definition", topic: "software", answerNe: "Tally ek popular accounting software ho jo inventory, sales, purchase, accounting sabai manage garchha. Nepal ma SME, traders, chartered accountants lai bahut use hunchha. Yo GST/VAT compliant pani ho.", answerEn: "Tally is a popular accounting software that manages inventory, sales, purchases, and accounting. Widely used by SMEs, traders, and chartered accountants in Nepal. It is GST/VAT compliant.", answerShortNe: "Tally = Popular accounting aur inventory management software.", relatedQuestions: ["tally vs busy", "tally kasari use garnu", "tally ko cost kati"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-004", question: "busy software k ho?", questionNormalized: "busy software k ho", questionType: "definition", topic: "software", answerNe: "Busy ek Nepali-friendly accounting software ho. Yo GST, TDS, VAT compliant ho aur Nepal ko business requirement ke hisaab se banai cha. SME ra small traders le bahut use garchha.", answerEn: "Busy is a Nepal-friendly accounting software that is compliant with GST, TDS, and VAT regulations. Designed according to Nepal's business requirements and widely used by SMEs and small traders.", answerShortNe: "Busy = Nepali business ke liye special accounting software.", relatedQuestions: ["busy vs tally", "busy kasari use garnu", "busy ka license cost"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-005", question: "VAT k ho?", questionNormalized: "vat k ho", questionType: "definition", topic: "tax", answerNe: "VAT = Value Added Tax. Nepal ma VAT rate 13% ho. Ye tax customer le product/service kinu time dinu parcha. Business-le VAT collected garchha aur government-lai deposit garchha.", answerEn: "VAT = Value Added Tax. In Nepal, VAT rate is 13%. This tax is paid by customers when purchasing products/services. Businesses collect VAT and deposit it to the government.", answerShortNe: "VAT = 13% tax jo customer le pay garchha.", relatedQuestions: ["vat kasari calculate garnu", "vat deposit kasari garnu", "vat exempt products"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-006", question: "TDS k ho?", questionNormalized: "tds k ho", questionType: "definition", topic: "tax", answerNe: "TDS = Tax Deducted at Source. Jab ek company doosre company ko service karta hai, to TDS cut garchha aur government-ko deposit garchha. TDS rate alag-alag service ke liye different ho (2%, 5%, 10%).", answerEn: "TDS = Tax Deducted at Source. When one company provides services to another, TDS is deducted and deposited to the government. TDS rates vary by service type (2%, 5%, 10%).", answerShortNe: "TDS = Service payment se government ko hisaab se tax cut garchha.", relatedQuestions: ["tds rate k ho", "tds kasari calculate garnu", "tds deposit kasari garnu"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-007", question: "PAN registration k ho?", questionNormalized: "pan registration k ho", questionType: "definition", topic: "registration", answerNe: "PAN = Permanent Account Number. Ye Nepal ke alyaw tax department ko side se ek unique number ho jise individual ya business ke tax record ke liye use hota hai. PAN na hone se business nahi chalau ta.", answerEn: "PAN = Permanent Account Number. A unique number issued by Nepal's tax department for individuals and businesses to track tax records. Business cannot operate without PAN.", answerShortNe: "PAN = Government ka tax ID number jise business ko tax record track hota hai.", relatedQuestions: ["pan registration kasari garnu", "pan application form", "pan certificate kaise milta hai"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-008", question: "company registration kasari garnu?", questionNormalized: "company registration kasari garnu", questionType: "process", topic: "registration", answerNe: "Company registration kelag steps hote hain: 1) Company name approve karau government-se 2) Memorandum of Association (MOA) banau 3) Articles of Association (AOA) prepare garnu 4) Company registration office-ma submit garnu 5) Certificate of Incorporation mile 6) PAN registration garnu 7) VAT registration garnu.", answerEn: "Company registration involves: 1) Get company name approved by government 2) Prepare Memorandum of Association (MOA) 3) Prepare Articles of Association (AOA) 4) Submit to company registration office 5) Receive Certificate of Incorporation 6) Register for PAN 7) Register for VAT.", answerShortNe: "Company registration = Government-ma name approve karau aur official documents submit garnu.", relatedQuestions: ["company registration ke liye documents", "registration cost", "registration time"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-009", question: "trade license k ho?", questionNormalized: "trade license k ho", questionType: "definition", topic: "registration", answerNe: "Trade license ek permission letter ho jo local government (municipality/rural municipality) se milta hai. Isse business legally chalau ta sakta hai. Trade license renewal every year karna padta hai.", answerEn: "Trade license is a permission letter issued by local government (municipality/rural municipality) to legally operate a business. Trade license must be renewed annually.", answerShortNe: "Trade license = Local government ki permission jo business chalane ke liye chahiye.", relatedQuestions: ["trade license kasari karau", "trade license cost", "trade license validity"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-010", question: "invoice k ho?", questionNormalized: "invoice k ho", questionType: "definition", topic: "documents", answerNe: "Invoice ek document ho jise seller customer-ko deta hai jab product/service sell karta hai. Ismein product details, quantity, price, VAT, total amount likha hota hai. Invoice ka number aur date zaroor likha hona chahiye.", answerEn: "Invoice is a document provided by seller to customer when selling products/services. It contains product details, quantity, price, VAT, and total amount. Invoice must have number and date.", answerShortNe: "Invoice = Sales document jismein product aur price ka detail hota hai.", relatedQuestions: ["invoice template", "invoice kasari banau", "invoice number system"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-011", question: "bill aur invoice ma k farak ho?", questionNormalized: "bill aur invoice ma k farak ho", questionType: "comparison", topic: "documents", answerNe: "Invoice aur bill dono same hote hain lekin kuch difference hai. Invoice = seller deta hai product sell karte time. Bill = paise pay karte time diya jata hai. Kisi kisi cases me invoice aur bill alag alag hote hain.", answerEn: "Invoice and bill are similar but have differences. Invoice = given by seller when selling product. Bill = given when payment is made. In some cases, invoice and bill are separate.", answerShortNe: "Invoice = sale ke time, Bill = payment ke time diya jata hai.", relatedQuestions: ["receipt k ho", "invoice vs receipt", "bill ka format"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-012", question: "receipt k ho?", questionNormalized: "receipt k ho", questionType: "definition", topic: "documents", answerNe: "Receipt ek document ho jo customer-ko diya jata hai jab paise pay karta hai. Ismein paise ki amount, date, aur payment method likha hota hai. Receipt customer ke pass proof ke tarah rakha jata hai.", answerEn: "Receipt is a document given to customer when payment is made. It contains payment amount, date, and payment method. Customer keeps receipt as proof.", answerShortNe: "Receipt = Payment proof document jo customer ko diya jata hai.", relatedQuestions: ["receipt format", "receipt numbering", "digital receipt"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-013", question: "voucher k ho?", questionNormalized: "voucher k ho", questionType: "definition", topic: "documents", answerNe: "Voucher ek internal document ho jo business internally use karta hai. Ismein transaction ka detail likha hota hai - kya likha hai, kitna rupya likha hai, aur approval likha hai. Voucher 4 types hote hain: Receipt Voucher, Payment Voucher, Journal Voucher, Debit/Credit Voucher.", answerEn: "Voucher is an internal document used by business to record transactions. It contains transaction details, amount, and approval. There are 4 types: Receipt Voucher, Payment Voucher, Journal Voucher, Debit/Credit Voucher.", answerShortNe: "Voucher = Internal document jismein transaction record hota hai.", relatedQuestions: ["voucher types", "voucher numbering", "journal voucher"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-014", question: "SSF k ho?", questionNormalized: "ssf k ho", questionType: "definition", topic: "employee_benefits", answerNe: "SSF = Social Security Fund. Nepal me jab employee kisi job ma kaam karta hai, to employer aur employee dono SSF me contribute karte hain. Rate normally 10% hai jo employer pay karta hai aur 10% jo employee salary se cut kiya jata hai. Senior citizen (60+ age) ka rate 11% ho sakta hai.", answerEn: "SSF = Social Security Fund. In Nepal, when an employee works, both employer and employee contribute to SSF. Rate is normally 10% paid by employer and 10% deducted from employee salary. Senior citizens (60+) may have 11% rate.", answerShortNe: "SSF = Employee ko old age me pension dene ke liye fund jismein employer aur employee dono contribute karte hain.", relatedQuestions: ["ssf contribution", "ssf calculation", "ssf withdrawal"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-015", question: "gratuity k ho?", questionNormalized: "gratuity k ho", questionType: "definition", topic: "employee_benefits", answerNe: "Gratuity ek lump sum amount ho jo employee-ko milta hai jab wo job chhod deta hai ya kaam se retire hota hai. Gratuity calculate hota hai based on salary aur years of service. Normally 15 din ki salary per year of service diya jata hai.", answerEn: "Gratuity is a lump sum amount given to employee when they leave or retire from job. It is calculated based on salary and years of service. Normally 15 days salary per year of service is given.", answerShortNe: "Gratuity = Final payment jo employee ko job chhod ke jaate time milta hai.", relatedQuestions: ["gratuity calculation", "gratuity policy", "gratuity eligibility"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-016", question: "minimum wage Nepal ma kati ho?", questionNormalized: "minimum wage nepal ma kati ho", questionType: "calculation", topic: "employee_benefits", answerNe: "Minimum wage Nepal ma different category ke hisaab se different ho. Manufacturing: Rs. 18,000, Service sector: Rs. 15,600, Domestic worker: Rs. 10,000 (2024 rates). Minimum wage every year update hota hai.", answerEn: "Minimum wage in Nepal varies by sector. Manufacturing: Rs. 18,000, Service sector: Rs. 15,600, Domestic worker: Rs. 10,000 (2024 rates). Minimum wage is updated annually.", answerShortNe: "Minimum wage = Government ka lowest salary jo kisi ko dena zaroor hota hai.", relatedQuestions: ["minimum wage 2024", "minimum wage calculation", "minimum wage violation"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-017", question: "bank account kaise kholu?", questionNormalized: "bank account kaise kholu", questionType: "process", topic: "banking", answerNe: "Bank account khulne ke liye: 1) Bank-ma jaao 2) Account opening form bharu 3) Identity proof (passport, citizenship certificate) lao 4) Address proof (electricity bill, tax receipt) lao 5) Initial deposit karo (minimum amount bank define karta hai) 6) Cheque book aur debit card mil jayega.", answerEn: "To open bank account: 1) Go to bank 2) Fill account opening form 3) Submit identity proof (passport, citizenship certificate) 4) Submit address proof (electricity bill, tax receipt) 5) Make initial deposit (minimum amount as per bank) 6) Receive cheque book and debit card.", answerShortNe: "Bank account = Bank-ma money rakhne ke liye khata jo identity aur address proof se khul ta.", relatedQuestions: ["bank account types", "joint account", "nri account"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-018", question: "cheque kaise likhu?", questionNormalized: "cheque kaise likhu", questionType: "process", topic: "banking", answerNe: "Cheque likne ke steps: 1) Cheque number dekhu (top right) 2) Date likhu (in words and numbers) 3) Payee ka naam likhu ('Pay to' line par) 4) Words me amount likhu (rupees line par) 5) Figures me amount likhu (amount box me) 6) Memo likhu (optional, purpose ke liye) 7) Signature karnu (account holder ko) 8) Cheque validate kare aur bank ko submit kare.", answerEn: "Steps to write cheque: 1) Check cheque number (top right) 2) Write date (in words and numbers) 3) Write payee name ('Pay to' line) 4) Write amount in words (rupees line) 5) Write amount in figures (amount box) 6) Write memo (optional, for purpose) 7) Sign (account holder) 8) Validate cheque and submit to bank.", answerShortNe: "Cheque = Bank se paise nikalne ka order likhat jo payee ko paise deta hai.", relatedQuestions: ["cheque bounce", "post dated cheque", "cheque clearing time"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-019", question: "online banking kasari use garnu?", questionNormalized: "online banking kasari use garnu", questionType: "process", topic: "banking", answerNe: "Online banking use karne ke liye: 1) Bank-se online banking activate karay 2) Username aur password laye 3) Bank ka website ya mobile app kholu 4) Login karo 5) Pin ya OTP enter karo 6) Transaction karo (transfer, payment, check balance, etc.) 7) Confirmation receive karo.", answerEn: "To use online banking: 1) Activate online banking with bank 2) Get username and password 3) Open bank website or mobile app 4) Login 5) Enter PIN or OTP 6) Perform transaction (transfer, payment, check balance) 7) Receive confirmation.", answerShortNe: "Online banking = Internet se bank account access karke paise transfer ya bill pay karna.", relatedQuestions: ["online banking safety", "mobile banking app", "password change"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-020", question: "ledger k ho?", questionNormalized: "ledger k ho", questionType: "definition", topic: "accounting", answerNe: "Ledger ek book ya document ho jismein company ke sabai accounts likhe hote hain (assets, liabilities, income, expense). Har account ke liye ledger page hota hai jismein debit aur credit entries likhi hoti hain. Ledger prepare karne ke liye journal entries use hote hain.", answerEn: "Ledger is a book/document containing all company accounts (assets, liabilities, income, expense). Each account has a ledger page with debit and credit entries. Ledger is prepared from journal entries.", answerShortNe: "Ledger = Accounting book jismein har account ki detailed entries likhi hoti hain.", relatedQuestions: ["journal vs ledger", "ledger posting", "subsidiary ledger"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-021", question: "journal k ho?", questionNormalized: "journal k ho", questionType: "definition", topic: "accounting", answerNe: "Journal ek chronological record ho jismein sabhi transactions likhe hote hain. Har transaction me debit aur credit account likha hota hai aur rules follow hota hai: debit = credit. Journal ko 'Book of Original Entry' kaha jata hai kyunki transaction pehle journal me likha jata hai phir ledger me.", answerEn: "Journal is a chronological record of all transactions. Each transaction shows debit and credit accounts following the rule: debit = credit. Journal is called 'Book of Original Entry' as transactions are recorded here first, then transferred to ledger.", answerShortNe: "Journal = Daily record jismein har transaction date ke hisaab se likha hota hai.", relatedQuestions: ["journal entry", "journal vs ledger", "subsidiary journal"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-022", question: "trial balance k ho?", questionNormalized: "trial balance k ho", questionType: "definition", topic: "accounting", answerNe: "Trial balance ek statement ho jismein sabhi ledger accounts likhe hote hain aur unki debit/credit balance likhi hoti hai. Trial balance banane ka purpose check karna hota hai ki ledger entries mein koi error to nahi hai. Agar total debit = total credit ho, to accounting correct ho sakta hai.", answerEn: "Trial balance is a statement listing all ledger accounts with their debit/credit balances. Purpose is to check if ledger entries are correct. If total debit = total credit, accounting is likely correct.", answerShortNe: "Trial balance = Final check document jo ledger ke accounts ko verify karta hai.", relatedQuestions: ["trial balance format", "trial balance preparation", "errors in trial balance"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-023", question: "financial statements k ho?", questionNormalized: "financial statements k ho", questionType: "definition", topic: "accounting", answerNe: "Financial statements company ke financial condition ka summary hote hain. Main 3 financial statements hote hain: 1) Income Statement (profit/loss dikhaata hai) 2) Balance Sheet (assets, liabilities, equity dikhaata hai) 3) Cash Flow Statement (cash inflow/outflow dikhaata hai). Financial statements annually prepare kiye jate hain.", answerEn: "Financial statements are summaries of company's financial condition. Main 3 statements are: 1) Income Statement (shows profit/loss) 2) Balance Sheet (shows assets, liabilities, equity) 3) Cash Flow Statement (shows cash inflow/outflow). Prepared annually.", answerShortNe: "Financial statements = Company ke paise ka complete report jismein income, assets, aur cash likha hota hai.", relatedQuestions: ["income statement", "balance sheet", "cash flow statement"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-024", question: "income statement kaise banau?", questionNormalized: "income statement kaise banau", questionType: "process", topic: "accounting", answerNe: "Income statement banane ke liye: 1) Revenue collect karo (sales, service income, etc.) 2) Cost of Goods Sold (COGS) calculate karo 3) Gross Profit = Revenue - COGS 4) Operating Expenses collect karo (salary, rent, utilities) 5) Operating Income = Gross Profit - Operating Expenses 6) Other income/expense add/subtract karo 7) Net Income = Operating Income ± Other items. Income statement format: Revenue - Expenses = Profit/Loss.", answerEn: "To prepare income statement: 1) Collect revenue (sales, service income) 2) Calculate Cost of Goods Sold (COGS) 3) Gross Profit = Revenue - COGS 4) Collect Operating Expenses (salary, rent, utilities) 5) Operating Income = Gross Profit - Operating Expenses 6) Add/subtract other income/expense 7) Net Income = Operating Income ± Other items.", answerShortNe: "Income statement = Revenue - Expenses = Profit/Loss likhat jo monthly/yearly banaya jata hai.", relatedQuestions: ["income statement format", "revenue recognition", "expense classification"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-025", question: "balance sheet kaise banau?", questionNormalized: "balance sheet kaise banau", questionType: "process", topic: "accounting", answerNe: "Balance sheet banane ke liye: 1) Sabhi assets likho (current aur non-current) 2) Sabhi liabilities likho (current aur non-current) 3) Owner's Equity likho 4) Formula check karo: Assets = Liabilities + Equity 5) Balance sheet ke 2 side hote hain: left side = assets, right side = liabilities + equity. Balance sheet typically year end-ko banaya jata hai.", answerEn: "To prepare balance sheet: 1) List all assets (current and non-current) 2) List all liabilities (current and non-current) 3) List owner's equity 4) Check formula: Assets = Liabilities + Equity 5) Balance sheet has 2 sides: left = assets, right = liabilities + equity. Typically prepared at year-end.", answerShortNe: "Balance sheet = Assets likho left side par, Liabilities + Equity right side par. Dono equal hone chahiye.", relatedQuestions: ["balance sheet format", "current assets", "non-current assets"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-026", question: "debit aur credit ka matlab kya ho?", questionNormalized: "debit aur credit ka matlab kya ho", questionType: "definition", topic: "accounting", answerNe: "Debit aur credit accounting ke foundation hain. Debit = left side, Credit = right side. Rules hote hain: Assets/Expenses increase se debit, liabilities/income increase se credit. Ek simple rule: jo income/liabilities/equity hai wo credit side, jo assets/expenses hai wo debit side. Har transaction me debit = credit.", answerEn: "Debit and credit are foundation of accounting. Debit = left side, Credit = right side. Rules: Assets/Expenses increase = debit, Liabilities/Income increase = credit. Simple rule: Income/Liabilities/Equity = credit side, Assets/Expenses = debit side. In every transaction, debit = credit.", answerShortNe: "Debit = Left side (Assets/Expenses), Credit = Right side (Income/Liabilities). Dono equal hone chahiye.", relatedQuestions: ["debit credit rules", "debit credit examples", "t account"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-027", question: "assets ka matlab kya ho?", questionNormalized: "assets ka matlab kya ho", questionType: "definition", topic: "accounting", answerNe: "Assets wo cheezein hain jinhe company own karta hai aur future benefit de skti hain. Assets 2 types hote hain: Current Assets (cash, bank, inventory, receivables - jo 1 year ke andar convert ho sakte hain) aur Non-Current Assets (machinery, buildings, land - long term assets).", answerEn: "Assets are things owned by company that provide future benefit. 2 types: Current Assets (cash, bank, inventory, receivables - convertible within 1 year) and Non-Current Assets (machinery, buildings, land - long-term).", answerShortNe: "Assets = Company ke paas jo valuable cheezein hain jaise paise, inventory, machinery, building.", relatedQuestions: ["current assets", "non-current assets", "asset classification"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-028", question: "liabilities ka matlab kya ho?", questionNormalized: "liabilities ka matlab kya ho", questionType: "definition", topic: "accounting", answerNe: "Liabilities wo debts/obligations hain jo company-ko pay karne hote hain. Liabilities 2 types hote hain: Current Liabilities (jo 1 year ke andar pay honge - payables, short-term loans) aur Non-Current Liabilities (long-term loans, bonds - jo 1 year se zyada me pay honge).", answerEn: "Liabilities are debts/obligations company must pay. 2 types: Current Liabilities (due within 1 year - payables, short-term loans) and Non-Current Liabilities (long-term - due after 1 year).", answerShortNe: "Liabilities = Company ke paas jo debts hain jo pay karne hote hain.", relatedQuestions: ["current liabilities", "non-current liabilities", "liability examples"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-029", question: "equity ka matlab kya ho?", questionNormalized: "equity ka matlab kya ho", questionType: "definition", topic: "accounting", answerNe: "Equity owner ke ownership stake ko represent karta hai. Equity = Assets - Liabilities. Jo paise owner ek company me invest karta hai wo equity ban jata hai. Agar company profit karti hai to equity increase hoti hai, agar loss hote toh decrease hoti hai.", answerEn: "Equity represents owner's ownership stake in company. Equity = Assets - Liabilities. Money invested by owner becomes equity. If company profits, equity increases; if loses, equity decreases.", answerShortNe: "Equity = Company ka jo hissa owner ka hai = Assets - Liabilities.", relatedQuestions: ["stockholders equity", "owners equity", "retained earnings"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-030", question: "revenue ka matlab kya ho?", questionNormalized: "revenue ka matlab kya ho", questionType: "definition", topic: "accounting", answerNe: "Revenue wo paise hain jo company kisi ko product/service sell karke earn karta hai. Revenue 2 types hote hain: Operating Revenue (main business se - sales) aur Non-Operating Revenue (investments se, interest se). Revenue always credit side me likha jata hai.", answerEn: "Revenue is money earned by company from selling products/services. 2 types: Operating Revenue (from main business - sales) and Non-Operating Revenue (from investments, interest). Revenue is always on credit side.", answerShortNe: "Revenue = Paise jo company sell karke earn karta hai.", relatedQuestions: ["sales revenue", "revenue recognition", "operating vs non-operating revenue"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-031", question: "expense ka matlab kya ho?", questionNormalized: "expense ka matlab kya ho", questionType: "definition", topic: "accounting", answerNe: "Expense wo paise hote hain jo company kisi cheez buy/use karne ke liye spend karta hai - jaise salary, rent, utilities, supplies. Expenses profit ko reduce karte hain. Expenses debit side me likhe jate hain. Jab tak expense na ho tab tak kharcha likha nahi jata.", answerEn: "Expenses are money spent by company to buy/use things (salary, rent, utilities, supplies). Expenses reduce profit. Expenses are on debit side. Expense is recognized only when incurred.", answerShortNe: "Expense = Paise jo company spend karta hai business chalane ke liye.", relatedQuestions: ["operating expenses", "capital expenditure", "expense classification"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-032", question: "profit ka matlab kya ho?", questionNormalized: "profit ka matlab kya ho", questionType: "definition", topic: "accounting", answerNe: "Profit = Revenue - Expenses. Jab company ke revenue expenses se zyada ho tab profit hota hai. Profit company ko good financial health dikhaata hai. Profit 2 types hote hain: Gross Profit (Revenue - COGS) aur Net Profit (Revenue - Total Expenses).", answerEn: "Profit = Revenue - Expenses. When company's revenue exceeds expenses, profit occurs. Profit shows good financial health. 2 types: Gross Profit (Revenue - COGS) and Net Profit (Revenue - Total Expenses).", answerShortNe: "Profit = Revenue - Expenses = Company ke paise increase hona.", relatedQuestions: ["gross profit", "net profit", "operating profit"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-033", question: "loss ka matlab kya ho?", questionNormalized: "loss ka matlab kya ho", questionType: "definition", topic: "accounting", answerNe: "Loss = Expenses - Revenue. Jab company ke expenses revenue se zyada ho tab loss hota hai. Loss company ko bad financial health dikhaata hai. Loss owner ke equity ko reduce karta hai. Loss minimize karne ke liye company ko expenses control karne chahiye ya revenue increase karni chahiye.", answerEn: "Loss = Expenses - Revenue. When company's expenses exceed revenue, loss occurs. Loss indicates poor financial health. Loss reduces owner's equity. To minimize loss, company should control expenses or increase revenue.", answerShortNe: "Loss = Expenses revenue se zyada hona = Company ko nuksaan hona.", relatedQuestions: ["loss analysis", "breakeven", "cost control"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-034", question: "cash flow ka matlab kya ho?", questionNormalized: "cash flow ka matlab kya ho", questionType: "definition", topic: "accounting", answerNe: "Cash flow = cash inflow - cash outflow. Ye dikhaata hai ki company ke pas actual cash kaise move kar raha hai. Cash flow 3 categories se hota hai: Operating Activities (daily business se), Investing Activities (machinery khareedna/sell karna), Financing Activities (loans lena/dena). Good cash flow company ko financially healthy rakhta hai.", answerEn: "Cash flow = cash inflow - cash outflow. Shows how actual cash moves in company. 3 categories: Operating Activities (daily business), Investing Activities (buy/sell machinery), Financing Activities (loans). Good cash flow keeps company financially healthy.", answerShortNe: "Cash flow = Actual paise jo aata aur jata hai company ko.", relatedQuestions: ["operating cash flow", "investing cash flow", "financing cash flow"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-035", question: "reconciliation ka matlab kya ho?", questionNormalized: "reconciliation ka matlab kya ho", questionType: "definition", topic: "accounting", answerNe: "Reconciliation ek process hai jisse 2 records ko compare karte hain ki dono same match kar rahe hain ya nahi. Bank reconciliation sab se common hai - bank statement ko compare karte hain company ke records ke saath. Agar match ho to bank ka balance correct hai, agar na mile to kisi error ko check karna padta hai.", answerEn: "Reconciliation is process of comparing 2 records to ensure they match. Bank reconciliation is most common - comparing bank statement with company records. If match, balance is correct; if not, errors need to be checked.", answerShortNe: "Reconciliation = 2 records ko compare karke check karna ki match kar rahe hain ya nahi.", relatedQuestions: ["bank reconciliation", "cash reconciliation", "receivable reconciliation"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-036", question: "VAT kasari calculate garnu?", questionNormalized: "vat kasari calculate garnu", questionType: "calculation", topic: "tax", answerNe: "VAT calculation: 1) Taxable value (product/service price) lao 2) VAT rate (13% in Nepal) apply karo: VAT Amount = Taxable Value × 13% 3) Total Price = Taxable Value + VAT Amount. Example: Product price Rs. 1000, VAT = 1000 × 13% = 130, Total = 1000 + 130 = 1130.", answerEn: "VAT calculation: 1) Take taxable value (product/service price) 2) Apply VAT rate (13% in Nepal): VAT Amount = Taxable Value × 13% 3) Total Price = Taxable Value + VAT Amount. Example: Product Rs. 1000, VAT = 1000 × 13% = 130, Total = 1000 + 130 = 1130.", answerShortNe: "VAT = Price × 13%. Example: 1000 × 13% = 130 VAT, Total = 1130.", relatedQuestions: ["vat on different products", "vat exempted items", "vat return"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-037", question: "TDS kasari calculate garnu?", questionNormalized: "tds kasari calculate garnu", questionType: "calculation", topic: "tax", answerNe: "TDS calculation: 1) Service amount lao 2) Applicable TDS rate use karo (jaise 2%, 5%, 10% etc. service type par depend karta hai) 3) TDS Amount = Service Amount × TDS Rate. Example: Contractor payment Rs. 10,000, TDS rate 2%, TDS = 10,000 × 2% = 200, Payment = 10,000 - 200 = 9,800.", answerEn: "TDS calculation: 1) Take service amount 2) Apply applicable TDS rate (2%, 5%, 10% etc. depends on service type) 3) TDS Amount = Service Amount × TDS Rate. Example: Contractor payment Rs. 10,000, TDS rate 2%, TDS = 10,000 × 2% = 200, Payment = 10,000 - 200 = 9,800.", answerShortNe: "TDS = Amount × Rate (2%, 5%, 10%). Example: 10,000 × 2% = 200 TDS, Payment = 9,800.", relatedQuestions: ["tds rates", "tds deposit", "tds certificate"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-038", question: "gratuity kasari calculate garnu?", questionNormalized: "gratuity kasari calculate garnu", questionType: "calculation", topic: "employee_benefits", answerNe: "Gratuity calculation: 1) Monthly salary lao 2) Years of service lao (multiple of 15 days ke barabar) 3) Formula: Gratuity = (Monthly Salary / 30) × 15 × Years of Service. Example: Salary Rs. 10,000, Service 5 years, Gratuity = (10,000/30) × 15 × 5 = 333.33 × 15 × 5 = Rs. 25,000.", answerEn: "Gratuity calculation: 1) Take monthly salary 2) Take years of service 3) Formula: Gratuity = (Monthly Salary / 30) × 15 × Years of Service. Example: Salary Rs. 10,000, Service 5 years, Gratuity = (10,000/30) × 15 × 5 = 333.33 × 15 × 5 = Rs. 25,000.", answerShortNe: "Gratuity = (Salary / 30) × 15 × Years. Example: (10,000/30) × 15 × 5 = 25,000.", relatedQuestions: ["gratuity policy", "gratuity eligibility", "gratuity deduction"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-039", question: "SSF contribution kasari calculate garnu?", questionNormalized: "ssf contribution kasari calculate garnu", questionType: "calculation", topic: "employee_benefits", answerNe: "SSF contribution: 1) Employee ka base salary lao 2) SSF rate lao (10% normally) 3) Employer contribution = Salary × 10% 4) Employee contribution = Salary × 10% (salary se cut hota hai). Example: Salary Rs. 20,000, Employer SSF = 20,000 × 10% = 2,000, Employee SSF = 20,000 × 10% = 2,000, Total = 4,000.", answerEn: "SSF contribution: 1) Take employee base salary 2) Take SSF rate (10% normally) 3) Employer contribution = Salary × 10% 4) Employee contribution = Salary × 10% (deducted from salary). Example: Salary Rs. 20,000, Employer SSF = 20,000 × 10% = 2,000, Employee SSF = 20,000 × 10% = 2,000, Total = 4,000.", answerShortNe: "SSF = Salary × 10% (employer) + Salary × 10% (employee). Example: 20,000 = 2,000 + 2,000.", relatedQuestions: ["ssf withdrawal", "ssf benefits", "ssf contribution late"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-040", question: "double entry bookkeeping ka matlab kya ho?", questionNormalized: "double entry bookkeeping ka matlab kya ho", questionType: "definition", topic: "accounting", answerNe: "Double entry bookkeeping ek system hai jismein har transaction ke liye 2 entries likhe jate hain - ek account ko debit karoge aur doosre ko credit. Ye rule follow karta hai: Debit = Credit. Isse accounting ka balance maintain reh ta hai aur errors catch hote hain. Modern accounting double entry system use karta hai.", answerEn: "Double entry bookkeeping is system where every transaction has 2 entries - one account debited and another credited. Follows rule: Debit = Credit. Maintains accounting balance and catches errors. Modern accounting uses double entry system.", answerShortNe: "Double entry = Har transaction-ke liye 2 entries: ek debit, ek credit.", relatedQuestions: ["debit credit rules", "single entry", "chart of accounts"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-041", question: "depreciation ka matlab kya ho?", questionNormalized: "depreciation ka matlab kya ho", questionType: "definition", topic: "accounting", answerNe: "Depreciation ek process hai jismein fixed assets (machinery, building, equipment) ki value time se reduce hoti hai. Depreciation expense har saal likha jata hai income statement me. Depreciation calculate karte hain using methods: Straight-line (same amount every year), Declining balance (zyada pehle, kam baad me).", answerEn: "Depreciation is process where fixed assets (machinery, building, equipment) value reduces over time. Depreciation expense recorded yearly in income statement. Calculated using methods: Straight-line (same amount yearly), Declining balance (more initially, less later).", answerShortNe: "Depreciation = Machine/Building ki value jo har saal kam hoti hai.", relatedQuestions: ["depreciation methods", "accumulated depreciation", "salvage value"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-042", question: "amortization ka matlab kya ho?", questionNormalized: "amortization ka matlab kya ho", questionType: "definition", topic: "accounting", answerNe: "Amortization ek process similar to depreciation par intangible assets (patents, copyrights, goodwill) ke liye use hota hai. Amortization expense yearly likha jata hai. Amortization usually straight-line method se calculate kiya jata hai.", answerEn: "Amortization is similar to depreciation but for intangible assets (patents, copyrights, goodwill). Amortization expense recorded yearly. Usually calculated using straight-line method.", answerShortNe: "Amortization = Intangible assets (patent, copyright) ki value jo kam hoti hai.", relatedQuestions: ["intangible assets", "amortization schedule", "goodwill amortization"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-043", question: "provision ka matlab kya ho?", questionNormalized: "provision ka matlab kya ho", questionType: "definition", topic: "accounting", answerNe: "Provision ek liability hai jo estimated hota hai because future obligation uncertain hota hai. Example: Provision for bad debts (jab kuch customer payment na de), Provision for warranty (product warranty claims), Provision for legal disputes. Provision conservative accounting follow karta hai - future losses estimate karte hain.", answerEn: "Provision is liability estimated for future obligations that are uncertain. Examples: Provision for bad debts (customers not paying), Provision for warranty (product warranty claims), Provision for legal disputes. Provision follows conservative accounting by estimating future losses.", answerShortNe: "Provision = Future loss ka estimate jo liability ke tarah likha jata hai.", relatedQuestions: ["doubtful debts", "bad debts provision", "contingent liabilities"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-044", question: "goodwill ka matlab kya ho?", questionNormalized: "goodwill ka matlab kya ho", questionType: "definition", topic: "accounting", answerNe: "Goodwill ek intangible asset hai jo reputation, brand name, customer loyalty ko represent karta hai. Goodwill accounting me utni tab likha jata hai jab ek business buy kiya jaye aur purchase price assets se zyada ho. Goodwill = Purchase Price - Fair Value of Assets. Goodwill amortization-capable hota hai.", answerEn: "Goodwill is intangible asset representing reputation, brand name, customer loyalty. Goodwill recorded in accounting when business purchased and purchase price exceeds assets. Goodwill = Purchase Price - Fair Value of Assets. Goodwill is amortizable.", answerShortNe: "Goodwill = Business ki reputation aur brand value jo khrid ke samay likha jata hai.", relatedQuestions: ["intangible assets", "goodwill impairment", "goodwill amortization"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-045", question: "asset ka valuation kaise hota hai?", questionNormalized: "asset ka valuation kaise hota hai", questionType: "process", topic: "accounting", answerNe: "Asset valuation ke methods: 1) Cost Method (historical cost jab asset buy hui) 2) Market Value Method (current market price) 3) Net Realizable Value (kitne me sell kar sakte hain) 4) Replacement Cost (nayi asset ki cost). Different assets ke liye different methods use hote hain. Inventory usually NRV, Fixed Assets usually Historical Cost.", answerEn: "Asset valuation methods: 1) Cost Method (historical cost when asset purchased) 2) Market Value Method (current market price) 3) Net Realizable Value (selling price) 4) Replacement Cost (cost of new asset). Different assets use different methods. Inventory usually NRV, Fixed Assets usually Historical Cost.", answerShortNe: "Asset valuation = Asset ki value kitni hai ye decide karna - different methods se.", relatedQuestions: ["inventory valuation", "fixed asset valuation", "fair value"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-046", question: "inventory management ka matlab kya ho?", questionNormalized: "inventory management ka matlab kya ho", questionType: "definition", topic: "accounting", answerNe: "Inventory management ek process hai jismein company ke goods ka stock maintain kiya jata hai. Inventory management me recording hota hai, valuation hota hai, aur reordering hota hai. Good inventory management cost reduce karta hai aur waste minimize karta hai. Inventory valuation methods: FIFO, LIFO, Weighted Average.", answerEn: "Inventory management is process of maintaining company's goods stock. Includes recording, valuation, and reordering. Good inventory management reduces cost and minimizes waste. Inventory valuation methods: FIFO, LIFO, Weighted Average.", answerShortNe: "Inventory management = Goods ke stock ka record rakhna aur manage karna.", relatedQuestions: ["fifo method", "lifo method", "weighted average method"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-047", question: "FIFO method ka matlab kya ho?", questionNormalized: "fifo method ka matlab kya ho", questionType: "definition", topic: "accounting", answerNe: "FIFO = First In First Out. Ye inventory valuation method assume karta hai ki jo pehle inventory buy hui wo pehle sell hoti hai. FIFO method inflation ka time me lower COGS aur higher profit dikhaata hai. FIFO method real inventory movement ko better represent karta hai.", answerEn: "FIFO = First In First Out. Assumes inventory purchased first is sold first. FIFO shows lower COGS and higher profit in inflation period. FIFO better represents real inventory movement.", answerShortNe: "FIFO = Pehle aaye, pehle gaye. Pehle khareedas inventory pehle sell ho.", relatedQuestions: ["lifo method", "fifo vs lifo", "weighted average"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-048", question: "LIFO method ka matlab kya ho?", questionNormalized: "lifo method ka matlab kya ho", questionType: "definition", topic: "accounting", answerNe: "LIFO = Last In First Out. Ye inventory valuation method assume karta hai ki jo aakhir me inventory buy hui wo pehle sell hoti hai. LIFO method inflation ka time me higher COGS aur lower profit dikhaata hai. LIFO tax advantage provide karta hai lekin Nepal me commonly use nahi hota.", answerEn: "LIFO = Last In First Out. Assumes inventory purchased last is sold first. LIFO shows higher COGS and lower profit in inflation period. LIFO provides tax advantage but not commonly used in Nepal.", answerShortNe: "LIFO = Aakhir me aaye, pehle gaye. Aakhir khareedas inventory pehle sell ho.", relatedQuestions: ["fifo method", "fifo vs lifo", "inventory valuation"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-049", question: "cost of goods sold (COGS) ka matlab kya ho?", questionNormalized: "cost of goods sold cogs ka matlab kya ho", questionType: "definition", topic: "accounting", answerNe: "COGS = Cost of Goods Sold. Ye wo cost hai jo product khareedne/banane me lagti hai. COGS me raw material, direct labor, manufacturing overhead likha jata hai. COGS = Opening Inventory + Purchases - Closing Inventory. COGS ko income statement me revenue se subtract karte hain.", answerEn: "COGS = Cost of Goods Sold. Cost incurred to purchase/manufacture products. Includes raw material, direct labor, manufacturing overhead. COGS = Opening Inventory + Purchases - Closing Inventory. Subtracted from revenue in income statement.", answerShortNe: "COGS = Product banane/khareedne me lagni wali cost.", relatedQuestions: ["cost of goods purchased", "gross profit", "operating expenses"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-050", question: "account receivable ka matlab kya ho?", questionNormalized: "account receivable ka matlab kya ho", questionType: "definition", topic: "accounting", answerNe: "Account Receivable (AR) wo amount hai jo customers se outstanding ho. Jab company on credit basis goods sell karta hai tab AR create hota hai. AR balance sheet ka current asset section me likha jata hai. AR reduce hota hai jab customer payment de. Bad debts ka provision AR se likha jata hai.", answerEn: "Account Receivable (AR) is amount outstanding from customers. Created when company sells on credit. AR appears in balance sheet's current assets. Reduces when customer pays. Bad debts provision deducted from AR.", answerShortNe: "AR = Customer ko jo paise dene hain (credit sale se).", relatedQuestions: ["accounts payable", "bad debts", "aged receivables"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-051", question: "account payable ka matlab kya ho?", questionNormalized: "account payable ka matlab kya ho", questionType: "definition", topic: "accounting", answerNe: "Account Payable (AP) wo amount hai jo company-ko suppliers/vendors ko dena ho. Jab company on credit basis goods buy karta hai tab AP create hota hai. AP balance sheet ka current liability section me likha jata hai. AP reduce hota hai jab company payment de.", answerEn: "Account Payable (AP) is amount company owes to suppliers/vendors. Created when company purchases on credit. AP appears in balance sheet's current liabilities. Reduces when company pays.", answerShortNe: "AP = Company ko jo paise dene hain suppliers ko (credit purchase se).", relatedQuestions: ["accounts receivable", "payable aging", "payment terms"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-052", question: "audit ka matlab kya ho?", questionNormalized: "audit ka matlab kya ho", questionType: "definition", topic: "accounting", answerNe: "Audit ek independent review ho jismein external auditor company ke financial records aur statements ko check karta hai. Auditor verify karta hai ki records accurate hain, internal controls proper hain, aur laws follow ho rahe hain. Audit companies ko credibility provide karta hai.", answerEn: "Audit is independent review where external auditor examines company's financial records and statements. Auditor verifies accuracy, proper internal controls, and law compliance. Audit provides credibility to company.", answerShortNe: "Audit = Independent check jo company ke accounts ko verify karta hai.", relatedQuestions: ["internal audit", "external audit", "audit report"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-053", question: "tax audit ka matlab kya ho?", questionNormalized: "tax audit ka matlab kya ho", questionType: "definition", topic: "tax", answerNe: "Tax audit ek check hota hai jismein tax department verify karta hai ki company ne correctly tax pay ki hai ya nahi. Tax audit Nepal me mandatory hota hai jab company ka turnover certain limit se zyada ho. Tax audit costly ho sakta hai isliye proper tax planning zaroori hai.", answerEn: "Tax audit is check by tax department to verify if company paid correct tax. Mandatory in Nepal when company turnover exceeds certain limit. Tax audit can be costly, so proper tax planning is necessary.", answerShortNe: "Tax audit = Government ki check jo verify karte hain ki sahi tax pay hua ya nahi.", relatedQuestions: ["tax return", "tax compliance", "tax liability"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-054", question: "tax return kasari bharu?", questionNormalized: "tax return kasari bharu", questionType: "process", topic: "tax", answerNe: "Tax return bharne ke liye: 1) Financial statements prepare karo (income statement, balance sheet) 2) Tax calculation karo 3) Tax return form (by tax department) ley 4) All required info fill karo (income, expenses, tax paid) 5) Supporting documents attach karo (invoices, receipts, bank statements) 6) Tax department ko submit karo (deadline: usually fiscal year end ke baad) 7) Receipt/acknowledgment laye.", answerEn: "To file tax return: 1) Prepare financial statements (income statement, balance sheet) 2) Calculate tax 3) Get tax return form from tax department 4) Fill required info (income, expenses, tax paid) 5) Attach supporting documents (invoices, receipts, bank statements) 6) Submit to tax department (deadline: usually after fiscal year) 7) Get receipt/acknowledgment.", answerShortNe: "Tax return = Income aur expenses ka official document jo tax department ko dena hota hai.", relatedQuestions: ["tax return deadline", "tax return form", "tax compliance"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-055", question: "internal control ka matlab kya ho?", questionNormalized: "internal control ka matlab kya ho", questionType: "definition", topic: "accounting", answerNe: "Internal control policies aur procedures hote hain jo company assets ko protect karte hain aur errors/fraud ko prevent karte hain. Internal controls me segregation of duties, approval processes, regular checks likha jata hai. Good internal control fraud ko rokta hai aur accuracy ensure karta hai.", answerEn: "Internal control are policies/procedures that protect company assets and prevent errors/fraud. Includes segregation of duties, approval processes, regular checks. Good internal control prevents fraud and ensures accuracy.", answerShortNe: "Internal control = Company ke internal rules jo fraud aur errors ko prevent karte hain.", relatedQuestions: ["segregation of duties", "internal audit", "control procedures"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-056", question: "cash management ka matlab kya ho?", questionNormalized: "cash management ka matlab kya ho", questionType: "definition", topic: "accounting", answerNe: "Cash management process hai jismein company ka cash properly manage kiya jata hai. Cash management me recording hota hai, forecasting hota hai, optimization hota hai. Good cash management ensure karta hai ki company-ke pas liquidity hai aur bills pay kar sakta hai. Cash management me cash flow statement important role play karta hai.", answerEn: "Cash management is process of properly managing company's cash. Includes recording, forecasting, optimization. Good cash management ensures company has liquidity and can pay bills. Cash flow statement plays important role in cash management.", answerShortNe: "Cash management = Company ke paise ko properly manage karna.", relatedQuestions: ["cash flow", "working capital", "liquidity management"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-057", question: "working capital ka matlab kya ho?", questionNormalized: "working capital ka matlab kya ho", questionType: "definition", topic: "accounting", answerNe: "Working Capital = Current Assets - Current Liabilities. Ye represent karta hai company ki short-term financial health. Positive working capital means company ke pas current assets hain current liabilities pay karne ke liye. Working capital important hota hai daily operations chalane ke liye.", answerEn: "Working Capital = Current Assets - Current Liabilities. Represents company's short-term financial health. Positive working capital means company has current assets to pay current liabilities. Important for daily operations.", answerShortNe: "Working capital = Current assets minus current liabilities. Company ke paise short term use ke liye.", relatedQuestions: ["current ratio", "quick ratio", "liquidity ratios"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-058", question: "current ratio ka matlab kya ho?", questionNormalized: "current ratio ka matlab kya ho", questionType: "definition", topic: "accounting", answerNe: "Current Ratio = Current Assets / Current Liabilities. Ye measure karta hai ki company kitni easily current liabilities pay kar sakta hai. Good current ratio 1.5 to 2.0 hota hai. Low current ratio liquidity problem indicate karta hai. Current ratio banking aur investors ke liye important metric ho ta hai.", answerEn: "Current Ratio = Current Assets / Current Liabilities. Measures how easily company can pay current liabilities. Good current ratio is 1.5 to 2.0. Low current ratio indicates liquidity problem. Important metric for banks and investors.", answerShortNe: "Current ratio = Current assets divided by current liabilities. 1.5 to 2.0 good ho ta.", relatedQuestions: ["quick ratio", "debt ratio", "liquidity analysis"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-059", question: "debt to equity ratio ka matlab kya ho?", questionNormalized: "debt to equity ratio ka matlab kya ho", questionType: "definition", topic: "accounting", answerNe: "Debt to Equity Ratio = Total Liabilities / Total Equity. Ye measure karta hai ki company kitna debt use kar raha hai vs. equity. Low ratio zyada better hota hai (less risky), High ratio zyada risky hota hai. Ratio 1 acceptable ho ta hai. High ratio business risk indicate karta hai.", answerEn: "Debt to Equity Ratio = Total Liabilities / Total Equity. Measures how much debt company uses vs. equity. Low ratio better (less risky), High ratio more risky. Ratio 1 acceptable. High ratio indicates business risk.", answerShortNe: "Debt to equity = Total liabilities divided by total equity. Low ratio better.", relatedQuestions: ["debt ratio", "equity ratio", "financial leverage"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-060", question: "ROA ka matlab kya ho?", questionNormalized: "roa ka matlab kya ho", questionType: "definition", topic: "accounting", answerNe: "ROA = Return on Assets = Net Income / Total Assets. Ye measure karta hai ki company assets se kitna efficiently profit generate kar raha hai. Higher ROA better, iska matlab company efficiently assets use kar raha hai. ROA comparing different companies ke liye useful ho ta hai.", answerEn: "ROA = Return on Assets = Net Income / Total Assets. Measures how efficiently company generates profit from assets. Higher ROA better, means company efficiently uses assets. ROA useful for comparing companies.", answerShortNe: "ROA = Net income divided by total assets. Higher ROA better ho ta.", relatedQuestions: ["roe", "profit margin", "return ratios"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-061", question: "ROE ka matlab kya ho?", questionNormalized: "roe ka matlab kya ho", questionType: "definition", topic: "accounting", answerNe: "ROE = Return on Equity = Net Income / Total Equity. Ye measure karta hai ki owner ko invest kiye paise se kitna return mil raha hai. Higher ROE better, iska matlab owner ke liye business profitable ho. ROE compare karne me use hota hai ek company vs doosra company.", answerEn: "ROE = Return on Equity = Net Income / Total Equity. Measures return owner gets from invested money. Higher ROE better, means business profitable for owner. Used for comparing companies.", answerShortNe: "ROE = Net income divided by total equity. Higher ROE better.", relatedQuestions: ["roa", "profit margin", "return metrics"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-062", question: "consolidation ka matlab kya ho?", questionNormalized: "consolidation ka matlab kya ho", questionType: "definition", topic: "accounting", answerNe: "Consolidation ek process hai jismein parent company aur subsidiary companies ke financial statements combine kiye jate hain. Consolidation use hota hai jab parent company subsidiary ko control karta hai. Consolidation me inter-company transactions eliminate kiye jate hain. Consolidated financial statements complete group picture dikhaate hain.", answerEn: "Consolidation is process of combining parent company and subsidiary companies' financial statements. Used when parent company controls subsidiary. Inter-company transactions eliminated. Consolidated statements show complete group picture.", answerShortNe: "Consolidation = Parent aur subsidiary ke accounts ko combine karna.", relatedQuestions: ["subsidiary", "parent company", "consolidated balance sheet"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-063", question: "forex accounting ka matlab kya ho?", questionNormalized: "forex accounting ka matlab kya ho", questionType: "definition", topic: "accounting", answerNe: "Forex accounting ek process jismein foreign currency transactions record kiye jate hain. Jab company different countries ke saath transaction karta hai toh forex accounting zaroor hota hai. Exchange rates fluctuate karte hain isliye exchange gain/loss record kiya jata hai. Forex transactions complex ho sakte hain.", answerEn: "Forex accounting is process of recording foreign currency transactions. When company transactions with different countries, forex accounting needed. Exchange rates fluctuate so exchange gain/loss recorded. Forex transactions can be complex.", answerShortNe: "Forex accounting = Different currency ke transactions ko record karna.", relatedQuestions: ["exchange rate", "exchange gain loss", "foreign currency translation"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-064", question: "budget ka matlab kya ho?", questionNormalized: "budget ka matlab kya ho", questionType: "definition", topic: "accounting", answerNe: "Budget ek plan hota hai jismein estimated income aur estimated expenses likhe jate hain. Budget future ke liye guide provide karta hai. Budget planning ke through company resources efficiently allocate kar sakta hai. Budget vs Actual comparison se performance analyze kiya jata hai.", answerEn: "Budget is plan with estimated income and expenses. Provides guide for future. Through budgeting, company can allocate resources efficiently. Budget vs Actual comparison analyzes performance.", answerShortNe: "Budget = Plan jismein estimated income aur expenses likhe hote hain.", relatedQuestions: ["budgeting process", "budget variance", "cost control"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-065", question: "variance analysis ka matlab kya ho?", questionNormalized: "variance analysis ka matlab kya ho", questionType: "definition", topic: "accounting", answerNe: "Variance analysis ek process jismein budgeted amounts ko actual amounts se compare kiya jata hai. Variance = Actual - Budget. Positive variance good ho sakta hai (actual > budget revenue), negative variance bad (actual < budget). Variance analysis performance identify karta hai aur corrective action suggest karta hai.", answerEn: "Variance analysis is process of comparing budgeted amounts to actual amounts. Variance = Actual - Budget. Positive variance can be good (actual > budget revenue), negative bad (actual < budget). Identifies performance and suggests corrective action.", answerShortNe: "Variance = Actual minus Budget. Difference between plan aur reality.", relatedQuestions: ["budget variance", "cost variance", "volume variance"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-066", question: "cost accounting ka matlab kya ho?", questionNormalized: "cost accounting ka matlab kya ho", questionType: "definition", topic: "accounting", answerNe: "Cost accounting ek system jismein production/service ka cost analyze kiya jata hai. Cost accounting identify karta hai direct costs (material, labor) aur indirect costs (overhead). Cost accounting through company manufacturing efficiency improve kar sakta hai aur waste identify kar sakta hai. Cost control ke liye cost accounting important ho ta hai.", answerEn: "Cost accounting is system analyzing production/service costs. Identifies direct costs (material, labor) and indirect costs (overhead). Helps improve manufacturing efficiency and identify waste. Important for cost control.", answerShortNe: "Cost accounting = Production ya service ka cost analyze karna.", relatedQuestions: ["direct costs", "indirect costs", "costing methods"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-067", question: "standard costing ka matlab kya ho?", questionNormalized: "standard costing ka matlab kya ho", questionType: "definition", topic: "accounting", answerNe: "Standard costing ek method jismein standard (predetermined) cost product karne ke liye set kiya jata hai. Actual cost compare kiya jata hai standard cost ke saath. Variance identify kiye jate hain aur investigate kiye jate hain. Standard costing efficiency improve karne me help karta hai.", answerEn: "Standard costing is method where standard (predetermined) cost is set for production. Actual cost compared to standard. Variances identified and investigated. Helps improve efficiency.", answerShortNe: "Standard costing = Advance me production ka cost predict karna.", relatedQuestions: ["standard cost", "cost variance", "variance analysis"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-068", question: "break-even point ka matlab kya ho?", questionNormalized: "break-even point ka matlab kya ho", questionType: "definition", topic: "accounting", answerNe: "Break-even point wo level hota hai jab Revenue = Total Costs, matlab profit = 0, loss = 0. Break-even identify karta hai company ko minimum kitni sales chahiye sirf break-even karne ke liye. Break-even ke baad har sale profit generate karta hai. Break-even calculation: Break-Even = Fixed Costs / (Price - Variable Cost per unit).", answerEn: "Break-even point is level where Revenue = Total Costs, so profit = 0, loss = 0. Identifies minimum sales needed to break-even. After break-even, sales generate profit. Formula: Break-Even = Fixed Costs / (Price - Variable Cost per unit).", answerShortNe: "Break-even = Sales level jahan profit aur loss dono zero hon.", relatedQuestions: ["contribution margin", "fixed costs", "variable costs"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-069", question: "contribution margin ka matlab kya ho?", questionNormalized: "contribution margin ka matlab kya ho", questionType: "definition", topic: "accounting", answerNe: "Contribution Margin = Sales Price - Variable Cost per unit. Ye contribution represent karta hai jo har sale se fixed costs cover karne ke liye. Higher contribution margin better, iska matlab fixed costs easily cover ho sakte hain. Contribution margin ratio = (Contribution Margin / Sales Price) × 100.", answerEn: "Contribution Margin = Sales Price - Variable Cost per unit. Represents contribution each sale makes to cover fixed costs. Higher contribution margin better, means fixed costs easily covered. Contribution margin ratio = (Contribution Margin / Sales Price) × 100.", answerShortNe: "Contribution margin = Sale price minus variable cost per unit.", relatedQuestions: ["break-even", "fixed costs", "variable costs"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-070", question: "fixed costs ka matlab kya ho?", questionNormalized: "fixed costs ka matlab kya ho", questionType: "definition", topic: "accounting", answerNe: "Fixed costs wo costs hote hain jo production volume ke regardless same rehte hain. Example: Rent, Salary, Insurance, Depreciation. Fixed costs production na hone par bhi pay karne padte hain. Fixed costs budget mein important role play karte hain.", answerEn: "Fixed costs are costs that remain same regardless of production volume. Examples: Rent, Salary, Insurance, Depreciation. Must be paid even if no production. Play important role in budgeting.", answerShortNe: "Fixed costs = Wo costs jo production volume se independent hote hain.", relatedQuestions: ["variable costs", "semi-variable costs", "cost behavior"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-071", question: "variable costs ka matlab kya ho?", questionNormalized: "variable costs ka matlab kya ho", questionType: "definition", topic: "accounting", answerNe: "Variable costs wo costs hote hain jo production volume ke saath change hote hain. Jab production zyada ho tab variable costs zyada, jab production kam ho tab variable costs kam. Example: Raw Material, Direct Labor, Packaging. Variable costs production se directly related hote hain.", answerEn: "Variable costs are costs that change with production volume. More production = higher variable costs, less production = lower variable costs. Examples: Raw Material, Direct Labor, Packaging. Directly related to production.", answerShortNe: "Variable costs = Wo costs jo production volume ke saath badal jate hain.", relatedQuestions: ["fixed costs", "semi-variable costs", "contribution margin"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-072", question: "semi-variable costs ka matlab kya ho?", questionNormalized: "semi-variable costs ka matlab kya ho", questionType: "definition", topic: "accounting", answerNe: "Semi-variable costs ek combination hote hain fixed aur variable costs. Example: Phone bill (base charge fixed + usage charges variable), Electricity (minimum charges + usage charges). Semi-variable costs partial fixed aur partial variable hote hain.", answerEn: "Semi-variable costs are combination of fixed and variable costs. Examples: Phone bill (base fixed + usage variable), Electricity (minimum charges + usage). Partly fixed and partly variable.", answerShortNe: "Semi-variable = Fixed aur variable costs ka mix.", relatedQuestions: ["fixed costs", "variable costs", "cost behavior"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-073", question: "product costing ka matlab kya ho?", questionNormalized: "product costing ka matlab kya ho", questionType: "definition", topic: "accounting", answerNe: "Product costing process jismein product ka total cost calculate kiya jata hai. Product cost include karta hai: Raw Material + Direct Labor + Manufacturing Overhead. Product costing important hota hai pricing decision lene ke liye. Different costing methods available hote hain: Absorption Costing, Variable Costing.", answerEn: "Product costing is process of calculating product's total cost. Includes: Raw Material + Direct Labor + Manufacturing Overhead. Important for pricing decisions. Different methods available: Absorption Costing, Variable Costing.", answerShortNe: "Product costing = Product ka total cost calculate karna.", relatedQuestions: ["absorption costing", "variable costing", "pricing"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-074", question: "cash basis accounting ka matlab kya ho?", questionNormalized: "cash basis accounting ka matlab kya ho", questionType: "definition", topic: "accounting", answerNe: "Cash basis accounting ek system jismein transactions record hote hain jab cash actually receive/pay hota hai. Cash basis simple hota hai lekin financial picture accurate nahi deta. Nepal me small businesses cash basis use kar sakte hain but larger businesses accrual basis follow karte hain.", answerEn: "Cash basis accounting is system where transactions recorded when cash actually received/paid. Simple but doesn't give accurate financial picture. Small businesses may use in Nepal but larger use accrual basis.", answerShortNe: "Cash basis = Transactions record hote hain jab cash actual aaye/jaye.", relatedQuestions: ["accrual basis", "cash vs accrual", "accounting methods"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-075", question: "accrual basis accounting ka matlab kya ho?", questionNormalized: "accrual basis accounting ka matlab kya ho", questionType: "definition", topic: "accounting", answerNe: "Accrual basis accounting ek system jismein transactions record hote hain jab liability/obligation create hota hai, cash receive/pay na hone par bhi. Accrual basis accurate financial picture deta hai. Larger companies aur international standards accrual basis follow karte hain. Nepal me companies accrual basis use kar sakte hain.", answerEn: "Accrual basis accounting is system where transactions recorded when liability/obligation created, even if cash not received/paid. Gives accurate financial picture. Larger companies and international standards use accrual. Can be used in Nepal.", answerShortNe: "Accrual basis = Transactions record hote hain jab liability create ho.", relatedQuestions: ["cash basis", "cash vs accrual", "revenue recognition"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-076", question: "tally kasari use karnu?", questionNormalized: "tally kasari use karnu", questionType: "process", topic: "software", answerNe: "Tally use karne ke liye: 1) Tally software install karo 2) Company create karo (File > New Company) 3) Company info fill karo (name, address, fiscal year) 4) Chart of Accounts setup karo 5) Ledgers create karo 6) Voucher entry karo (daily transactions) 7) Reports view karo (Trial Balance, Balance Sheet, P&L). Tally user-friendly hai.", answerEn: "To use Tally: 1) Install Tally software 2) Create company (File > New Company) 3) Fill company info (name, address, fiscal year) 4) Setup Chart of Accounts 5) Create ledgers 6) Enter vouchers (daily transactions) 7) View reports (Trial Balance, Balance Sheet, P&L). User-friendly.", answerShortNe: "Tally = Software install karke company create karo, voucher entry karo, reports dekho.", relatedQuestions: ["tally shortcut keys", "tally chart of accounts", "tally reports"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-077", question: "busy kasari use karnu?", questionNormalized: "busy kasari use karnu", questionType: "process", topic: "software", answerNe: "Busy use karne ke liye: 1) Busy software install karo 2) Company create karo 3) Company details fill karo 4) Chart of Accounts configure karo 5) Inventory setup karo (if needed) 6) Daily transactions entry karo 7) Reports generate karo. Busy Nepal ke businesses ke liye specially designed ho so features easily accessible hote hain.", answerEn: "To use Busy: 1) Install Busy software 2) Create company 3) Fill company details 4) Configure Chart of Accounts 5) Setup inventory (if needed) 6) Enter daily transactions 7) Generate reports. Designed for Nepal businesses so features easily accessible.", answerShortNe: "Busy = Nepali-friendly software jo accounting aur inventory manage karta hai.", relatedQuestions: ["busy features", "busy chart of accounts", "busy reporting"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-078", question: "PAN certificate kaise laye?", questionNormalized: "pan certificate kaise laye", questionType: "process", topic: "registration", answerNe: "PAN certificate lene ke liye: 1) Tax office kho 2) Application form fill karo (prescribed form) 3) Citizenship copy attach karo 4) Temporary tax receipt paper attach karo 5) Application submit karo 6) Receipt laye 7) Usually 3-5 din me certificate mil jata hai. PAN certificate official proof hota hai tax registration ka.", answerEn: "To get PAN certificate: 1) Go to tax office 2) Fill application form 3) Attach citizenship copy 4) Attach temporary tax receipt 5) Submit application 6) Get receipt 7) Usually certificate issued in 3-5 days. Certificate is official proof of tax registration.", answerShortNe: "PAN certificate = Tax office se 3-5 din me mil jata hai application submit karke.", relatedQuestions: ["pan registration", "pan number", "pan certificate copy"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-079", question: "VAT registration kasari garnu?", questionNormalized: "vat registration kasari garnu", questionType: "process", topic: "tax", answerNe: "VAT registration karne ke liye: 1) VAT application form bharu 2) PAN certificate attach karo 3) Business address proof attach karo 4) Trade license copy attach karo 5) Tax office ko submit karo 6) Verification process hote hain 7) VAT registration confirm ho jata hai 8) VAT certificate mil jata hai. VAT registration se business tax compliant ban jata hai.", answerEn: "To register for VAT: 1) Fill VAT application form 2) Attach PAN certificate 3) Attach business address proof 4) Attach trade license copy 5) Submit to tax office 6) Verification process 7) VAT registration confirmed 8) Get VAT certificate. Makes business tax compliant.", answerShortNe: "VAT registration = Tax office me form submit karke VAT certificate milta hai.", relatedQuestions: ["vat return", "vat compliance", "vat invoice"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-080", question: "GST registration ka matlab kya ho?", questionNormalized: "gst registration ka matlab kya ho", questionType: "definition", topic: "tax", answerNe: "GST = Goods and Services Tax. Nepal me GST concept nahi ho, instead VAT hota hai. Lekin international context me GST registration means government ke paas register hona similar to VAT registration. GST registration requirement hota hai jab sales certain limit cross kare.", answerEn: "GST = Goods and Services Tax. Nepal has VAT concept instead of GST. But in international context, GST registration means registering with government similar to VAT registration. Required when sales exceed certain limit.", answerShortNe: "GST = International tax similar to Nepal's VAT.", relatedQuestions: ["vat registration", "gst compliance", "tax registration"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-081", question: "TDS deposit kasari garnu?", questionNormalized: "tds deposit kasari garnu", questionType: "process", topic: "tax", answerNe: "TDS deposit karne ke liye: 1) TDS collected amount calculate karo 2) Tax office ke khaate ko identify karo 3) Bank me challan fill karo (JV, TDS, etc.) 4) Amount deposit karo 5) Receipt laye 6) Receipt ko record me store karo 7) TDS return file karo (quarterly/monthly). TDS on time deposit zaroor karo nahi to penalty ho sakti hai.", answerEn: "To deposit TDS: 1) Calculate collected TDS amount 2) Identify tax office account 3) Fill bank challan 4) Deposit amount 5) Get receipt 6) Keep receipt in records 7) File TDS return (quarterly/monthly). Deposit on time or penalty may apply.", answerShortNe: "TDS deposit = Tax office ko collected TDS amount bank se dena.", relatedQuestions: ["tds calculation", "tds return", "tds certificate"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-082", question: "income tax Nepal ma kati ho?", questionNormalized: "income tax nepal ma kati ho", questionType: "calculation", topic: "tax", answerNe: "Income tax Nepal ma income bracket par depend karta hai. Standard slab (2024): 0-500,000 = 0%, 500,000-1,000,000 = 10%, 1,000,000-1,350,000 = 20%, 1,350,000+ = 30%. Different person categories (individual, company, organization) ke liye different rates ho sakte hain. Annual income tax return file karna zaroori hota hai.", answerEn: "Income tax in Nepal depends on income bracket. Standard slab (2024): 0-500,000 = 0%, 500,000-1,000,000 = 10%, 1,000,000-1,350,000 = 20%, 1,350,000+ = 30%. Different rates for categories (individual, company, organization). Annual tax return filing required.", answerShortNe: "Income tax Nepal = Income bracket par depend karta hai (0% to 30%).", relatedQuestions: ["income tax slab", "income tax return", "tax deduction"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-083", question: "corporate tax ka matlab kya ho?", questionNormalized: "corporate tax ka matlab kya ho", questionType: "definition", topic: "tax", answerNe: "Corporate tax tax hota hai jo companies ko apni profit par pay karna padta hai. Nepal me corporate tax rate 25% hota hai (standard rate). Corporate tax different hota hai individual income tax se. Company ko corporate tax file karna padta hai on annual basis.", answerEn: "Corporate tax is tax companies pay on their profit. In Nepal, corporate tax rate is 25% (standard rate). Different from individual income tax. Companies must file corporate tax annually.", answerShortNe: "Corporate tax = 25% tax jo companies apni profit par pay karte hain.", relatedQuestions: ["income tax", "corporate tax rate", "tax compliance"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-084", question: "tax deduction ka matlab kya ho?", questionNormalized: "tax deduction ka matlab kya ho", questionType: "definition", topic: "tax", answerNe: "Tax deduction ek relief hota hai jo government provide karta hai. Deduction se taxable income reduce hota hai. Common deductions: Charitable donations, Insurance premiums, Professional development expenses. More deductions mean lower tax payable. Tax planning ke through deductions maximize kiye ja sakte hain.", answerEn: "Tax deduction is relief provided by government. Reduces taxable income. Common deductions: Charitable donations, Insurance premiums, Professional development. More deductions = lower tax payable. Can be maximized through tax planning.", answerShortNe: "Tax deduction = Taxable income reduce karne wali cheez.", relatedQuestions: ["tax credit", "tax planning", "deductible expenses"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-085", question: "tax credit ka matlab kya ho?", questionNormalized: "tax credit ka matlab kya ho", questionType: "definition", topic: "tax", answerNe: "Tax credit direct kameez karta hai tax payable amount ko. Agar tax payable Rs. 10,000 hai aur tax credit Rs. 2,000 hai to actual pay Rs. 8,000 hona chahiye. Tax credit more valuable hota hai deduction ke compare me. Tax credits specific conditions par depend karte hain.", answerEn: "Tax credit directly reduces tax payable amount. If tax payable Rs. 10,000 and tax credit Rs. 2,000, actual pay Rs. 8,000. More valuable than deduction. Depends on specific conditions.", answerShortNe: "Tax credit = Direct reduction tax payable amount me.", relatedQuestions: ["tax deduction", "tax planning", "tax credits"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-086", question: "tax planning ka matlab kya ho?", questionNormalized: "tax planning ka matlab kya ho", questionType: "definition", topic: "tax", answerNe: "Tax planning ek strategy ho jasle business apna tax legally minimize kar sakta hai. Tax planning through proper documentation, deductions, credits use karke kiya jata hai. Tax planning illegal nahi hai, sirf legal tarike se taxes optimize karna hota hai. Proper tax planning business ko save help karta hai.", answerEn: "Tax planning is strategy to legally minimize business tax. Through proper documentation, deductions, credits. Not illegal, just legal tax optimization. Proper planning helps business save money.", answerShortNe: "Tax planning = Legal tarike se taxes minimize karna.", relatedQuestions: ["tax compliance", "tax deduction", "tax strategy"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-087", question: "fiscal year ka matlab kya ho?", questionNormalized: "fiscal year ka matlab kya ho", questionType: "definition", topic: "accounting", answerNe: "Fiscal year ek 12-month period hota hai jiskep liye company financial records maintain karta hai. Nepal me fiscal year Baishakh 1 se Chaitra 32 tak hota hai (July 17 - July 16 next year in Gregorian calendar). Different countries ke different fiscal years hote hain. Fiscal year ke baad financial statements prepare kiye jate hain.", answerEn: "Fiscal year is 12-month period for which company maintains financial records. In Nepal, fiscal year is Baishakh 1 to Chaitra 32 (July 17 - July 16 next year in Gregorian). Different countries have different fiscal years. Financial statements prepared after fiscal year.", answerShortNe: "Fiscal year = Nepal me Baishakh 1 se Chaitra 32 (July-July).", relatedQuestions: ["financial year", "year end closing", "fiscal year reporting"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-088", question: "year-end closing ka matlab kya ho?", questionNormalized: "year-end closing ka matlab kya ho", questionType: "definition", topic: "accounting", answerNe: "Year-end closing ek process jismein fiscal year ke laast din transactions finalize kiye jate hain aur closing entries likhe jate hain. Year-end closing me temporary accounts (revenue, expenses) close kiye jate hain. Permanent accounts (assets, liabilities, equity) open reh jate hain. Year-end closing ke baad financial statements prepare kiye jate hain.", answerEn: "Year-end closing is process where fiscal year's final transactions finalized and closing entries made. Temporary accounts (revenue, expenses) closed. Permanent accounts (assets, liabilities, equity) remain open. Financial statements prepared after.", answerShortNe: "Year-end closing = Fiscal year ke aakhir ko accounts finalize karna.", relatedQuestions: ["closing entries", "profit & loss account", "retained earnings"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-089", question: "profit and loss account ka matlab kya ho?", questionNormalized: "profit and loss account ka matlab kya ho", questionType: "definition", topic: "accounting", answerNe: "Profit and Loss Account (P&L) ek statement hota hai jo revenue aur expenses show karta hai specific period ke liye. P&L statement se pata chalta hai company ne profit kiya ya loss. P&L statement = Revenue - Expenses. P&L account temporary account hota hai jo year-end par close kiya jata hai.", answerEn: "Profit and Loss Account (P&L) is statement showing revenue and expenses for specific period. Shows if company made profit or loss. P&L = Revenue - Expenses. Temporary account closed at year-end.", answerShortNe: "P&L account = Revenue minus expenses jo year-end profit/loss show karta hai.", relatedQuestions: ["income statement", "revenue", "operating expenses"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-090", question: "retained earnings ka matlab kya ho?", questionNormalized: "retained earnings ka matlab kya ho", questionType: "definition", topic: "accounting", answerNe: "Retained Earnings wo profit hota hai jo company ne previous years me earn kiya aur reinvest kiya. Retained Earnings = Previous Retained Earnings + Net Income - Dividends. Retained Earnings permanent account hota hai balance sheet me likha jata hai. High retained earnings company ke liye positive signal hota hai.", answerEn: "Retained Earnings is profit company earned in previous years and reinvested. Retained Earnings = Previous RE + Net Income - Dividends. Permanent account shown in balance sheet. High retained earnings positive signal.", answerShortNe: "Retained earnings = Profit jo company apne pehle save rakhaa hai.", relatedQuestions: ["dividend", "equity", "owner withdrawal"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-091", question: "dividend ka matlab kya ho?", questionNormalized: "dividend ka matlab kya ho", questionType: "definition", topic: "accounting", answerNe: "Dividend ek payment hota hai jo company shareholders ko deta hai. Dividend company ke profit se distribute kiya jata hai. Dividend usually cash form me hota hai lekin sometimes stock form me bhi hota hai. Dividend shareholders ko owner benefit provide karta hai. Dividend decision company ke board of directors leta hai.", answerEn: "Dividend is payment company gives to shareholders. Distributed from company profit. Usually cash form but sometimes stock form. Provides owner benefit to shareholders. Decided by company's board of directors.", answerShortNe: "Dividend = Profit ka share jo company shareholders ko deta hai.", relatedQuestions: ["dividend payment", "dividend policy", "retained earnings"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-092", question: "inventory turnover ratio ka matlab kya ho?", questionNormalized: "inventory turnover ratio ka matlab kya ho", questionType: "definition", topic: "accounting", answerNe: "Inventory Turnover Ratio = COGS / Average Inventory. Ye measure karta hai ki company inventory kitne quickly sell kar raha hai. Higher ratio better, iska matlab inventory fast movement ho raha hai. Lower ratio bad, inventory dead stock ho sakti hai. Inventory turnover efficiency ka measure hota hai.", answerEn: "Inventory Turnover Ratio = COGS / Average Inventory. Measures how quickly company sells inventory. Higher ratio better (fast inventory movement). Lower ratio bad (may indicate dead stock). Measure of efficiency.", answerShortNe: "Inventory turnover = COGS divided by average inventory. Higher better.", relatedQuestions: ["days inventory outstanding", "inventory management", "working capital"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-093", question: "receivable turnover ratio ka matlab kya ho?", questionNormalized: "receivable turnover ratio ka matlab kya ho", questionType: "definition", topic: "accounting", answerNe: "Receivable Turnover Ratio = Sales / Average Accounts Receivable. Ye measure karta hai ki company kitni quickly customer se payment collect kar raha hai. Higher ratio better, iska matlab quick collection. Lower ratio bad, credit policy issue ho sakti hai. Receivable turnover cash flow impact karta hai.", answerEn: "Receivable Turnover Ratio = Sales / Average Accounts Receivable. Measures how quickly company collects customer payments. Higher ratio better (quick collection). Lower ratio bad (may indicate credit policy issues). Impacts cash flow.", answerShortNe: "Receivable turnover = Sales divided by average accounts receivable.", relatedQuestions: ["days sales outstanding", "credit policy", "collection efficiency"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-094", question: "payable turnover ratio ka matlab kya ho?", questionNormalized: "payable turnover ratio ka matlab kya ho", questionType: "definition", topic: "accounting", answerNe: "Payable Turnover Ratio = COGS / Average Accounts Payable. Ye measure karta hai ki company kitni quickly suppliers ko pay kar raha hai. Higher ratio means company quickly pays (less working capital benefit), Lower ratio means company slow pays (good for cash flow). Payable turnover payment policy reflect karta hai.", answerEn: "Payable Turnover Ratio = COGS / Average Accounts Payable. Measures how quickly company pays suppliers. Higher ratio = pays quickly (less working capital benefit), Lower ratio = pays slowly (good for cash flow). Reflects payment policy.", answerShortNe: "Payable turnover = COGS divided by average accounts payable.", relatedQuestions: ["days payable outstanding", "payment terms", "working capital"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-095", question: "operating cycle ka matlab kya ho?", questionNormalized: "operating cycle ka matlab kya ho", questionType: "definition", topic: "accounting", answerNe: "Operating Cycle = Days Inventory Outstanding + Days Sales Outstanding. Ye show karta hai ki company ko kitna time lagta hai inventory khareedne se lekar customer se payment collect karne tak. Shorter operating cycle better, working capital requirement kam hota hai. Operating cycle business efficiency ka indicator hota hai.", answerEn: "Operating Cycle = Days Inventory Outstanding + Days Sales Outstanding. Shows time from buying inventory to collecting customer payment. Shorter cycle better (less working capital needed). Indicator of business efficiency.", answerShortNe: "Operating cycle = Time inventory buy se leke customer payment collect hone tak.", relatedQuestions: ["cash conversion cycle", "working capital", "operating efficiency"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-096", question: "accounting standards ka matlab kya ho?", questionNormalized: "accounting standards ka matlab kya ho", questionType: "definition", topic: "accounting", answerNe: "Accounting standards ek guidelines hote hain jo companies follow karte hain transactions record karne ke liye. International standards IFRS (International Financial Reporting Standards) hote hain. Nepal locally accepted accounting standards hote hain. Standards consistency ensure karte hain aur comparability improve karte hain.", answerEn: "Accounting standards are guidelines companies follow to record transactions. International standard is IFRS (International Financial Reporting Standards). Nepal has locally accepted standards. Ensure consistency and improve comparability.", answerShortNe: "Accounting standards = Rules jo companies ko accounting follow karne chahiye.", relatedQuestions: ["ifrs", "gaap", "accounting policies"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-097", question: "revenue recognition ka matlab kya ho?", questionNormalized: "revenue recognition ka matlab kya ho", questionType: "definition", topic: "accounting", answerNe: "Revenue recognition process jismein company revenue record karta hai jab earned hota hai, cash receive na hone par bhi. Revenue recognition principle: revenue record karte hain jab sale confirm hota hai, not when cash received. Proper revenue recognition financial statements accuracy ensure karta hai.", answerEn: "Revenue recognition is process of recording revenue when earned, not necessarily when cash received. Principle: Record when sale confirmed, not when cash received. Ensures financial statement accuracy.", answerShortNe: "Revenue recognition = Revenue likha jata hai jab sale ho, cash na milne par bhi.", relatedQuestions: ["accrual basis", "revenue policy", "income recognition"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-098", question: "matching principle ka matlab kya ho?", questionNormalized: "matching principle ka matlab kya ho", questionType: "definition", topic: "accounting", answerNe: "Matching Principle ek accounting concept jismein expenses match kiye jate hain corresponding revenue ke saath. Iska matlab ek period me jo revenue earn hua us period me corresponding expenses likhe jate hain. Matching principle accurate profitability ensure karta hai. Matching principle fundamental accounting principle hota hai.", answerEn: "Matching Principle is concept where expenses matched to corresponding revenue. Revenue and related expenses recorded in same period. Ensures accurate profitability. Fundamental accounting principle.", answerShortNe: "Matching principle = Revenue aur related expenses same period me likhe jate hain.", relatedQuestions: ["accrual basis", "revenue recognition", "accounting principles"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-099", question: "materiality ka matlab kya ho?", questionNormalized: "materiality ka matlab kya ho", questionType: "definition", topic: "accounting", answerNe: "Materiality ek concept jismein small items ko financial statements me record na karne decision li ta hai. Material = important/significant. Materiality ne basis par company decide karta hai kaunse items important hain. Materiality company size, industry, profit level par depend karta hai. Materiality auditors ke liye bhi important hota hai.", answerEn: "Materiality is concept where small items not recorded in financial statements. Material = important/significant. Company decides which items important. Depends on company size, industry, profit level. Important for auditors too.", answerShortNe: "Materiality = Small items jo important nahi hote financial statements ke liye.", relatedQuestions: ["accounting principles", "accounting policies", "accounting estimates"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-100", question: "going concern assumption ka matlab kya ho?", questionNormalized: "going concern assumption ka matlab kya ho", questionType: "definition", topic: "accounting", answerNe: "Going Concern Assumption ek assumption jismehen company assume karta hai ki business indefinitely continue ho sakta hai. Going concern ke tahat assets value recorded kiya jata hai based on ongoing operations. Agar going concern doubt ho to special disclosure karna padta hai. Going concern fundamental accounting assumption hota hai.", answerEn: "Going Concern Assumption assumes business can continue indefinitely. Assets valued based on ongoing operations. If doubt, special disclosure required. Fundamental accounting assumption.", answerShortNe: "Going concern = Assumption ki business future me bhi chalegi.", relatedQuestions: ["accounting assumptions", "liquidation value", "bankruptcy"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-101", question: "fraud detection ka matlab kya ho?", questionNormalized: "fraud detection ka matlab kya ho", questionType: "definition", topic: "accounting", answerNe: "Fraud detection ek process jismein unusual activities identify kiye jate hain jo fraud indicate kar sakte hain. Common frauds: Inventory theft, Receivable manipulation, Expense overstatement. Fraud detection through internal controls, audits, reconciliations kiya jata hai. Early fraud detection losses minimize karta hai.", answerEn: "Fraud detection is process identifying unusual activities indicating fraud. Common frauds: Inventory theft, Receivable manipulation, Expense overstatement. Detected through internal controls, audits, reconciliations. Early detection minimizes losses.", answerShortNe: "Fraud detection = Suspicious activities ko identify karna jo theft/manipulation suggest karte hain.", relatedQuestions: ["internal control", "audit", "fraud prevention"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-102", question: "financial analysis ka matlab kya ho?", questionNormalized: "financial analysis ka matlab kya ho", questionType: "definition", topic: "accounting", answerNe: "Financial analysis process jismein financial statements analyze kiye jate hain company ke performance understand karne ke liye. Financial analysis through ratios, trends, comparisons kiya jata hai. Financial analysis investors, creditors, management ke liye important hota hai. Good financial analysis informed decisions lene me help karta hai.", answerEn: "Financial analysis is process of analyzing financial statements to understand company performance. Through ratios, trends, comparisons. Important for investors, creditors, management. Helps make informed decisions.", answerShortNe: "Financial analysis = Financial statements ko analyze karke performance understand karna.", relatedQuestions: ["financial ratios", "trend analysis", "comparative analysis"], intent: "accounting_qa", notTransaction: true},
  {id: "faq-103", question: "investment analysis ka matlab kya ho?", questionNormalized: "investment analysis ka matlab kya ho", questionType: "definition", topic: "accounting", answerNe: "Investment analysis process jismein different investment options analyze kiye jate hain returns aur risks compare karte hain. Investment analysis through financial ratios, cash flow analysis kiya jata hai. Investment analysis investors ke liye important hota hai decision lene ke liye. Good investment analysis long-term wealth create karta hai.", answerEn: "Investment analysis is process of analyzing investment options comparing returns and risks. Through financial ratios, cash flow analysis. Important for investors making decisions. Good analysis creates long-term wealth.", answerShortNe: "Investment analysis = Different investments ko analyze karke best choose karna.", relatedQuestions: ["investment returns", "risk analysis", "portfolio management"], intent: "accounting_qa", notTransaction: true},
];

