export const NEPAL_TAX_FAQ: NepalTaxFaqEntry[] = [
  {id: "taxfaq-001", topic: "VAT registration threshold", topicKey: "vat_registration_threshold", questionNe: "VAT register garna kati turnover chahiyo?", questionEn: "What is the VAT registration threshold?", questionNormalized: "vat register garna kati turnover chahiyo", answerNe: "Annual turnover Rs 50 lakh (goods) athawa Rs 20 lakh (services) bhanda badhi bhaye VAT mandatory registration garna parcha. Voluntary registration pani garna sakincha.", answerEn: "VAT registration is mandatory if annual turnover exceeds Rs 50 lakh for goods or Rs 20 lakh for services. Voluntary registration is also allowed.", answerShortNe: "Annual turnover Rs 50 lakh (goods) athawa Rs 20 lakh (services) bhanda badhi bhaye VAT mandatory registration garna parcha.", currentAsOf: "FY 2080/81", legalReference: "VAT Act 2052", relatedTopics: ["VAT rate", "VAT return", "VAT refund"], commonFollowups: ["VAT kati % ho?", "VAT return kahile file garne?"], intent: "accounting_qa", notTransaction: true},
  {id: "taxfaq-002", topic: "VAT rate", topicKey: "vat_rate", questionNe: "Nepal ma VAT ko dar kati cha?", questionEn: "What is the VAT rate in Nepal?", questionNormalized: "nepal ma vat ko dar kati cha", answerNe: "Nepal ma VAT ko single standard rate 13% cha. Kehi specific goods ra services ma exemption cha.", answerEn: "Nepal has a single standard VAT rate of 13%. Some specific goods and services are exempt.", answerShortNe: "Nepal ma VAT ko single standard rate 13% cha.", currentAsOf: "FY 2080/81", legalReference: "VAT Act 2052, Schedule 1", relatedTopics: ["VAT exemption", "VAT registration threshold", "VAT return"], commonFollowups: ["Kun saman ma VAT chhut cha?", "VAT register garna kati turnover chahiyo?"], intent: "accounting_qa", notTransaction: true},
  {id: "taxfaq-003", topic: "VAT return filing", topicKey: "vat_return_filing", questionNe: "VAT return kahile file garne?", questionEn: "When to file VAT return?", questionNormalized: "vat return kahile file garne", answerNe: "VAT return har mahina ko 25 gate bhanda agadi file garera tax tirda huncha. Barsa ma 12 wata monthly return file garne parcha.", answerEn: "VAT returns must be filed by the 25th of the following month. A total of 12 monthly returns must be filed per year.", answerShortNe: "VAT return har mahina ko 25 gate bhanda agadi file garera tax tirda huncha.", currentAsOf: "FY 2080/81", legalReference: "VAT Act 2052, Section 18", relatedTopics: ["VAT registration threshold", "VAT refund", "Penalty"], commonFollowups: ["VAT register garna kati turnover chahiyo?", "Monthly return file nagare ke huncha?"], intent: "accounting_qa", notTransaction: true},
  {id: "taxfaq-004", topic: "VAT refund", topicKey: "vat_refund", questionNe: "VAT refund kasari paune?", questionEn: "How to get VAT refund?", questionNormalized: "vat refund kasari paune", answerNe: "Zero rated goods ko bikri athawa excess input tax bhayema VAT refund claim garna sakincha. Niyam anusar IRD ma niwedan gari refund pauna sakcha.", answerEn: "VAT refund can be claimed for zero-rated goods sales or excess input tax. A claim application must be submitted to IRD as per rules.", answerShortNe: "Zero rated goods ko bikri athawa excess input tax bhayema VAT refund claim garna sakincha.", currentAsOf: "FY 2080/81", legalReference: "VAT Act 2052, Section 24", relatedTopics: ["VAT return", "Input tax credit", "Zero rate"], commonFollowups: ["Zero rate ke ho?", "Refund aauna kati time lagcha?"], intent: "accounting_qa", notTransaction: true},
  {id: "taxfaq-005", topic: "Input tax credit", topicKey: "input_tax_credit", questionNe: "Input tax credit ke ho?", questionEn: "What is input tax credit?", questionNormalized: "input tax credit ke ho", answerNe: "Business ko lagi kinmel garda tireko VAT lai bikri garda uthayeko VAT bata ghatayera net tax nikalna sakine wyawastha lai input tax credit bhanincha.", answerEn: "Input tax credit is a mechanism that allows businesses to deduct the VAT paid on purchases from the VAT collected on sales to calculate net tax payable.", answerShortNe: "Business ko lagi kinmel garda tireko VAT lai bikri garda uthayeko VAT bata ghatayera net tax nikalna sakine wyawastha lai input tax credit bhanincha.", currentAsOf: "FY 2080/81", legalReference: "VAT Act 2052, Section 12", relatedTopics: ["VAT return", "VAT refund", "Tax invoice"], commonFollowups: ["Kohi pani saman kinna le credit pauncha?", "Tax invoice bina credit pauncha?"], intent: "accounting_qa", notTransaction: true},
  {id: "taxfaq-006", topic: "VAT exemption", topicKey: "vat_exemption", questionNe: "Nepal ma kun saman ma VAT chhut cha?", questionEn: "Which goods are VAT exempt in Nepal?", questionNormalized: "nepal ma kun saman ma vat chhut cha", answerNe: "Krishna ko aadharbhut saman (chamal, pitho, dal), shikshya ra swasthya sewa, suwa ko saaman, kehi krishi upaj haru ma VAT chhut cha.", answerEn: "VAT exemption applies to basic food items (rice, flour, lentils), education and health services, infant supplies, and certain agricultural products.", answerShortNe: "Krishna ko aadharbhut saman (chamal, pitho, dal), shikshya ra swasthya sewa, suwa ko saaman, kehi krishi upaj haru ma VAT chhut cha.", currentAsOf: "FY 2080/81", legalReference: "VAT Act 2052, Schedule 1", relatedTopics: ["VAT rate", "Zero rate", "VAT registration threshold"], commonFollowups: ["VAT rate kati ho?", "Zero rate ra exempt ma ke farak cha?"], intent: "accounting_qa", notTransaction: true},
  {id: "taxfaq-007", topic: "Individual Income Tax Slab", topicKey: "individual_income_tax_slab", questionNe: "Nepal ma natural person ko income tax rate kati ho?", questionEn: "What are the individual income tax slabs in Nepal?", questionNormalized: "nepal ma natural person ko income tax rate kati ho", answerNe: "FY 2080/81 ma yearly income Rs 500,000 samma 1% (natural person), 5 lakh dekhi 7 lakh samma 10%, 7 lakh dekhi 20 lakh samma 20%, 20 lakh dekhi 50 lakh samma 30% ra 50 lakh bhanda mathi 36% cha.", answerEn: "For FY 2080/81, annual income up to 500k 1% (natural person), 500k-700k 10%, 700k-2M 20%, 2M-5M 30%, and above 5M 36%.", answerShortNe: "FY 2080/81 ma yearly income Rs 500,000 samma 1% (natural person), 5 lakh dekhi 7 lakh samma 10%, 7 lakh dekhi 20 lakh samma 20%, 20 lakh dekhi 50 lakh samma 30%", currentAsOf: "FY 2080/81", legalReference: "Income Tax Act 2058, Schedule 1", relatedTopics: ["Tax deduction", "Advance tax", "Tax return"], commonFollowups: ["Couple ko lagi slab ke ho?", "1% social security fund ho?"], intent: "accounting_qa", notTransaction: true},
  {id: "taxfaq-008", topic: "Corporate Tax Rate", topicKey: "corporate_tax_rate", questionNe: "Nepal ma company lai corporate tax kati lagcha?", questionEn: "What is the corporate tax rate in Nepal?", questionNormalized: "nepal ma company lai corporate tax kati lagcha", answerNe: "Normal business ko lagi 25% corporate tax lagcha. Banks ra financial institutions lai 30%, hydropower ra special industries lai 10-20% samma cha.", answerEn: "The normal corporate tax rate is 25%. Banks and financial institutions pay 30%, while hydropower and special industries have rates ranging from 10-20%.", answerShortNe: "Normal business ko lagi 25% corporate tax lagcha.", currentAsOf: "FY 2080/81", legalReference: "Income Tax Act 2058, Section 2", relatedTopics: ["Tax exemption", "Advance tax", "TDS"], commonFollowups: ["Micro/Small enterprise ko rate ke cha?", "Dividend ma tax lagcha?"], intent: "accounting_qa", notTransaction: true},
  {id: "taxfaq-009", topic: "Tax Deduction at Source (TDS) Rates", topicKey: "tax_deduction_at_source_tds_rates", questionNe: "TDS rate kati kati cha?", questionEn: "What are the TDS rates in Nepal?", questionNormalized: "tds rate kati kati cha", answerNe: "Interest ma 5%, dividend ma 5%, rent ma 10%, commission/meeting fee ma 15%, contract payment ma 1.5% TDS kataincha. Praya 15% rate general payment ma lagu huncha.", answerEn: "TDS rates are 5% on interest, 5% on dividends, 10% on rent, 15% on commission/meeting fees, 1.5% on contract payments. Generally 15% applies to miscellaneous payments.", answerShortNe: "Interest ma 5%, dividend ma 5%, rent ma 10%, commission/meeting fee ma 15%, contract payment ma 1.", currentAsOf: "FY 2080/81", legalReference: "Income Tax Act 2058, Section 87/88", relatedTopics: ["TDS deposit", "TDS return", "Tax credit"], commonFollowups: ["TDS kateko paisa ka bharne?", "TDS kahile katni?"], intent: "accounting_qa", notTransaction: true},
  {id: "taxfaq-010", topic: "TDS Deposit Timeline", topicKey: "tds_deposit_timeline", questionNe: "TDS ko raka deposit kahile garne?", questionEn: "When should TDS be deposited?", questionNormalized: "tds ko raka deposit kahile garne", answerNe: "TDS katayeko mahina ko aaudo mahina 25 gate bhanda agadi Revenue Account ma jamma garne garnu parcha.", answerEn: "TDS deducted must be deposited into the Revenue Account by the 25th of the following month.", answerShortNe: "TDS katayeko mahina ko aaudo mahina 25 gate bhanda agadi Revenue Account ma jamma garne garnu parcha.", currentAsOf: "FY 2080/81", legalReference: "Income Tax Act 2058, Section 90", relatedTopics: ["TDS return", "Penalty", "TDS rates"], commonFollowups: ["Der bhayo bhane ke huncha?", "eTDS garnu parcha?"], intent: "accounting_qa", notTransaction: true},
  {id: "taxfaq-011", topic: "TDS Return Filing", topicKey: "tds_return_filing", questionNe: "TDS return kahile file garne?", questionEn: "When to file TDS return?", questionNormalized: "tds return kahile file garne", answerNe: "TDS return har mahina katayeko mahina aawadhi pachi 15 gate bhanda agadi file garna parcha. Barsa ko 12 wota return file garna parcha.", answerEn: "TDS return must be filed by the 15th of the following month after the deduction month. 12 returns must be filed annually.", answerShortNe: "TDS return har mahina katayeko mahina aawadhi pachi 15 gate bhanda agadi file garna parcha.", currentAsOf: "FY 2080/81", legalReference: "Income Tax Act 2058, Section 90", relatedTopics: ["TDS rates", "TDS deposit", "Penalty"], commonFollowups: ["TDS kateko rakam kata dekhaune?", "File nagare ke fine lagcha?"], intent: "accounting_qa", notTransaction: true},
  {id: "taxfaq-012", topic: "Advance Tax Installment", topicKey: "advance_tax_installment", questionNe: "Advance tax kati kishthama tirne?", questionEn: "How many installments for advance tax?", questionNormalized: "advance tax kati kishthama tirne", answerNe: "Assessed income ko aadhar ma 40%, 30%, 30% ko dar le Poush end, Chaitra end, ra Ashad end ma advance tax tirna parcha.", answerEn: "Advance tax is paid in three installments of 40%, 30%, 30% based on the assessed income by the end of Poush, Chaitra, and Ashad.", answerShortNe: "Assessed income ko aadhar ma 40%, 30%, 30% ko dar le Poush end, Chaitra end, ra Ashad end ma advance tax tirna parcha.", currentAsOf: "FY 2080/81", legalReference: "Income Tax Act 2058, Section 94", relatedTopics: ["Income tax return", "Penalty", "Tax assessment"], commonFollowups: ["Naya business le kati advance tax tirne?", "Time ma tiriyena bhane ke huncha?"], intent: "accounting_qa", notTransaction: true},
  {id: "taxfaq-013", topic: "Permanent Account Number (PAN)", topicKey: "permanent_account_number_pan", questionNe: "PAN card kasaile banauna parcha?", questionEn: "Who needs a PAN card?", questionNormalized: "pan card kasaile banauna parcha", answerNe: "Taxable income bhaye darta huna sabai byakti ra sanstha lai PAN chaincha. Rs 500 jari kharcha tirera IRD bata PAN liya jana sakincha.", answerEn: "All individuals and entities with taxable income must register for a PAN. It can be obtained from IRD by paying a registration fee of Rs 500.", answerShortNe: "Taxable income bhaye darta huna sabai byakti ra sanstha lai PAN chaincha.", currentAsOf: "FY 2080/81", legalReference: "Income Tax Act 2058, Section 100", relatedTopics: ["Income tax return", "TDS", "Tax clearance"], commonFollowups: ["PAN banauna ke chahincha?", "Online banauna milcha?"], intent: "accounting_qa", notTransaction: true},
  {id: "taxfaq-014", topic: "Income Tax Return Due Date", topicKey: "income_tax_return_due_date", questionNe: "Income tax return kahile file garne?", questionEn: "When to file income tax return?", questionNormalized: "income tax return kahile file garne", answerNe: "Vyaktigat income tax return Poush end samma (3 months extension) file garna milcha. Company le aafno year end ko 6 mahina bhanda dhilo garna hudaina.", answerEn: "Personal income tax returns can be filed by the end of Poush (3 months extension). Companies must file within 6 months of their fiscal year end.", answerShortNe: "Vyaktigat income tax return Poush end samma (3 months extension) file garna milcha.", currentAsOf: "FY 2080/81", legalReference: "Income Tax Act 2058, Section 96", relatedTopics: ["Advance tax", "Penalty", "Audit report"], commonFollowups: ["Date extend garna milcha?", "Return late bhaye kati penalty?"], intent: "accounting_qa", notTransaction: true},
  {id: "taxfaq-015", topic: "Customs Import Duty", topicKey: "customs_import_duty", questionNe: "Nepal ma customs duty kati lagcha?", questionEn: "What is the customs duty in Nepal?", questionNormalized: "nepal ma customs duty kati lagcha", answerNe: "Customs duty rates 0% dekhi 60% samma HS code anusar farak parcha. Aadharbhut khadya saman ma 5-15%, luxury ma 40%+, raw materials ma 1-10% dastoor lagcha.", answerEn: "Customs duty rates vary from 0% to 60% based on HS codes. Basic food items 5-15%, luxury goods 40%+, raw materials 1-10% duty applies.", answerShortNe: "Customs duty rates 0% dekhi 60% samma HS code anusar farak parcha.", currentAsOf: "FY 2080/81", legalReference: "Customs Act 2064", relatedTopics: ["HS Code", "Excise duty", "Anti-dumping"], commonFollowups: ["HS code kaha bata thaha paune?", "Customs calculator cha?"], intent: "accounting_qa", notTransaction: true},
  {id: "taxfaq-016", topic: "Excise Duty", topicKey: "excise_duty", questionNe: "Excise duty kati lagcha?", questionEn: "What is the excise duty rate?", questionNormalized: "excise duty kati lagcha", answerNe: "Excise duty surti, madyapadarth, soft drinks, luxury items ra gadi ma lagcha. Rate ad valorem (%, e.g., 25-60%) athawa specific rate (per unit) ma huncha.", answerEn: "Excise duty applies to tobacco, alcohol, soft drinks, luxury items, and vehicles. Rates are either ad valorem (%, e.g., 25-60%) or specific rates (per unit).", answerShortNe: "Excise duty surti, madyapadarth, soft drinks, luxury items ra gadi ma lagcha.", currentAsOf: "FY 2080/81", legalReference: "Excise Act 2058", relatedTopics: ["Customs duty", "VAT", "HS Code"], commonFollowups: ["Excise duty ko sworup ke ho?", "Excise return kasari file garne?"], intent: "accounting_qa", notTransaction: true},
  {id: "taxfaq-017", topic: "HS Code", topicKey: "hs_code", questionNe: "HS code ke ho?", questionEn: "What is HS code?", questionNormalized: "hs code ke ho", answerNe: "Harmonized System (HS) code biswabhar ma mannyata prapt saman ko classification system ho, jasle customs valuation ra duty determinate garcha.", answerEn: "The Harmonized System (HS) code is a globally standardized classification system for goods that determines customs valuation and duty rates.", answerShortNe: "Harmonized System (HS) code biswabhar ma mannyata prapt saman ko classification system ho, jasle customs valuation ra duty determinate garcha.", currentAsOf: "FY 2080/81", legalReference: "Customs Tariff Act", relatedTopics: ["Customs duty", "Export", "Import license"], commonFollowups: ["HS code kaha pauncha?", "Customs rate table kaha cha?"], intent: "accounting_qa", notTransaction: true},
  {id: "taxfaq-018", topic: "Property Tax", topicKey: "property_tax", questionNe: "Sampati kar kati tirne?", questionEn: "What is the property tax rate?", questionNormalized: "sampati kar kati tirne", answerNe: "Sthaniya sarkar (Gaupalika/Nagarpalika) le sampati ko prakar ra location adi anusar sampati kar nirdharan garcha. Dharauti mulya ya area aadhar ma progressive rate huncha.", answerEn: "Local governments (Rural/Municipal) determine property tax based on property type and location. Progressive rates apply based on assessed value or area.", answerShortNe: "Sthaniya sarkar (Gaupalika/Nagarpalika) le sampati ko prakar ra location adi anusar sampati kar nirdharan garcha.", currentAsOf: "FY 2080/81", legalReference: "Local Government Operation Act 2074, Section 55", relatedTopics: ["Local tax", "Vehicle tax", "Rental tax"], commonFollowups: ["Calculation kasari garne?", "Fine lagcha bhane kati?"], intent: "accounting_qa", notTransaction: true},
  {id: "taxfaq-019", topic: "Vehicle Tax", topicKey: "vehicle_tax", questionNe: "Gadi ko tax kati tirne?", questionEn: "What is the vehicle tax rate?", questionNormalized: "gadi ko tax kati tirne", answerNe: "Sawari sadhan kar engine capacity (CC) ra prakar anusar prabesh ma eak patak ra barshik navikaran garne gari staniya sarkar le rate nirdharan garcha.", answerEn: "Vehicle tax is determined by the local government based on engine capacity (CC) and type, payable as a one-time entry tax and annual renewal.", answerShortNe: "Sawari sadhan kar engine capacity (CC) ra prakar anusar prabesh ma eak patak ra barshik navikaran garne gari staniya sarkar le rate nirdharan garcha.", currentAsOf: "FY 2080/81", legalReference: "Local Government Operation Act 2074", relatedTopics: ["Property tax", "Road tax", "Customs duty"], commonFollowups: ["Tax kaha tirne?", "Purano gadi ko tax ke huncha?"], intent: "accounting_qa", notTransaction: true},
  {id: "taxfaq-020", topic: "Penalty for Late Filing", topicKey: "penalty_for_late_filing", questionNe: "Tax return dhila file garda kati penalty?", questionEn: "What is the penalty for late tax filing?", questionNormalized: "tax return dhila file garda kati penalty", answerNe: "File nagarema Income Tax Act anushar 0.01% to 0.05% per day late fee, plus Rs 5,000 prabarsa samma extra penalty huna sakcha. VAT ma per return Rs 2000 dekhi Rs 8000 penalty cha.", answerEn: "Under the Income Tax Act, late fees range from 0.01% to 0.05% per day, plus up to Rs 5,000 extra penalty per instance. VAT penalties range from Rs 2,000 to Rs 8,000 per return.", answerShortNe: "File nagarema Income Tax Act anushar 0.", currentAsOf: "FY 2080/81", legalReference: "Income Tax Act 2058, VAT Act 2052", relatedTopics: ["Tax return", "TDS return", "Interest"], commonFollowups: ["Penalty chhut garne milecha?", "Punishment pani huncha?"], intent: "accounting_qa", notTransaction: true},
  {id: "taxfaq-021", topic: "Corporate Tax for Micro/SSE", topicKey: "corporate_tax_for_micro_sse", questionNe: "Micro business ko tax rate kati cha?", questionEn: "What is the tax rate for micro businesses?", questionNormalized: "micro business ko tax rate kati cha", answerNe: "Classification anusar micro, small ra medium enterprises lai kehi sarsahuliyat cha. Nepal ma Micro (10 lakh samma capital) ra Small business ko lagi certain income threshold ma 0.75% ya turnover based tax lagcha.", answerEn: "Micro (capital up to 10 lakh) and small enterprises enjoy concessions. Certain thresholds allow for a 0.75% turnover-based tax or prescribed slab rates.", answerShortNe: "Classification anusar micro, small ra medium enterprises lai kehi sarsahuliyat cha.", currentAsOf: "FY 2080/81", legalReference: "Industrial Enterprises Act 2076, Income Tax Act", relatedTopics: ["VAT threshold", "PAN", "Tax exemption"], commonFollowups: ["Registration process ke cha?", "Audit garna parcha?"], intent: "accounting_qa", notTransaction: true},
  {id: "taxfaq-022", topic: "Tax Clearance Certificate", topicKey: "tax_clearance_certificate", questionNe: "Tax clearance certificate kasari paune?", questionEn: "How to get a tax clearance certificate?", questionNormalized: "tax clearance certificate kasari paune", answerNe: "Sabai tax details updated gari, audit report (company ko lagi) ra applicable documents submit garera IRD ko online system bata niwedan dine.", answerEn: "Submit an application via IRD's online system with all tax details updated, audit report (for companies), and applicable documents.", answerShortNe: "Sabai tax details updated gari, audit report (company ko lagi) ra applicable documents submit garera IRD ko online system bata niwedan dine.", currentAsOf: "FY 2080/81", legalReference: "Income Tax Act 2058, Section 105", relatedTopics: ["PAN", "Tax audit", "VAT clearance"], commonFollowups: ["Lina kati din lagcha?", "Purpose ke ke ma chahincha?"], intent: "accounting_qa", notTransaction: true},
  {id: "taxfaq-023", topic: "Withholding on Rent", topicKey: "withholding_on_rent", questionNe: "Rent ma TDS kati katne?", questionEn: "What is TDS on rent?", questionNormalized: "rent ma tds kati katne", answerNe: "Basobas arthath ghar bhada ma 10% TDS katni parcha. Byawasayik prayojan ko lagi tireko bhadai ma 10% TDS kataincha.", answerEn: "10% TDS must be deducted on residential house rent. 10% TDS is also deducted on rent paid for business purposes.", answerShortNe: "Basobas arthath ghar bhada ma 10% TDS katni parcha.", currentAsOf: "FY 2080/81", legalReference: "Income Tax Act 2058, Section 87", relatedTopics: ["TDS deposit", "Rental income", "Tax credit"], commonFollowups: ["Ghar dhani lai TDS dina parcha?", "Contract rent ma kati lagcha?"], intent: "accounting_qa", notTransaction: true},
  {id: "taxfaq-024", topic: "Withholding on Interest", topicKey: "withholding_on_interest", questionNe: "Interest income ma TDS kati katne?", questionEn: "What is TDS on interest income?", questionNormalized: "interest income ma tds kati katne", answerNe: "Nepal ma bank ko nikshep ra debenture ma 5% TDS kataincha. Anya byakti bata liyeko rin ko interest ma 15% TDS lagcha.", answerEn: "TDS of 5% applies to bank deposits and debentures. Interest on loans from other individuals attracts 15% TDS.", answerShortNe: "Nepal ma bank ko nikshep ra debenture ma 5% TDS kataincha.", currentAsOf: "FY 2080/81", legalReference: "Income Tax Act 2058, Section 87", relatedTopics: ["TDS rates", "Investment", "Savings"], commonFollowups: ["Banks le automatic katne ho?", "Tax return ma adjust huncha?"], intent: "accounting_qa", notTransaction: true},
  {id: "taxfaq-025", topic: "Medical Tax Credit", topicKey: "medical_tax_credit", questionNe: "Income tax ma medical kharcha credit kati pauncha?", questionEn: "What is the medical tax credit limit?", questionNormalized: "income tax ma medical kharcha credit kati pauncha", answerNe: "Byakti le chikitsha kharach bapat 15% athawa adhikatam Rs 750 prabarsa samma credit pauna sakne byawastha cha.", answerEn: "Individuals can claim a medical tax credit of up to 15% of the expense or a maximum of Rs 750 per year.", answerShortNe: "Byakti le chikitsha kharach bapat 15% athawa adhikatam Rs 750 prabarsa samma credit pauna sakne byawastha cha.", currentAsOf: "FY 2080/81", legalReference: "Income Tax Act 2058, Section 51", relatedTopics: ["Insurance premium", "Tax rebate", "Income slab"], commonFollowups: ["Insurance premium ma pani pauncha?", "Bill rakhnai parcha?"], intent: "accounting_qa", notTransaction: true},
  {id: "taxfaq-026", topic: "Remote Area Tax Benefit", topicKey: "remote_area_tax_benefit", questionNe: "Durgam kshetra ma tax chhut ke cha?", questionEn: "What is the tax benefit for remote areas?", questionNormalized: "durgam kshetra ma tax chhut ke cha", answerNe: "Durgam kshetra ma karyarat karmachari lai 20% dekhi 50% samma tax exemption cha. Company lai pani certain areas ma 20% dekhi 50% samma discount cha.", answerEn: "Employees working in remote areas get 20% to 50% tax exemption. Companies also receive 20% to 50% tax discounts in certain designated areas.", answerShortNe: "Durgam kshetra ma karyarat karmachari lai 20% dekhi 50% samma tax exemption cha.", currentAsOf: "FY 2080/81", legalReference: "Income Tax Act 2058, Schedule 1", relatedTopics: ["Corporate tax", "Salary tax", "Investment"], commonFollowups: ["Kun kshetra durgam ma parcha?", "Log book rakhnu parcha?"], intent: "accounting_qa", notTransaction: true},
  {id: "taxfaq-027", topic: "Export Tax", topicKey: "export_tax", questionNe: "Export ma tax lagcha ki nai?", questionEn: "Is there tax on exports?", questionNormalized: "export ma tax lagcha ki nai", answerNe: "Export ma customs duty lagdaina (Zero rated). VAT ko lagi pani zero rate hunale input tax credit refund garna milcha.", answerEn: "Exports are zero-rated for customs duty. For VAT, it is also zero-rated, allowing a refund of input tax credits.", answerShortNe: "Export ma customs duty lagdaina (Zero rated).", currentAsOf: "FY 2080/81", legalReference: "VAT Act 2052, Customs Act", relatedTopics: ["VAT refund", "Export incentive", "Customs"], commonFollowups: ["Rebate paincha?", "Export VAT kasari claim garne?"], intent: "accounting_qa", notTransaction: true},
  {id: "taxfaq-028", topic: "Local Professional Tax", topicKey: "local_professional_tax", questionNe: "Professional tax ke ho?", questionEn: "What is professional tax?", questionNormalized: "professional tax ke ho", answerNe: "Sthaniya sarkar le doctor, engineer, lawyer, auditor jasta pesagat byakti lai barshik swikriti kar (professional tax) lagau garna sakcha.", answerEn: "Local governments can levy an annual license tax (professional tax) on professionals such as doctors, engineers, lawyers, and auditors.", answerShortNe: "Sthaniya sarkar le doctor, engineer, lawyer, auditor jasta pesagat byakti lai barshik swikriti kar (professional tax) lagau garna sakcha.", currentAsOf: "FY 2080/81", legalReference: "Local Government Operation Act 2074", relatedTopics: ["Local tax", "Business license", "PAN"], commonFollowups: ["Kati amount tirne?", "Multiple profession bhaye k garne?"], intent: "accounting_qa", notTransaction: true},
  {id: "taxfaq-029", topic: "Capital Gains Tax", topicKey: "capital_gains_tax", questionNe: "Capital gains tax kati lagcha?", questionEn: "What is the capital gains tax rate?", questionNormalized: "capital gains tax kati lagcha", answerNe: "Sampati/security bikri garda natural person lai 5% (fixed deposit) ra listed shares ma 5%/7.5% (individual/institutional) lagcha. Jagga ma 5% dekhi 10% samma cha.", answerEn: "Natural persons pay 5% on fixed deposit gains, and 5%/7.5% on listed shares (individual/institutional). Land sales attract 5% to 10%.", answerShortNe: "Sampati/security bikri garda natural person lai 5% (fixed deposit) ra listed shares ma 5%/7.", currentAsOf: "FY 2080/81", legalReference: "Income Tax Act 2058, Section 95", relatedTopics: ["Land tax", "Shares", "Investment income"], commonFollowups: ["Short term ra long term rate ke ho?", "Dharauti mulya dekhi farak?"], intent: "accounting_qa", notTransaction: true},
  {id: "taxfaq-030", topic: "E-Commerce Tax", topicKey: "e_commerce_tax", questionNe: "Online business lai tax ke cha?", questionEn: "What is the tax for e-commerce?", questionNormalized: "online business lai tax ke cha", answerNe: "E-commerce business lai pani normal business jastai income tax ra VAT lagcha. Foreign entity le digital service provide garda 2% turnover tax (VAT) lagcha.", answerEn: "E-commerce businesses are subject to normal income tax and VAT. Foreign entities providing digital services face a 2% turnover tax (VAT).", answerShortNe: "E-commerce business lai pani normal business jastai income tax ra VAT lagcha.", currentAsOf: "FY 2080/81", legalReference: "Income Tax Act, Finance Act", relatedTopics: ["VAT registration", "Digital service", "Tax return"], commonFollowups: ["Foreign company lai PAN chaincha?", "Payment gateway ma tax katne ki?"], intent: "accounting_qa", notTransaction: true},
  {id: "taxfaq-031", topic: "Gift Tax", topicKey: "gift_tax", questionNe: "Gift tax Nepal ma lagcha?", questionEn: "Is there gift tax in Nepal?", questionNormalized: "gift tax nepal ma lagcha", answerNe: "Kehi paristhiti ma gift amount lai income manine byabastha cha. Afanta bata property transfer ma nalagepani unnatural/undue influence bhayema tax lagcha.", answerEn: "In some circumstances, gift amounts can be treated as income. While family property transfers may be exempt, unnatural transfers may attract tax.", answerShortNe: "Kehi paristhiti ma gift amount lai income manine byabastha cha.", currentAsOf: "FY 2080/81", legalReference: "Income Tax Act 2058", relatedTopics: ["Income tax", "Property transfer", "Capital gains"], commonFollowups: ["Close family ko list ke cha?", "Gift tax rate kati ho?"], intent: "accounting_qa", notTransaction: true},
  {id: "taxfaq-032", topic: "Tax on NGOs", topicKey: "tax_on_ngos", questionNe: "NGO lai tax lagcha ki nai?", questionEn: "Are NGOs taxed in Nepal?", questionNormalized: "ngo lai tax lagcha ki nai", answerNe: "NGO lai certain conditions pura bhaye income tax chhut huncha. Tara PAN line, audit garne ra return file garne daayitwa huncha. VAT ma chai 13% lagcha.", answerEn: "NGOs can get income tax exemption if they meet certain conditions. However, they must obtain PAN, conduct audits, and file returns. VAT at 13% applies.", answerShortNe: "NGO lai certain conditions pura bhaye income tax chhut huncha.", currentAsOf: "FY 2080/81", legalReference: "Income Tax Act 2058, Section 2", relatedTopics: ["PAN", "Tax exemption", "Audit"], commonFollowups: ["NGO le TDS katnu parcha?", "SWC ma darta chaincha?"], intent: "accounting_qa", notTransaction: true},
  {id: "taxfaq-033", topic: "Business Vehicle Tax", topicKey: "business_vehicle_tax", questionNe: "Byawasayik gadi ko tax ke ho?", questionEn: "What is the tax for business vehicles?", questionNormalized: "byawasayik gadi ko tax ke ho", answerNe: "Company le gadi leaunda customs, excise ra VAT tirna parcha. Barseni staniya sarkar lai sawari kar tire pani byawasaya ko kharcha ma dekhai tax ghatayera faida lina sakcha.", answerEn: "Companies must pay customs, excise, and VAT when purchasing vehicles. Annual local vehicle tax can be shown as business expenses, reducing taxable income.", answerShortNe: "Company le gadi leaunda customs, excise ra VAT tirna parcha.", currentAsOf: "FY 2080/81", legalReference: "Income Tax Act, Local Govt Act", relatedTopics: ["Vehicle tax", "Depreciation", "Customs duty"], commonFollowups: ["Depreciation rate kati ho?", "Personal use gadi ko tax?"], intent: "accounting_qa", notTransaction: true},
  {id: "taxfaq-034", topic: "Pension Tax", topicKey: "pension_tax", questionNe: "Pension ma income tax lagcha?", questionEn: "Is pension taxable in Nepal?", questionNormalized: "pension ma income tax lagcha", answerNe: "Sarkari nijamati ra sangathit sector ko pension ma 25% exemption pachi bakhi rakam ma slab anusar tax lagcha. Deposit based pension yojana ma kehi suwidha cha.", answerEn: "Government, civil service, and organized sector pensions get a 25% exemption, and the remaining amount is taxed as per slabs. Deposit-based pension schemes have some benefits.", answerShortNe: "Sarkari nijamati ra sangathit sector ko pension ma 25% exemption pachi bakhi rakam ma slab anusar tax lagcha.", currentAsOf: "FY 2080/81", legalReference: "Income Tax Act 2058, Finance Act", relatedTopics: ["Salary tax", "Retirement fund", "Insurance"], commonFollowups: ["Gratuity ma tax lagcha?", "Commuted pension k ho?"], intent: "accounting_qa", notTransaction: true},
  {id: "taxfaq-035", topic: "Penalty for Not Deducting TDS", topicKey: "penalty_for_not_deducting_tds", questionNe: "TDS na kate ke huncha?", questionEn: "What happens if TDS is not deducted?", questionNormalized: "tds na kate ke huncha", answerNe: "TDS na kateko rakam, 15% interest ra total amount ko 20% penalty tirai dine dayitwa huncha, katai nakatayeko apradh maninchha.", answerEn: "The undeducted TDS amount, plus 15% interest and a 20% penalty on the total amount, must be paid. It is treated as an offense.", answerShortNe: "TDS na kateko rakam, 15% interest ra total amount ko 20% penalty tirai dine dayitwa huncha, katai nakatayeko apradh maninchha.", currentAsOf: "FY 2080/81", legalReference: "Income Tax Act 2058, Section 87", relatedTopics: ["TDS deposit", "Penalty", "Tax audit"], commonFollowups: ["Principal amount ma credit paincha?", "Court case lagcha?"], intent: "accounting_qa", notTransaction: true},
  {id: "taxfaq-036", topic: "Tax Residency", topicKey: "tax_residency", questionNe: "Tax resident kasaile manincha?", questionEn: "Who is considered a tax resident?", questionNormalized: "tax resident kasaile manincha", answerNe: "Aay barsa ma 183 din Nepal ma basne byakti athawa Nepal bata income ko source bhako byakti lai tax resident manincha.", answerEn: "An individual staying in Nepal for 183 days in an income year or having a source of income in Nepal is considered a tax resident.", answerShortNe: "Aay barsa ma 183 din Nepal ma basne byakti athawa Nepal bata income ko source bhako byakti lai tax resident manincha.", currentAsOf: "FY 2080/81", legalReference: "Income Tax Act 2058, Section 2", relatedTopics: ["Income tax return", "Double taxation", "PAN"], commonFollowups: ["NRN lai ke suwidha cha?", "Double tax avoidance ke ho?"], intent: "accounting_qa", notTransaction: true},
  {id: "taxfaq-037", topic: "Digital Service Tax", topicKey: "digital_service_tax", questionNe: "Digital service provider lai tax ke cha?", questionEn: "What is the tax for digital service providers?", questionNormalized: "digital service provider lai tax ke cha", answerNe: "Non-resident digital service provider lai 2% turnover based tax (VAT) registration garera quarterly return file garne byabastha cha.", answerEn: "Non-resident digital service providers must register for a 2% turnover-based tax (VAT) and file quarterly returns.", answerShortNe: "Non-resident digital service provider lai 2% turnover based tax (VAT) registration garera quarterly return file garne byabastha cha.", currentAsOf: "FY 2080/81", legalReference: "Finance Act 2079", relatedTopics: ["E-commerce tax", "VAT registration", "Foreign income"], commonFollowups: ["Nepal ma office chaine ho?", "Netflix/Google lai kati tax lagcha?"], intent: "accounting_qa", notTransaction: true},
  {id: "taxfaq-038", topic: "Cooperative Tax", topicKey: "cooperative_tax", questionNe: "Sahakari sanstha ko tax rate ke ho?", questionEn: "What is the tax rate for cooperatives?", questionNormalized: "sahakari sanstha ko tax rate ke ho", answerNe: "Bachat ra rin sahakari lai kehi limit samma tax chut huncha. General cooperative lai 25% ra special sectors lai 20% corporate tax lagcha.", answerEn: "Savings and loan cooperatives get tax exemptions up to certain limits. General cooperatives pay 25% and special sectors pay 20% corporate tax.", answerShortNe: "Bachat ra rin sahakari lai kehi limit samma tax chut huncha.", currentAsOf: "FY 2080/81", legalReference: "Income Tax Act 2058", relatedTopics: ["Corporate tax", "Dividend tax", "Microfinance"], commonFollowups: ["Sadasya transaction ma TDS lagcha?", "Audit garna parcha?"], intent: "accounting_qa", notTransaction: true},
  {id: "taxfaq-039", topic: "Inheritance Tax", topicKey: "inheritance_tax", questionNe: "Nepal ma Inheritance tax lagcha?", questionEn: "Is there inheritance tax in Nepal?", questionNormalized: "nepal ma inheritance tax lagcha", answerNe: "Nepal ma aanshik aakar ma pani Inheritance/Estate tax lagu chaina. Tara sampati transfer garda capital gains tax ra registration fee lagcha.", answerEn: "Nepal does not have Inheritance/Estate tax in any form. However, property transfer involves capital gains tax and registration fees.", answerShortNe: "Nepal ma aanshik aakar ma pani Inheritance/Estate tax lagu chaina.", currentAsOf: "FY 2080/81", legalReference: "Income Tax Act, Muluki Dewani Samhita", relatedTopics: ["Gift tax", "Property tax", "Capital gains"], commonFollowups: ["Kunai tax change hudai cha?", "Property registration fee kati ho?"], intent: "accounting_qa", notTransaction: true},
  {id: "taxfaq-040", topic: "Tax on Share Transactions", topicKey: "tax_on_share_transactions", questionNe: "Share market ma tax kati ho?", questionEn: "What is the tax on share transactions?", questionNormalized: "share market ma tax kati ho", answerNe: "Dharauti saraah bikri garda 0.015% sebi tax lagcha. Capital gains ma natural person lai 5% ya 7.5% income tax cha.", answerEn: "SEBI tax of 0.015% applies on share collateral sales. Capital gains tax of 5% or 7.5% applies to natural persons.", answerShortNe: "Dharauti saraah bikri garda 0.", currentAsOf: "FY 2080/81", legalReference: "Income Tax Act, Securities Act", relatedTopics: ["Capital gains tax", "Broker commission", "IPO tax"], commonFollowups: ["Broker commission ma tax cha?", "NRN le share bechda tax ke cha?"], intent: "accounting_qa", notTransaction: true},
  {id: "taxfaq-041", topic: "Electric Vehicle Tax", topicKey: "electric_vehicle_tax", questionNe: "Electric gadi ko tax ke cha?", questionEn: "What is the tax on electric vehicles?", questionNormalized: "electric gadi ko tax ke cha", answerNe: "Electric gadi ko customs duty 10% matra cha ra excise pani chhut gariyeko cha. 40-50% tax suwidha cha petrol gadi bhanda.", answerEn: "Customs duty on electric vehicles is only 10%, and excise is exempted. There is a 40-50% tax benefit compared to petrol vehicles.", answerShortNe: "Electric gadi ko customs duty 10% matra cha ra excise pani chhut gariyeko cha.", currentAsOf: "FY 2080/81", legalReference: "Finance Act, Customs Tariff", relatedTopics: ["Vehicle tax", "Customs duty", "Excise duty"], commonFollowups: ["Charger ma tax ke cha?", "Luxury EV lai pani same ho?"], intent: "accounting_qa", notTransaction: true},
  {id: "taxfaq-042", topic: "Contract Payment Tax", topicKey: "contract_payment_tax", questionNe: "Contract payment ma TDS kati katne?", questionEn: "What is TDS on contract payments?", questionNormalized: "contract payment ma tds kati katne", answerNe: "Thekedari bhukhtani ma 1.5% TDS kataincha. Tenant/consultant lai 15%, mechanic lai 10% TDS lagu huncha.", answerEn: "1.5% TDS is deducted on contract payments. 15% applies to tenants/consultants and 10% to mechanics.", answerShortNe: "Thekedari bhukhtani ma 1.", currentAsOf: "FY 2080/81", legalReference: "Income Tax Act 2058, Section 88", relatedTopics: ["TDS deposit", "Work contract", "VAT on contract"], commonFollowups: ["Construction contract ho bhane ke rate?", "Bills ma VAT pani jodne ho?"], intent: "accounting_qa", notTransaction: true},
  {id: "taxfaq-043", topic: "Foreign Investment Tax", topicKey: "foreign_investment_tax", questionNe: "Nepal ma foreign investment lai ke tax cha?", questionEn: "What is the tax on foreign investment?", questionNormalized: "nepal ma foreign investment lai ke tax cha", answerNe: "Foreign investment lai Nepal ma normal tax lagcha. 50% had samma foreign loan ko interest (thin cap rule) capital manincha ra tax lagcha.", answerEn: "Normal tax applies to foreign investment in Nepal. Under thin capitalization rules, up to 50% of foreign loan interest can be treated as capital and taxed.", answerShortNe: "Foreign investment lai Nepal ma normal tax lagcha.", currentAsOf: "FY 2080/81", legalReference: "Income Tax Act, FITTA", relatedTopics: ["Repatriation", "Tax holiday", "TDS on royalty"], commonFollowups: ["Profit repatriate garda tax ke cha?", "DTAA ke ke cha?"], intent: "accounting_qa", notTransaction: true},
  {id: "taxfaq-044", topic: "Agriculture Tax", topicKey: "agriculture_tax", questionNe: "Krishi income ma tax lagcha?", questionEn: "Is agricultural income taxable?", questionNormalized: "krishi income ma tax lagcha", answerNe: "Vyaktigat krishi aaya kar mukt cha. Tara company dwara garine commercial farming ra tea estate ma normal tax lagcha.", answerEn: "Personal agricultural income is tax-exempt. However, commercial farming and tea estates operated by companies are subject to normal tax.", answerShortNe: "Vyaktigat krishi aaya kar mukt cha.", currentAsOf: "FY 2080/81", legalReference: "Income Tax Act 2058", relatedTopics: ["Tax exemption", "Land tax", "Commercial farming"], commonFollowups: ["Pashupalan ma tax lagcha?", "Greenhouse farming ko tax?"], intent: "accounting_qa", notTransaction: true},
  {id: "taxfaq-045", topic: "Insurance Premium Tax Credit", topicKey: "insurance_premium_tax_credit", questionNe: "Insurance premium ma tax credit pauncha?", questionEn: "Is there a tax credit on insurance premiums?", questionNormalized: "insurance premium ma tax credit pauncha", answerNe: "Jeevan bima premium ko 40% athawa adhikatam Rs 25,000 prabarsa income tax credit pauncha. Swasthya bima ma pani similar suwidha cha.", answerEn: "A tax credit of 40% of the life insurance premium or a maximum of Rs 25,000 per year is available. Similar benefits apply to health insurance.", answerShortNe: "Jeevan bima premium ko 40% athawa adhikatam Rs 25,000 prabarsa income tax credit pauncha.", currentAsOf: "FY 2080/81", legalReference: "Income Tax Act 2058, Section 51", relatedTopics: ["Medical credit", "Tax rebate", "Insurance"], commonFollowups: ["Couple lai double pauncha?", "Bima maturity ma tax lagcha?"], intent: "accounting_qa", notTransaction: true},
  {id: "taxfaq-046", topic: "Bootstrap Penalty", topicKey: "bootstrap_penalty", questionNe: "Tax officer le dhamki diyo bhane?", questionEn: "What if a tax officer threatens?", questionNormalized: "tax officer le dhamki diyo bhane", answerNe: "Tax officer le manomanni garda Department ya Revenue Board ma ujoor garna paaincha. Tax audit unfair bhayema admin review ma jana sakincha.", answerEn: "If a tax officer acts arbitrarily, complaints can be filed with the Department or Revenue Board. Unfair tax audits can be taken up for administrative review.", answerShortNe: "Tax officer le manomanni garda Department ya Revenue Board ma ujoor garna paaincha.", currentAsOf: "FY 2080/81", legalReference: "Income Tax Act 2058, Right to information", relatedTopics: ["Tax audit", "Penalty", "Appeal"], commonFollowups: ["Notice ayo, k garne?", "Revenue Tribunal kahile jane?"], intent: "accounting_qa", notTransaction: true},
  {id: "taxfaq-047", topic: "Double Taxation Avoidance", topicKey: "double_taxation_avoidance", questionNe: "DTAA Nepal ko sanga sanga cha?", questionEn: "DTAA is with which countries?", questionNormalized: "dtaa nepal ko sanga sanga cha", answerNe: "Nepal le 11 desh sanga DTAA gareko cha. Jastai India, China, Qatar ra South Korea. Bank interest 5-15% dependent ma reduce bhayeko cha.", answerEn: "Nepal has DTAA with 11 countries, including India, China, Qatar, and South Korea. Bank interest is reduced to 5-15% dependent on the agreement.", answerShortNe: "Nepal le 11 desh sanga DTAA gareko cha.", currentAsOf: "FY 2080/81", legalReference: "Income Tax Act 2058, Treaties", relatedTopics: ["Tax residency", "Foreign tax credit", "TDS"], commonFollowups: ["USA sanga DTAA cha?", "Foreign income declare garne ki nai?"], intent: "accounting_qa", notTransaction: true},
  {id: "taxfaq-048", topic: "VAT Reconciliation", topicKey: "vat_reconciliation", questionNe: "VAT reconciliation ke ho?", questionEn: "What is VAT reconciliation?", questionNormalized: "vat reconciliation ke ho", answerNe: "Bikri ra khata bahi anusar file gareko VAT return milan garne kaam reconciliation ho. Barsa bhari 12 wota return ra audit report milan anibaraya cha.", answerEn: "VAT reconciliation is matching filed VAT returns with sales and account books. Matching 12 monthly returns with the audit report is mandatory.", answerShortNe: "Bikri ra khata bahi anusar file gareko VAT return milan garne kaam reconciliation ho.", currentAsOf: "FY 2080/81", legalReference: "VAT Act 2052", relatedTopics: ["VAT return", "Audit report", "Income tax return"], commonFollowups: ["ETDS sanga milena bhane?", "Milan audit garne ko ho?"], intent: "accounting_qa", notTransaction: true},
  {id: "taxfaq-049", topic: "Audit Report Submission", topicKey: "audit_report_submission", questionNe: "Tax audit report kasko chaine?", questionEn: "Who needs a tax audit report?", questionNormalized: "tax audit report kasko chaine", answerNe: "Company ra certain limit bhanda mathi turnover bhayeko byawasaya lai income tax ra VAT audit report IRD ma file garna parcha.", answerEn: "Companies and businesses exceeding a certain turnover limit must file income tax and VAT audit reports with IRD.", answerShortNe: "Company ra certain limit bhanda mathi turnover bhayeko byawasaya lai income tax ra VAT audit report IRD ma file garna parcha.", currentAsOf: "FY 2080/81", legalReference: "Income Tax Act 2058, Section 97", relatedTopics: ["Auditor", "Tax return", "Penalty"], commonFollowups: ["Auditor ko yogyata ke ho?", "Report date kati ho?"], intent: "accounting_qa", notTransaction: true},
  {id: "taxfaq-050", topic: "Map based tax", topicKey: "map_based_tax", questionNe: "Naksha pass bina ghar ko tax kati?", questionEn: "What is the tax for houses without map approval?", questionNormalized: "naksha pass bina ghar ko tax kati", answerNe: "Naksha pass nabhai baneko ghar lai staniya sarkar le 25% dekhi 50% samma extra sampati kar lagau garna sakcha.", answerEn: "Local governments can impose an additional 25% to 50% property tax on houses built without map approval.", answerShortNe: "Naksha pass nabhai baneko ghar lai staniya sarkar le 25% dekhi 50% samma extra sampati kar lagau garna sakcha.", currentAsOf: "FY 2080/81", legalReference: "Local Govt Operation Act", relatedTopics: ["Property tax", "Building permit", "Local tax"], commonFollowups: ["Regularize garna milcha?", "Fine tirera pass huncha?"], intent: "accounting_qa", notTransaction: true},
  {id: "taxfaq-051", topic: "Tax on Royalty", topicKey: "tax_on_royalty", questionNe: "Royalty ma tax kati lagcha?", questionEn: "What is the tax on royalty?", questionNormalized: "royalty ma tax kati lagcha", answerNe: "Non-resident lai tireko royalty ma 15% final withholding tax lagcha (DTAA dependent). Resident lai normal income tax nai lagcha.", answerEn: "A 15% final withholding tax applies to royalties paid to non-residents (DTAA dependent). Residents are subject to normal income tax.", answerShortNe: "Non-resident lai tireko royalty ma 15% final withholding tax lagcha (DTAA dependent).", currentAsOf: "FY 2080/81", legalReference: "Income Tax Act 2058, Section 87", relatedTopics: ["TDS", "Foreign payment", "DTAA"], commonFollowups: ["Copyright fee pani same ho?", "Technical service fee ma kati?"], intent: "accounting_qa", notTransaction: true},
  {id: "taxfaq-052", topic: "Payment of Tax", topicKey: "payment_of_tax", questionNe: "Tax payment kasari garne?", questionEn: "How to pay taxes?", questionNormalized: "tax payment kasari garne", answerNe: "IRD bata generate gareko PAN based Revenue Receipts (PRN) prayog gari online banking, eSewa, athawa bank counter bata tirna sakincha.", answerEn: "Taxes can be paid via online banking, eSewa, or bank counters using PAN-based Revenue Receipts (PRN) generated from IRD.", answerShortNe: "IRD bata generate gareko PAN based Revenue Receipts (PRN) prayog gari online banking, eSewa, athawa bank counter bata tirna sakincha.", currentAsOf: "FY 2080/81", legalReference: "Income Tax Manual", relatedTopics: ["eTDS", "PAN", "Tax return"], commonFollowups: ["Cash tire ke huncha?", "International payment milcha?"], intent: "accounting_qa", notTransaction: true},
  {id: "taxfaq-053", topic: "Inward Investment Tax", topicKey: "inward_investment_tax", questionNe: "Investment ma ke tax chhut cha?", questionEn: "What tax incentives exist for investment?", questionNormalized: "investment ma ke tax chhut cha", answerNe: "Hydropower, manufacturing, infrastructure ra tourism ma 5-10 barsa samma tax holiday pauna sakcha. 100% depreciation pani suwidha cha.", answerEn: "Tax holidays of 5-10 years are available for hydropower, manufacturing, infrastructure, and tourism. 100% depreciation benefits also exist.", answerShortNe: "Hydropower, manufacturing, infrastructure ra tourism ma 5-10 barsa samma tax holiday pauna sakcha.", currentAsOf: "FY 2080/81", legalReference: "Income Tax Act, Industry Act", relatedTopics: ["Corporate tax", "Depreciation", "Tax holiday"], commonFollowups: ["Hotel industry ma ke cha?", "Special Economic Zone ma k huncha?"], intent: "accounting_qa", notTransaction: true},
  {id: "taxfaq-054", topic: "Non-Resident Tax", topicKey: "non_resident_tax", questionNe: "Non-resident lai Nepal ma tax kati lagcha?", questionEn: "What is the tax rate for non-residents?", questionNormalized: "non-resident lai nepal ma tax kati lagcha", answerNe: "Non-resident lai Nepal srot ko income ma 25% samma withholding tax lagcha. Certain service ma 15% ra 5% pani lagcha.", answerEn: "Non-residents pay up to 25% withholding tax on income sourced in Nepal. Certain services attract 15% and 5%.", answerShortNe: "Non-resident lai Nepal srot ko income ma 25% samma withholding tax lagcha.", currentAsOf: "FY 2080/81", legalReference: "Income Tax Act 2058, Section 87", relatedTopics: ["DTAA", "TDS", "Foreign employment"], commonFollowups: ["Nepal ma ghar bhada ma tax lagcha?", "Retired abroad ho bhane pension tax?"], intent: "accounting_qa", notTransaction: true},
  {id: "taxfaq-055", topic: "Property Gain Tax", topicKey: "property_gain_tax", questionNe: "Jagga bechda tax kati lagcha?", questionEn: "What is the tax on land sales?", questionNormalized: "jagga bechda tax kati lagcha", answerNe: "Vyaktigat jagga bikri garda dharauti mulya ka aadhar ma 5% dekhi 10% samma capital gains tax lagcha. Holding period anusar exemptions cha.", answerEn: "Individual land sales attract 5% to 10% capital gains tax based on the assessed value. Exemptions exist based on the holding period.", answerShortNe: "Vyaktigat jagga bikri garda dharauti mulya ka aadhar ma 5% dekhi 10% samma capital gains tax lagcha.", currentAsOf: "FY 2080/81", legalReference: "Income Tax Act 2058, Land Revenue Act", relatedTopics: ["Capital gains", "Registration fee", "Inheritance tax"], commonFollowups: ["Primary residence bechda kati?", "Long term lai chhut cha?"], intent: "accounting_qa", notTransaction: true},
  {id: "taxfaq-056", topic: "Tax on Dividends", topicKey: "tax_on_dividends", questionNe: "Dividend ma tax kati katne?", questionEn: "What is the tax on dividends?", questionNormalized: "dividend ma tax kati katne", answerNe: "Company le dividend bhand garda 5% withholding tax kataincha. Byakti ma aaipugda final tax treatment huncha.", answerEn: "Companies withhold a 5% tax when distributing dividends. This is treated as final tax for individuals.", answerShortNe: "Company le dividend bhand garda 5% withholding tax kataincha.", currentAsOf: "FY 2080/81", legalReference: "Income Tax Act 2058, Section 87", relatedTopics: ["Corporate tax", "Investment", "Shareholder"], commonFollowups: ["Bonus share ma tax cha?", "Reinvest bhaye ke huncha?"], intent: "accounting_qa", notTransaction: true},
  {id: "taxfaq-057", topic: "Local Business Tax", topicKey: "local_business_tax", questionNe: "Pasalko tax kati tirne?", questionEn: "What is the local business tax?", questionNormalized: "pasalko tax kati tirne", answerNe: "Sthaniya sarkar le byawasaya ko prakar anusar bersik byawasaya kar (business tax) nirdharan garcha, jo pachhi sampati kar sangai tirna parcha.", answerEn: "Local governments determine annual business tax based on the type of business, which must be paid along with property tax.", answerShortNe: "Sthaniya sarkar le byawasaya ko prakar anusar bersik byawasaya kar (business tax) nirdharan garcha, jo pachhi sampati kar sangai tirna parcha.", currentAsOf: "FY 2080/81", legalReference: "Local Government Operation Act 2074, Section 55", relatedTopics: ["Property tax", "Business license", "Professional tax"], commonFollowups: ["Kati amount tirne?", "Renewal process ke ho?"], intent: "accounting_qa", notTransaction: true},
  {id: "taxfaq-058", topic: "Tax on Interest from Abroad", topicKey: "tax_on_interest_from_abroad", questionNe: "Bidesh ko interest income ma tax?", questionEn: "Is foreign interest income taxable?", questionNormalized: "bidesh ko interest income ma tax", answerNe: "Nepal ma basne tax resident le bidesh ko bank interest income dekhayema foreign tax credit claim garna sakcha, tara Nepal ma pani tax dina sakcha.", answerEn: "Nepal resident tax residents declaring foreign bank interest can claim foreign tax credits, but tax may also be due in Nepal.", answerShortNe: "Nepal ma basne tax resident le bidesh ko bank interest income dekhayema foreign tax credit claim garna sakcha, tara Nepal ma pani tax dina sakcha.", currentAsOf: "FY 2080/81", legalReference: "Income Tax Act, DTAA", relatedTopics: ["Foreign income", "Tax credit", "Non-resident"], commonFollowups: ["NRN account ko interest tax free ho?", "Report kasari garne?"], intent: "accounting_qa", notTransaction: true},
  {id: "taxfaq-059", topic: "Turnover Tax", topicKey: "turnover_tax", questionNe: "Turnover tax ke ho?", questionEn: "What is turnover tax?", questionNormalized: "turnover tax ke ho", answerNe: "Small taxpayers lai Rs 1 lakh samma chhut, 1L-2.5L ma 0.25%, 2.5L-5L ma 0.5%, 5L-10L ma 1.5% samma turnover tax tirne suwidha cha.", answerEn: "Small taxpayers have turnover tax benefits: up to Rs 1L exempt, 1L-2.5L 0.25%, 2.5L-5L 0.5%, 5L-10L up to 1.5%.", answerShortNe: "Small taxpayers lai Rs 1 lakh samma chhut, 1L-2.", currentAsOf: "FY 2080/81", legalReference: "Income Tax Act 2058, Finance Act", relatedTopics: ["VAT registration", "Income tax slab", "Micro tax"], commonFollowups: ["VAT register garna parcha?", "Income tax separate tirne ho?"], intent: "accounting_qa", notTransaction: true},
  {id: "taxfaq-060", topic: "Hotel Tax", topicKey: "hotel_tax", questionNe: "Hotel lai tax ke cha?", questionEn: "What is the tax for hotels?", questionNormalized: "hotel lai tax ke cha", answerNe: "Hotel lai normal 25% corporate tax lagcha, tara tourist standard ko hotel le 20% tirna paune suwidha cha. VAT 13% ra sewa soolka pani cha.", answerEn: "Normal 25% corporate tax applies, but tourist-standard hotels benefit from a 20% rate. VAT 13% and service charges also apply.", answerShortNe: "Hotel lai normal 25% corporate tax lagcha, tara tourist standard ko hotel le 20% tirna paune suwidha cha.", currentAsOf: "FY 2080/81", legalReference: "Income Tax Act, VAT Act", relatedTopics: ["Corporate tax", "Tourism tax", "VAT"], commonFollowups: ["Restaurant ko rate kati?", "Foreign currency ma bill?"], intent: "accounting_qa", notTransaction: true},
  {id: "taxfaq-061", topic: "Education Tax", topicKey: "education_tax", questionNe: "School ko income ma tax lagcha?", questionEn: "Is school income taxable?", questionNormalized: "school ko income ma tax lagcha", answerNe: "Sarkari school ko income tax exempt cha. Private school chai company saraha 25% income tax ra VAT (educational service ma chhut) bujhaunu parcha.", answerEn: "Government school income is tax-exempt. Private schools must pay 25% income tax like companies and VAT (educational services are exempt).", answerShortNe: "Sarkari school ko income tax exempt cha.", currentAsOf: "FY 2080/81", legalReference: "Income Tax Act, Education Act", relatedTopics: ["Tax exemption", "NGO tax", "Corporate tax"], commonFollowups: ["Books ma VAT lagcha?", "Consultancy lai tax chhut cha?"], intent: "accounting_qa", notTransaction: true},
  {id: "taxfaq-062", topic: "Permanent Establishment", topicKey: "permanent_establishment", questionNe: "PE concept Nepal ma ke ho?", questionEn: "What is the PE concept in Nepal?", questionNormalized: "pe concept nepal ma ke ho", answerNe: "Foreign company ko Nepal ma fixed base bhaye PE kaim garincha ra Nepal ma bhako income/asset ma tax tirna parcha.", answerEn: "A PE is established if a foreign company has a fixed base in Nepal, making income/assets in Nepal taxable.", answerShortNe: "Foreign company ko Nepal ma fixed base bhaye PE kaim garincha ra Nepal ma bhako income/asset ma tax tirna parcha.", currentAsOf: "FY 2080/81", legalReference: "Income Tax Act, DTAA", relatedTopics: ["DTAA", "Non-resident tax", "Liaison office"], commonFollowups: ["Liaison office PE huncha?", "Site office 6 months bhanda mathi?"], intent: "accounting_qa", notTransaction: true},
  {id: "taxfaq-063", topic: "Assessable Income", topicKey: "assessable_income", questionNe: "Assessable income ke ho?", questionEn: "What is assessable income?", questionNormalized: "assessable income ke ho", answerNe: "Business profit, salary, house rent, investment return sabai jodera prasashkiya kharcha ghatayera aauda aako rakam assessable income ho.", answerEn: "Assessable income is the total of business profit, salary, house rent, and investment returns after deducting administrative expenses.", answerShortNe: "Business profit, salary, house rent, investment return sabai jodera prasashkiya kharcha ghatayera aauda aako rakam assessable income ho.", currentAsOf: "FY 2080/81", legalReference: "Income Tax Act 2058, Section 7", relatedTopics: ["Taxable income", "Deduction", "Loss adjustment"], commonFollowups: ["Loss set off kasari garne?", "Donation deduct huncha?"], intent: "accounting_qa", notTransaction: true},
  {id: "taxfaq-064", topic: "Penalty for Not Filing ETDS", topicKey: "penalty_for_not_filing_etds", questionNe: "E-TDS file nagare ke huncha?", questionEn: "What is the penalty for not filing E-TDS?", questionNormalized: "e-tds file nagare ke huncha", answerNe: "E-TDS return file nagare Rs 50,000 samma penalty ra lagat ko byabstha cha. Mahina ko 15 gate pachi daily late fee lagcha.", answerEn: "A penalty of up to Rs 50,000 and daily late fees apply if the E-TDS return is not filed after the 15th of the month.", answerShortNe: "E-TDS return file nagare Rs 50,000 samma penalty ra lagat ko byabstha cha.", currentAsOf: "FY 2080/81", legalReference: "Income Tax Act 2058, Finance Act", relatedTopics: ["TDS return", "Penalty", "eTDS"], commonFollowups: ["Correction file garna milcha?", "Interest kati din?"], intent: "accounting_qa", notTransaction: true},
  {id: "taxfaq-065", topic: "Crypto Tax", topicKey: "crypto_tax", questionNe: "Cryptocurrency ma tax lagcha?", questionEn: "Is cryptocurrency taxed?", questionNormalized: "cryptocurrency ma tax lagcha", answerNe: "Nepal ma cryptocurrency karobar awaidha cha, ra jabardast kar hataune jariwana sahit sambhawit kar darkar cha.", answerEn: "Cryptocurrency trading is illegal in Nepal and carries severe penalties including potential confiscation, though tax implications apply if income is detected.", answerShortNe: "Nepal ma cryptocurrency karobar awaidha cha, ra jabardast kar hataune jariwana sahit sambhawit kar darkar cha.", currentAsOf: "FY 2080/81", legalReference: "NRB Act, Income Tax", relatedTopics: ["Asset tax", "Capital gains", "Legal income"], commonFollowups: ["Mining ma tax lagcha?", "Foreign wallet use garchu?"], intent: "accounting_qa", notTransaction: true},
  {id: "taxfaq-066", topic: "Bank Guarantee Tax", topicKey: "bank_guarantee_tax", questionNe: "Bank guarantee ma tax cha?", questionEn: "Is there tax on bank guarantees?", questionNormalized: "bank guarantee ma tax cha", answerNe: "Bank guarantee charge income le bank lai tax liability dincha. Grahak le tirne guarantee fee ma 15% TDS kataincha.", answerEn: "Bank guarantee charge income creates tax liability for the bank. The guarantee fee paid by the customer is subject to 15% TDS.", answerShortNe: "Bank guarantee charge income le bank lai tax liability dincha.", currentAsOf: "FY 2080/81", legalReference: "Income Tax Act 2058", relatedTopics: ["TDS on commission", "Banking tax", "VAT on banking"], commonFollowups: ["Bid bond ma kati TDS?", "Performance guarantee ke rate?"], intent: "accounting_qa", notTransaction: true},
  {id: "taxfaq-067", topic: "VAT Registration Process", topicKey: "vat_registration_process", questionNe: "VAT registration kasari garne?", questionEn: "How to register for VAT?", questionNormalized: "vat registration kasari garne", answerNe: "IRD ko online portal bari nivedan garda PAN, sthaniya sarkar ko darta, ra byawasaya sthala ko details sahita file garda VAT darta huncha.", answerEn: "Apply via the IRD online portal with PAN, local government registration, and business premise details to obtain VAT registration.", answerShortNe: "IRD ko online portal bari nivedan garda PAN, sthaniya sarkar ko darta, ra byawasaya sthala ko details sahita file garda VAT darta huncha.", currentAsOf: "FY 2080/81", legalReference: "VAT Act 2052, VAT Rules", relatedTopics: ["PAN", "VAT threshold", "VAT return"], commonFollowups: ["Online apply garna milcha?", "Documents ke ke chaincha?"], intent: "accounting_qa", notTransaction: true},
  {id: "taxfaq-068", topic: "Tax on Retirement Fund", topicKey: "tax_on_retirement_fund", questionNe: "Retirement fund (EPF/SSF) ma tax?", questionEn: "Is retirement fund (EPF/SSF) taxed?", questionNormalized: "retirement fund (epf/ssf) ma tax", answerNe: "Yogdan garda 1% social security tax lagcha. Nikalda 5% TDS katine byabastha cha, tara 25% exemption suwidha cha.", answerEn: "A 1% social security tax applies on contribution. On withdrawal, 5% TDS applies, but a 25% exemption benefit is available.", answerShortNe: "Yogdan garda 1% social security tax lagcha.", currentAsOf: "FY 2080/81", legalReference: "Income Tax Act, SSF Act", relatedTopics: ["Pension tax", "Gratuity", "Salary tax"], commonFollowups: ["Anivarya ho ki swechhik?", "Interest ma tax kati?"], intent: "accounting_qa", notTransaction: true},
  {id: "taxfaq-069", topic: "Transfer Pricing", topicKey: "transfer_pricing", questionNe: "Transfer pricing ke ho?", questionEn: "What is transfer pricing?", questionNormalized: "transfer pricing ke ho", answerNe: "Sambandhit pakshya bich transactions ma arm's length price kayam garna parcha. Nabhaye tax officer le adjustment garne adhikar rakhcha.", answerEn: "Transactions between associated parties must be at arm's length price. Otherwise, the tax officer has the right to make adjustments.", answerShortNe: "Sambandhit pakshya bich transactions ma arm's length price kayam garna parcha.", currentAsOf: "FY 2080/81", legalReference: "Income Tax Act 2058, Section 33", relatedTopics: ["Tax audit", "Associated person", "International tax"], commonFollowups: ["Documentation ke chaincha?", "Penalty kati huncha?"], intent: "accounting_qa", notTransaction: true},
  {id: "taxfaq-070", topic: "Tax Appeal Process", topicKey: "tax_appeal_process", questionNe: "Tax order ma chitta nabujhe ke garne?", questionEn: "What to do if unsatisfied with a tax order?", questionNormalized: "tax order ma chitta nabujhe ke garne", answerNe: "Tax officer ko nirnaya birudh 30 din bhitra administrative review, tespachhi Revenue Tribunal ma appeal garna sakincha.", answerEn: "An administrative review can be filed within 30 days against a tax officer's decision, followed by an appeal to the Revenue Tribunal.", answerShortNe: "Tax officer ko nirnaya birudh 30 din bhitra administrative review, tespachhi Revenue Tribunal ma appeal garna sakincha.", currentAsOf: "FY 2080/81", legalReference: "Income Tax Act 2058, Revenue Tribunal Act", relatedTopics: ["Tax audit", "Penalty", "Tax clearance"], commonFollowups: ["Court jana kati kharcha?", "Stay order pauncha?"], intent: "accounting_qa", notTransaction: true},
  {id: "taxfaq-071", topic: "Tax on Sale of Business", topicKey: "tax_on_sale_of_business", questionNe: "Business bechda tax ke huncha?", questionEn: "What is the tax on selling a business?", questionNormalized: "business bechda tax ke huncha", answerNe: "Slump sale ya itemized sale anusar capital gains tax lagcha. Assets ko valuation anusar 5% dekhi 25% samma effective tax lagcha.", answerEn: "Capital gains tax applies on slump sale or itemized sale, with an effective rate of 5% to 25% based on asset valuation.", answerShortNe: "Slump sale ya itemized sale anusar capital gains tax lagcha.", currentAsOf: "FY 2080/81", legalReference: "Income Tax Act 2058", relatedTopics: ["Capital gains", "VAT", "Depreciation"], commonFollowups: ["Stock transfer ma kati tax?", "Liabilities transfer bhaye tax?"], intent: "accounting_qa", notTransaction: true},
  {id: "taxfaq-072", topic: "Private Vehicle Import Tax", topicKey: "private_vehicle_import_tax", questionNe: "Nijji gadi import ma kati tax?", questionEn: "What is the tax on private vehicle imports?", questionNormalized: "nijji gadi import ma kati tax", answerNe: "Petrol/Diesel gadi ma 60% dekhi 300% samma customs, excise, ra VAT lagera kul tax 200%+ pugcha.", answerEn: "For petrol/diesel vehicles, customs, excise, and VAT range from 60% to 300%, bringing total taxes to 200%+.", answerShortNe: "Petrol/Diesel gadi ma 60% dekhi 300% samma customs, excise, ra VAT lagera kul tax 200%+ pugcha.", currentAsOf: "FY 2080/81", legalReference: "Customs Act, Finance Act", relatedTopics: ["Electric vehicle tax", "Customs duty", "Excise duty"], commonFollowups: ["Motorcycle ma kati ho?", "Old vehicle import garna milcha?"], intent: "accounting_qa", notTransaction: true},
  {id: "taxfaq-073", topic: "Tax on Books and Stationery", topicKey: "tax_on_books_and_stationery", questionNe: "Kitab ra stationary ma tax cha?", questionEn: "Is there tax on books and stationery?", questionNormalized: "kitab ra stationary ma tax cha", answerNe: "Kitab ma VAT chhut cha, stationary ma 13% VAT lagcha. Import ma kitab duty-free, stationary ma 5-15% duty cha.", answerEn: "VAT is exempt on books, while stationery attracts 13% VAT. Book imports are duty-free; stationery imports have 5-15% duty.", answerShortNe: "Kitab ma VAT chhut cha, stationary ma 13% VAT lagcha.", currentAsOf: "FY 2080/81", legalReference: "VAT Act, Customs Tariff", relatedTopics: ["Customs duty", "Education tax", "Printing"], commonFollowups: ["School bag ma ke cha?", "Online book ma tax?"], intent: "accounting_qa", notTransaction: true},
  {id: "taxfaq-074", topic: "Tax on Rent Income", topicKey: "tax_on_rent_income", questionNe: "Rent income ma tax kati lagcha?", questionEn: "What is the tax on rental income?", questionNormalized: "rent income ma tax kati lagcha", answerNe: "Byakti lai rent income ma salary jastai slab anusar tax lagcha. Company lai 25% lagcha. 10% TDS credit lincha.", answerEn: "Individuals are taxed on rental income as per slabs, similar to salary. Companies pay 25%. 10% TDS credit is taken.", answerShortNe: "Byakti lai rent income ma salary jastai slab anusar tax lagcha.", currentAsOf: "FY 2080/81", legalReference: "Income Tax Act 2058", relatedTopics: ["TDS on rent", "Property tax", "Income slab"], commonFollowups: ["Ghar repair kharcha ghatna milcha?", "Multiple ghar bhaye k garne?"], intent: "accounting_qa", notTransaction: true},
  {id: "taxfaq-075", topic: "Tax on Lottery/Gift", topicKey: "tax_on_lottery_gift", questionNe: "Lottery ra gift ma tax cha?", questionEn: "Is there tax on lottery and gifts?", questionNormalized: "lottery ra gift ma tax cha", answerNe: "Lottery ma 25% final withholding tax lagcha. Gift ma unnatural transaction bhaye income manine byabastha cha.", answerEn: "A 25% final withholding tax applies to lottery winnings. Unnatural gifts are treated as income.", answerShortNe: "Lottery ma 25% final withholding tax lagcha.", currentAsOf: "FY 2080/81", legalReference: "Income Tax Act 2058", relatedTopics: ["Gift tax", "Inheritance tax", "TDS rates"], commonFollowups: ["Prize bond ko tax kati ho?", "Cash gift ma tax lagcha?"], intent: "accounting_qa", notTransaction: true},
  {id: "taxfaq-076", topic: "Loss Carry Forward", topicKey: "loss_carry_forward", questionNe: "Business loss carry forward kati barsa?", questionEn: "How many years for business loss carry forward?", questionNormalized: "business loss carry forward kati barsa", answerNe: "General business loss 7 barsa samma ra hydropower/priority industry ma 12 barsa samma loss carry forward garera future profit ma adjust garna sakincha.", answerEn: "General business losses can be carried forward for 7 years, and for hydropower/priority industries, up to 12 years, to adjust against future profits.", answerShortNe: "General business loss 7 barsa samma ra hydropower/priority industry ma 12 barsa samma loss carry forward garera future profit ma adjust garna sakincha.", currentAsOf: "FY 2080/81", legalReference: "Income Tax Act 2058, Section 12", relatedTopics: ["Assessable income", "Tax calculation", "Depreciation"], commonFollowups: ["Capital loss ko rule ke ho?", "Merger ma loss jancha?"], intent: "accounting_qa", notTransaction: true},
  {id: "taxfaq-077", topic: "Tax on Commission", topicKey: "tax_on_commission", questionNe: "Commission income ma tax ke ho?", questionEn: "What is the tax on commission income?", questionNormalized: "commission income ma tax ke ho", answerNe: "Commission bhukhtani garda 15% TDS kataincha. Byakti ko lagi final tax manincha athawa return file garera claim garna milcha.", answerEn: "15% TDS is deducted on commission payments. It is treated as final tax for individuals or can be claimed by filing a return.", answerShortNe: "Commission bhukhtani garda 15% TDS kataincha.", currentAsOf: "FY 2080/81", legalReference: "Income Tax Act 2058, Section 87", relatedTopics: ["TDS rates", "Agency income", "Salary tax"], commonFollowups: ["Agent lai VAT pani lagcha?", "TDS credit kasari line?"], intent: "accounting_qa", notTransaction: true},
  {id: "taxfaq-078", topic: "Tax on Foreign Travel", topicKey: "tax_on_foreign_travel", questionNe: "Bidesh jada airport tax kati?", questionEn: "What is the airport tax for foreign travel?", questionNormalized: "bidesh jada airport tax kati", answerNe: "Bidesh jada TIA bata Rs 2,500 (SAARC) ra Rs 3,500 (Anya) barshik sewa soolka tireko huna parcha, jaslai tourism service fee pani bhanincha.", answerEn: "When traveling abroad from TIA, an annual service fee of Rs 2,500 (SAARC) or Rs 3,500 (Other) must be paid, also known as tourism service fee.", answerShortNe: "Bidesh jada TIA bata Rs 2,500 (SAARC) ra Rs 3,500 (Anya) barshik sewa soolka tireko huna parcha, jaslai tourism service fee pani bhanincha.", currentAsOf: "FY 2080/81", legalReference: "Finance Act, Aviation Policy", relatedTopics: ["Customs duty", "Travel tax", "Airline ticket tax"], commonFollowups: ["Ticket ma included huncha?", "Labour lai ke cha?"], intent: "accounting_qa", notTransaction: true},
  {id: "taxfaq-079", topic: "Tax on Sale of Shares", topicKey: "tax_on_sale_of_shares", questionNe: "Share bechda kati tax lagcha?", questionEn: "What is the tax on selling shares?", questionNormalized: "share bechda kati tax lagcha", answerNe: "Listed shares ma natural person lai 5% ra institutional lai 7.5% capital gains tax lagcha. Unlisted shares ma 10% lagcha.", answerEn: "Listed shares: 5% for natural persons and 7.5% for institutional. Unlisted shares attract 10% capital gains tax.", answerShortNe: "Listed shares ma natural person lai 5% ra institutional lai 7.", currentAsOf: "FY 2080/81", legalReference: "Income Tax Act 2058", relatedTopics: ["Capital gains", "Broker commission", "IPO"], commonFollowups: ["Bonus share ma tax?", "Right share bechda?"], intent: "accounting_qa", notTransaction: true},
  {id: "taxfaq-080", topic: "Tax on Hydropower", topicKey: "tax_on_hydropower", questionNe: "Hydropower project lai ke tax chhut cha?", questionEn: "What tax exemptions do hydropower projects get?", questionNormalized: "hydropower project lai ke tax chhut cha", answerNe: "Hydropower lai 10 barsa samma income tax chhut, 1% turnover tax tirna suwidha, ra construction period ma VAT exemption jasta suwidha chan.", answerEn: "Hydropower projects get income tax exemption for 10 years, a 1% turnover tax option, and VAT exemption during the construction period.", answerShortNe: "Hydropower lai 10 barsa samma income tax chhut, 1% turnover tax tirna suwidha, ra construction period ma VAT exemption jasta suwidha chan.", currentAsOf: "FY 2080/81", legalReference: "Income Tax Act, Electricity Act", relatedTopics: ["Tax holiday", "Loss carry forward", "Royalty"], commonFollowups: ["Royalty kati ho?", "Project bechda ke huncha?"], intent: "accounting_qa", notTransaction: true},
  {id: "taxfaq-081", topic: "Tax on Medical Equipment", topicKey: "tax_on_medical_equipment", questionNe: "Medical equipment ma tax cha?", questionEn: "Is there tax on medical equipment?", questionNormalized: "medical equipment ma tax cha", answerNe: "Aatayasiik ausadhi ra equipment ma customs duty 1% ra VAT chhut cha. Anya equipment ma 5% customs ra 13% VAT cha.", answerEn: "Essential medicines and equipment have 1% customs duty and VAT exemption. Other equipment faces 5% customs and 13% VAT.", answerShortNe: "Aatayasiik ausadhi ra equipment ma customs duty 1% ra VAT chhut cha.", currentAsOf: "FY 2080/81", legalReference: "Customs Tariff, VAT Act", relatedTopics: ["Excise duty", "Health tax", "Customs duty"], commonFollowups: ["Hospital le import garda ke chhut cha?", "Diagnostic kit ma tax?"], intent: "accounting_qa", notTransaction: true},
  {id: "taxfaq-082", topic: "Tax on Marriage Expenses", topicKey: "tax_on_marriage_expenses", questionNe: "Bihe kharcha ma tax chhut cha?", questionEn: "Is there a tax exemption on marriage expenses?", questionNormalized: "bihe kharcha ma tax chhut cha", answerNe: "Nepal ma bihe kharcha ma kunai tax chhut chaina. Tara bihe ko upahar (gift) ma unnatural transaction bhaye matra tax lagcha.", answerEn: "There is no tax exemption on marriage expenses in Nepal. Marriage gifts are only taxed if deemed an unnatural transaction.", answerShortNe: "Nepal ma bihe kharcha ma kunai tax chhut chaina.", currentAsOf: "FY 2080/81", legalReference: "Income Tax Act 2058", relatedTopics: ["Gift tax", "Inheritance tax", "Income source"], commonFollowups: ["Bihe ko gift tax free ho?", "Gold/jewellery ma tax?"], intent: "accounting_qa", notTransaction: true},
  {id: "taxfaq-083", topic: "Tax on Import of Gold", topicKey: "tax_on_import_of_gold", questionNe: "Gold import ma tax kati lagcha?", questionEn: "What is the tax on gold imports?", questionNormalized: "gold import ma tax kati lagcha", answerNe: "Commercial banks le matra gold import garna paune ra 20% customs duty lagcha. Vyaktigat 50 gram samma sun lyauda Rs 8,500/10 gram tax cha.", answerEn: "Only commercial banks can import gold, attracting 20% customs duty. Individuals can bring up to 50 grams with a tax of Rs 8,500 per 10 grams.", answerShortNe: "Commercial banks le matra gold import garna paune ra 20% customs duty lagcha.", currentAsOf: "FY 2080/81", legalReference: "Customs Act, NRB Act", relatedTopics: ["Customs duty", "Excise", "NRB regulation"], commonFollowups: ["Airport ma gold kurne tax ke cha?", "Silver ma tax kati?"], intent: "accounting_qa", notTransaction: true},
  {id: "taxfaq-084", topic: "Tax on Heavy Equipment", topicKey: "tax_on_heavy_equipment", questionNe: "Excavator, crane ma tax kati ho?", questionEn: "What is the tax on heavy equipment?", questionNormalized: "excavator, crane ma tax kati ho", answerNe: "Excavator, crane ma 5% customs duty ra 13% VAT lagcha. Construction work ma prayog hune ho bhane depreciation 20% pauncha.", answerEn: "Excavators and cranes face 5% customs duty and 13% VAT. If used for construction work, 20% depreciation is available.", answerShortNe: "Excavator, crane ma 5% customs duty ra 13% VAT lagcha.", currentAsOf: "FY 2080/81", legalReference: "Customs Tariff, Income Tax Act", relatedTopics: ["Customs duty", "Depreciation", "VAT refund"], commonFollowups: ["Second hand import garna milcha?", "Excise duty lagcha?"], intent: "accounting_qa", notTransaction: true},
  {id: "taxfaq-085", topic: "Tax on Tobacco", topicKey: "tax_on_tobacco", questionNe: "Surti janaya padartha ma tax kati ho?", questionEn: "What is the tax on tobacco products?", questionNormalized: "surti janaya padartha ma tax kati ho", answerNe: "Churot ma 60% customs, 30% excise, 13% VAT. Bidi ra surti ma specific excise rate cha.", answerEn: "Cigarettes attract 60% customs, 30% excise, and 13% VAT. Bidi and chewing tobacco have specific excise rates.", answerShortNe: "Churot ma 60% customs, 30% excise, 13% VAT.", currentAsOf: "FY 2080/81", legalReference: "Excise Act, Customs Act", relatedTopics: ["Excise duty", "Health tax", "Customs"], commonFollowups: ["E-cigarette ma kati tax?", "Gutka ma kati?"], intent: "accounting_qa", notTransaction: true},
  {id: "taxfaq-086", topic: "Tax on Sale of Property", topicKey: "tax_on_sale_of_property", questionNe: "Ghar bechda tax kati lagcha?", questionEn: "What is the tax on selling a house?", questionNormalized: "ghar bechda tax kati lagcha", answerNe: "Ghar jagga bikri ma 5%-10% samma capital gains tax lagcha. Owner occupier lai 2 barsa bhanda purano bhaye chhut cha.", answerEn: "Capital gains tax of 5%-10% applies to house/land sales. Owner-occupiers are exempt if the property is older than 2 years.", answerShortNe: "Ghar jagga bikri ma 5%-10% samma capital gains tax lagcha.", currentAsOf: "FY 2080/81", legalReference: "Income Tax Act, Land Revenue Act", relatedTopics: ["Capital gains", "Property tax", "Registration fee"], commonFollowups: ["Multiple ghar bhaye?", "Apartment ko tax ke cha?"], intent: "accounting_qa", notTransaction: true},
  {id: "taxfaq-087", topic: "Tax on Advertisement", topicKey: "tax_on_advertisement", questionNe: "Advertisement ma tax kati lagcha?", questionEn: "What is the tax on advertisements?", questionNormalized: "advertisement ma tax kati lagcha", answerNe: "Vigyapan service ma 15% TDS ra 13% VAT lagcha. Hoarding, newspaper, radio sabai ma lagu huncha.", answerEn: "15% TDS and 13% VAT apply to advertisement services across hoardings, newspapers, and radio.", answerShortNe: "Vigyapan service ma 15% TDS ra 13% VAT lagcha.", currentAsOf: "FY 2080/81", legalReference: "Income Tax Act, VAT Act", relatedTopics: ["TDS rates", "Media tax", "Service tax"], commonFollowups: ["Facebook/Google ads ma tax?", "Local advertising agency lai kati?"], intent: "accounting_qa", notTransaction: true},
  {id: "taxfaq-088", topic: "Tax on Motorcycle Import", topicKey: "tax_on_motorcycle_import", questionNe: "Motorcycle import ma kati tax?", questionEn: "What is the tax on motorcycle imports?", questionNormalized: "motorcycle import ma kati tax", answerNe: "Motorcycle import ma 40% dekhi 60% customs, 13% VAT ra 20% excise lagcha. Engine capacity 225cc samma ma kehi chhut cha.", answerEn: "Motorcycle imports face 40% to 60% customs, 13% VAT, and 20% excise. Some exemption exists for engine capacities up to 225cc.", answerShortNe: "Motorcycle import ma 40% dekhi 60% customs, 13% VAT ra 20% excise lagcha.", currentAsOf: "FY 2080/81", legalReference: "Customs Act, Excise Act", relatedTopics: ["Vehicle tax", "Customs duty", "Electric vehicle"], commonFollowups: ["Electric scooter ko tax ke cha?", "Parts import ma kati?"], intent: "accounting_qa", notTransaction: true},
  {id: "taxfaq-089", topic: "Tax on Freelance Services", topicKey: "tax_on_freelance_services", questionNe: "Freelance income ma tax kati ho?", questionEn: "What is the tax on freelance income?", questionNormalized: "freelance income ma tax kati ho", answerNe: "Freelance income lai business income manine ra slab anusar tax lagcha. Bidesh bata income bhayema 2% VAT lagne byabastha cha.", answerEn: "Freelance income is treated as business income and taxed per slabs. Income from abroad faces a 2% VAT rule.", answerShortNe: "Freelance income lai business income manine ra slab anusar tax lagcha.", currentAsOf: "FY 2080/81", legalReference: "Income Tax Act, Finance Act", relatedTopics: ["E-commerce tax", "Digital service", "Foreign income"], commonFollowups: ["Dollar income ko tax?", "PayPal bata Nepal lyauda tax?"], intent: "accounting_qa", notTransaction: true},
  {id: "taxfaq-090", topic: "Tax on Capital Reduction", topicKey: "tax_on_capital_reduction", questionNe: "Capital reduction ma tax cha?", questionEn: "Is there tax on capital reduction?", questionNormalized: "capital reduction ma tax cha", answerNe: "Company le capital reduce garda shareholder le prapta garne raka lai dividend distribution manincha ra 5% withholding tax lagcha.", answerEn: "When a company reduces capital, the amount received by shareholders is treated as dividend distribution, attracting a 5% withholding tax.", answerShortNe: "Company le capital reduce garda shareholder le prapta garne raka lai dividend distribution manincha ra 5% withholding tax lagcha.", currentAsOf: "FY 2080/81", legalReference: "Income Tax Act 2058", relatedTopics: ["Dividend tax", "Share buyback", "Capital gains"], commonFollowups: ["Share buy back ma tax?", "Loss ma capital reduce garda?"], intent: "accounting_qa", notTransaction: true},
  {id: "taxfaq-091", topic: "Tax on House Rent Allowance", topicKey: "tax_on_house_rent_allowance", questionNe: "Ghar bhada bhatta ma tax kati?", questionEn: "Is house rent allowance taxable?", questionNormalized: "ghar bhada bhatta ma tax kati", answerNe: "Salary ko hisab ma ghar bhada bhatta prapta garne karmachari lai Rs 25,000 barshik samma suwidha kar mukt cha.", answerEn: "Employees receiving house rent allowance as part of salary get a tax-free benefit of up to Rs 25,000 per year.", answerShortNe: "Salary ko hisab ma ghar bhada bhatta prapta garne karmachari lai Rs 25,000 barshik samma suwidha kar mukt cha.", currentAsOf: "FY 2080/81", legalReference: "Income Tax Act 2058", relatedTopics: ["Salary tax", "Medical allowance", "Deduction"], commonFollowups: ["Dashain allowance ma tax cha?", "Remote area allowance?"], intent: "accounting_qa", notTransaction: true},
  {id: "taxfaq-092", topic: "Tax on Royalty and License Fees", topicKey: "tax_on_royalty_and_license_fees", questionNe: "License renewal garda tax kati?", questionEn: "What is the tax on license renewal?", questionNormalized: "license renewal garda tax kati", answerNe: "Byawasaya license renewal garda staniya sarkar le nirdharit garne soolka matra ho, tara royalty/rights bhuktanima 15% TDS lagcha.", answerEn: "Business license renewal only involves local government fees, but 15% TDS applies to royalty/rights payments.", answerShortNe: "Byawasaya license renewal garda staniya sarkar le nirdharit garne soolka matra ho, tara royalty/rights bhuktanima 15% TDS lagcha.", currentAsOf: "FY 2080/81", legalReference: "Income Tax Act, Local Govt Act", relatedTopics: ["Royalty", "TDS", "Local tax"], commonFollowups: ["Software license ma kati?", "Franchise fee ma tax?"], intent: "accounting_qa", notTransaction: true},
];

