export const LEGAL_SECTION_EXPLAINERS: LegalSectionExplainer[] = [
  {id: "legsec-001", documentType: "Income Tax Act 2058", documentTypeKey: "income_tax_act_2058", section: "Section 88 - TDS on Rent", sectionKey: "section_88_tds_on_rent", originalTextNe: "कुनै व्यक्तिले अर्को व्यक्तिलाई भाडामा रकम तिर्दा भाडा रकमको दश प्रतिशत कर कट्टी गरी...", originalTextEn: "When any person pays rent to another person, they shall deduct tax at the rate of ten percent of the rent amount...", plainLanguageNe: "Bhada tirda 10% TDS katnu parcha. Landlord lai 90% matra dinus, 10% sarkar lai.", plainLanguageEn: "When paying rent, deduct 10% TDS. Pay only 90% to landlord, deposit 10% to government.", practicalExample: "Monthly rent Rs 20000 → Pay Rs 18000 to landlord, deposit Rs 2000 TDS to IRD", commonQuestions: ["Sabai bhada ma TDS katnu parcha?", "TDS deposit kahile garne?"], exceptions: ["Residential rent below threshold may be exempt"], relatedSections: ["Section 89 - TDS on Fees"], intent: "legal_qa", notTransaction: true},
  {id: "legsec-002", documentType: "Income Tax Act 2058", documentTypeKey: "income_tax_act_2058", section: "Section 89 - TDS on Fees for Professional Services", sectionKey: "section_89_tds_on_fees_for_professional_services", originalTextNe: "व्यावसायिक सेवा शुल्क तिर्दा शुल्क रकमको पन्ध्र प्रतिशत कर कट्टी गरी राजश्व खातामा जम्मा गर्नु पर्नेछ।", originalTextEn: "While making payment for professional services, tax shall be deducted at the rate of fifteen percent of the fee amount and deposited to the revenue account.", plainLanguageNe: "Professional service ko shulk tirda 15% TDS katnu. Service provider lai 85% matra dinu, baki 15% sarkar lai bujhau.", plainLanguageEn: "Deduct 15% TDS on professional fees. Pay 85% to the service provider, remit 15% to government.", practicalExample: "Legal fee Rs 50,000 → Pay Rs 42,500 to lawyer, deposit Rs 7,500 TDS", commonQuestions: ["Kun service ma TDS lagcha?", "TDS cut nagare ke huncha?"], exceptions: ["Payments to non-residents may have different rates"], relatedSections: ["Section 88 - TDS on Rent", "Section 90 - TDS on Interest"], intent: "legal_qa", notTransaction: true},
  {id: "legsec-003", documentType: "Income Tax Act 2058", documentTypeKey: "income_tax_act_2058", section: "Section 90 - TDS on Interest", sectionKey: "section_90_tds_on_interest", originalTextNe: "बैंक तथा वित्तीय संस्थाले बचत खातामा ब्याज दिँदा ब्याज रकमको पाँच प्रतिशत कर कट्टी गरी राजश्व जम्मा गर्नु पर्नेछ।", originalTextEn: "Banks and financial institutions shall deduct tax at five percent on interest paid on savings accounts and deposit to the revenue.", plainLanguageNe: "Bank bata paune byaj ma 5% TDS katkincha. Tumlai 95% matra pauchau, 5% sarkar lai jane.", plainLanguageEn: "5% TDS is deducted on interest earned from bank savings. You get 95%, 5% goes to government.", practicalExample: "Annual interest Rs 10,000 → Receive Rs 9,500, TDS Rs 500", commonQuestions: ["Fixed deposit ma pani TDS lagcha?", "TDS cut bhako byaj income tax return ma k show garne?"], exceptions: ["Interest below Rs 2,000 per year may be exempt"], relatedSections: ["Section 91 - TDS on Dividend"], intent: "legal_qa", notTransaction: true},
  {id: "legsec-004", documentType: "Income Tax Act 2058", documentTypeKey: "income_tax_act_2058", section: "Section 91 - TDS on Dividend", sectionKey: "section_91_tds_on_dividend", originalTextNe: "कम्पनीले आफ्ना सेयरधनीलाई लाभांश वितरण गर्दा लाभांश रकमको पाँच प्रतिशत कर कट्टी गरी राजश्व जम्मा गर्नु पर्नेछ।", originalTextEn: "A company distributing dividend to its shareholders shall deduct tax at five percent of the dividend amount and deposit to revenue.", plainLanguageNe: "Company le diye ko dividend ma 5% TDS katnu. Shareholders lai 95% matra paunchan, 5% sarkar jane.", plainLanguageEn: "Deduct 5% TDS on dividend paid to shareholders. Shareholders get 95%, 5% goes to government.", practicalExample: "Dividend Rs 100,000 → Pay Rs 95,000 to shareholder, TDS Rs 5,000", commonQuestions: ["Kun dividend ma TDS lagcha?", "Non-resident shareholder lai kati TDS?"], exceptions: ["Dividend from exempt entities may be exempt"], relatedSections: ["Section 90 - TDS on Interest"], intent: "legal_qa", notTransaction: true},
  {id: "legsec-005", documentType: "Income Tax Act 2058", documentTypeKey: "income_tax_act_2058", section: "Section 92 - Tax on Business Income", sectionKey: "section_92_tax_on_business_income", originalTextNe: "व्यवसायबाट प्राप्त आयमा कर लाग्नेछ। करको दर वार्षिक आयको आधारमा निर्धारण गरिनेछ।", originalTextEn: "Tax is levied on income derived from business. The tax rate shall be determined based on annual income.", plainLanguageNe: "Business ko nafa ma income tax tirnu parcha. Jati dherai kamauchau, teti dherai tax tirnu parcha.", plainLanguageEn: "You must pay income tax on business profits. The more you earn, the more tax you pay.", practicalExample: "Annual profit Rs 500,000 → Tax approx Rs 50,000 (for individual, slab rate)", commonQuestions: ["Business income ma kati tax lagcha?", "Ghati bhaye ke garne?"], exceptions: ["Small businesses may be eligible for presumptive taxation"], relatedSections: ["Section 93 - Deductions for Business"], intent: "legal_qa", notTransaction: true},
  {id: "legsec-006", documentType: "Income Tax Act 2058", documentTypeKey: "income_tax_act_2058", section: "Section 93 - Deductions for Business Expenses", sectionKey: "section_93_deductions_for_business_expenses", originalTextNe: "व्यवसाय सञ्चालन गर्न खर्च भएको रकम आयबाट कट्टी गर्न पाइनेछ। तर व्यक्तिगत खर्च कट्टी हुँदैन।", originalTextEn: "Expenses incurred for business operations may be deducted from income. However, personal expenses shall not be deducted.", plainLanguageNe: "Business chalau kharcha (rent, salary, raw materials) lai income bata ghatayera tax calculate garna milcha. Tara personal kharcha mildeina.", plainLanguageEn: "You can deduct business expenses (rent, salary, materials) from your income before calculating tax. Personal expenses are not deductible.", practicalExample: "Income Rs 800,000, expenses Rs 300,000 → Taxable income Rs 500,000", commonQuestions: ["Kun kun kharcha deductible?", "Bill chaincha?"], exceptions: ["Capital expenditure may be depreciated, not fully deducted"], relatedSections: ["Section 94 - Depreciation"], intent: "legal_qa", notTransaction: true},
  {id: "legsec-007", documentType: "Income Tax Act 2058", documentTypeKey: "income_tax_act_2058", section: "Section 94 - Depreciation Allowance", sectionKey: "section_94_depreciation_allowance", originalTextNe: "स्थायी सम्पत्तिमा भएको मूल्य ह्रासलाई आयकर गणना गर्दा कट्टी गर्न पाइनेछ। ह्रास दर सम्पत्तिको प्रकार अनुसार फरक हुनेछ।", originalTextEn: "Depreciation on fixed assets shall be allowed as a deduction in computing income tax. The rate of depreciation varies according to the type of asset.", plainLanguageNe: "Sampati ko value ghatda tyo ghati lai pani income bata ghatayera tax kam garna milcha. Different assets ko different depreciation rate.", plainLanguageEn: "You can deduct the decrease in value of assets (depreciation) from your income to reduce tax. Different asset types have different rates.", practicalExample: "Machinery cost Rs 1,000,000, depreciation rate 15% → Deduct Rs 150,000 per year", commonQuestions: ["Kun asset ma depreciation lagcha?", "Depreciation kasaari calculate garne?"], exceptions: ["Land does not depreciate"], relatedSections: ["Section 93 - Deductions"], intent: "legal_qa", notTransaction: true},
  {id: "legsec-008", documentType: "Income Tax Act 2058", documentTypeKey: "income_tax_act_2058", section: "Section 95 - Loss Carry Forward", sectionKey: "section_95_loss_carry_forward", originalTextNe: "कुनै वर्षमा घाटा भएमा सो घाटालाई अर्को ७ वर्षसम्म आयसँग साट्न पाइनेछ।", originalTextEn: "If there is a loss in any year, such loss may be set off against income for up to 7 subsequent years.", plainLanguageNe: "Yadi kunai saal business ma ghati bhayo bhane tyo ghati lai aune 7 saal samma ko nafa sanga jodera tax kam garna sakinchha.", plainLanguageEn: "If you have a business loss, you can carry it forward and set it off against profits for up to 7 years, reducing tax.", practicalExample: "Loss of Rs 200,000 in 2023, profit Rs 300,000 in 2024 → Tax on Rs 100,000 only", commonQuestions: ["Kati saal samma carry forward garna milcha?", "Loss carry forward garda ke form bharnu parcha?"], exceptions: ["Certain losses cannot be carried forward if ownership changes"], relatedSections: ["Section 96 - Group Relief"], intent: "legal_qa", notTransaction: true},
  {id: "legsec-009", documentType: "Income Tax Act 2058", documentTypeKey: "income_tax_act_2058", section: "Section 96 - Tax Rates for Individuals", sectionKey: "section_96_tax_rates_for_individuals", originalTextNe: "व्यक्तिगत आयकर दर वार्षिक आयको आधारमा निम्नानुसार हुनेछ: ५ लाखसम्म १%, ५–१० लाख १०%, १०–२० लाख २०%, २० लाखभन्दा माथि ३०%।", originalTextEn: "Personal income tax rates shall be as follows based on annual income: up to 500,000 – 1%, 500,001–1,000,000 – 10%, 1,000,001–2,000,000 – 20%, above 2,000,000 – 30%.", plainLanguageNe: "Tapaiko annual income anusar tax rate: 5 lakhs samma 1%, 5–10 lakhs 10%, 10–20 lakhs 20%, 20 lakhs mathi 30%.", plainLanguageEn: "Income tax rates: up to NPR 500k – 1%, 500k-1M – 10%, 1M-2M – 20%, above 2M – 30%.", practicalExample: "Income Rs 1,500,000 → Tax = 1% on 500k + 10% on 500k + 20% on 500k = 5,000+50,000+100,000 = 155,000", commonQuestions: ["Social security tax pani lagcha?", "Senior citizen lai discount?"], exceptions: ["Senior citizens get an additional 10% discount on tax liability"], relatedSections: ["Section 97 - Tax Rebates"], intent: "legal_qa", notTransaction: true},
  {id: "legsec-010", documentType: "Income Tax Act 2058", documentTypeKey: "income_tax_act_2058", section: "Section 97 - Tax Rebates for Investment", sectionKey: "section_97_tax_rebates_for_investment", originalTextNe: "निर्धारित क्षेत्रमा लगानी गरेमा आयकरमा छुट वा रियायत प्राप्त हुनेछ।", originalTextEn: "Investment in specified sectors shall be eligible for tax rebates or concessions.", plainLanguageNe: "Kunai special sector (jaise agriculture, tourism) ma lagaani garyo bhane tax ma discount paucha.", plainLanguageEn: "If you invest in specified sectors (e.g., agriculture, tourism), you may get tax rebates.", practicalExample: "Invest Rs 500,000 in approved tourism project → Get 10% rebate on tax liability", commonQuestions: ["Kun sector ma lagani garda rebate pauncha?", "Rebate kasari claim garne?"], exceptions: ["Rebate limited to 50% of tax liability"], relatedSections: ["Section 98 - Special Tax Incentives"], intent: "legal_qa", notTransaction: true},
  {id: "legsec-011", documentType: "Income Tax Act 2058", documentTypeKey: "income_tax_act_2058", section: "Section 98 - Filing of Return", sectionKey: "section_98_filing_of_return", originalTextNe: "प्रत्येक करदाताले प्रत्येक आर्थिक वर्षको मध्य माघसम्म कर विवरण पेश गर्नु पर्नेछ।", originalTextEn: "Every taxpayer shall file a tax return by mid-Magh (end of January) of each fiscal year.", plainLanguageNe: "Hare sal magh mas samma income tax return bharnu parcha. Natra fine lagna sakcha.", plainLanguageEn: "File your income tax return by the end of January each year. Late filing incurs penalties.", practicalExample: "Fiscal year ends Ashadh (July). Return due by Magh (Jan) – about 6 months later.", commonQuestions: ["Return online kasari bharne?", "Kati galti bhaye ke garne?"], exceptions: ["Extension may be granted for valid reasons"], relatedSections: ["Section 99 - Penalty for Non-compliance"], intent: "legal_qa", notTransaction: true},
  {id: "legsec-012", documentType: "Income Tax Act 2058", documentTypeKey: "income_tax_act_2058", section: "Section 99 - Penalty for Non-compliance", sectionKey: "section_99_penalty_for_non_compliance", originalTextNe: "कर विवरण पेश गर्न नसकेमा वा गलत विवरण पेश गरेमा जरिवाना र थप कर लाग्नेछ।", originalTextEn: "Failure to file return or filing incorrect return shall attract penalties and additional tax.", plainLanguageNe: "Return time ma nahalyam or galat halyam bhane jariwana tirnu parcha. Ani tax pani tirnu parcha.", plainLanguageEn: "Late or incorrect filing leads to penalties and interest. Be careful.", practicalExample: "Return filed 3 months late → Penalty 10% of tax + interest 15% per annum", commonQuestions: ["Penalty kati ho?", "Galti correction garna milcha?"], exceptions: ["No penalty if reasonable cause is shown"], relatedSections: ["Section 100 - Appeals"], intent: "legal_qa", notTransaction: true},
  {id: "legsec-013", documentType: "VAT Act 2052", documentTypeKey: "vat_act_2052", section: "Section 3 - Registration for VAT", sectionKey: "section_3_registration_for_vat", originalTextNe: "वार्षिक कारोबार रू. २० लाखभन्दा बढी हुने प्रत्येक व्यवसायीले VAT दर्ता गर्नु पर्नेछ।", originalTextEn: "Every business with annual turnover exceeding NPR 2 million shall register for VAT.", plainLanguageNe: "Yadi tapaiko business ko sal ko karobar 20 lakhs bhanda badhi cha bhane VAT registration garnu parcha.", plainLanguageEn: "If your annual turnover exceeds NPR 2 million, you must register for VAT.", practicalExample: "Turnover Rs 2.5 million → Must register; turnover Rs 1.8 million → optional registration", commonQuestions: ["VAT registration kaile garne?", "Registration nagare ke huncha?"], exceptions: ["Certain goods/services exempt from VAT registration"], relatedSections: ["Section 4 - Deregistration"], intent: "legal_qa", notTransaction: true},
  {id: "legsec-014", documentType: "VAT Act 2052", documentTypeKey: "vat_act_2052", section: "Section 4 - Deregistration", sectionKey: "section_4_deregistration", originalTextNe: "VAT दर्ता भएको व्यवसायीले व्यवसाय बन्द गरेमा वा कारोबार सीमा घटेमा VAT दर्ता रद्द गर्न सकिन्छ।", originalTextEn: "A VAT-registered business may deregister if it closes down or turnover falls below the threshold.", plainLanguageNe: "Business banda bhayo ya turnover ghatyo bhane VAT registration cancel garna milcha.", plainLanguageEn: "You can cancel VAT registration if you stop business or turnover drops below the limit.", practicalExample: "Business closed → Apply for deregistration within 15 days", commonQuestions: ["Deregistration ko lagi ke form cha?", "Deregister nagare ke huncha?"], exceptions: ["Deregistration may be refused if tax dues are pending"], relatedSections: ["Section 3 - Registration"], intent: "legal_qa", notTransaction: true},
  {id: "legsec-015", documentType: "VAT Act 2052", documentTypeKey: "vat_act_2052", section: "Section 5 - Tax Invoice", sectionKey: "section_5_tax_invoice", originalTextNe: "VAT दर्ता भएका व्यवसायीले प्रत्येक बिक्रीको VAT सहितको इनभ्वाइस जारी गर्नु पर्नेछ।", originalTextEn: "A registered business shall issue a tax invoice with VAT for each sale.", plainLanguageNe: "VAT registered bhaye pachi har bechdai ma VAT sahit ko bill dinu parcha.", plainLanguageEn: "If registered, you must issue invoices showing VAT for every sale.", practicalExample: "Sale Rs 10,000 + VAT 13% = Rs 11,300 → Invoice shows VAT Rs 1,300", commonQuestions: ["Bill ma VAT clearly dekhna parcha?", "VAT na dekhaaye ke huncha?"], exceptions: ["Small cash sales below Rs 500 may not require invoice"], relatedSections: ["Section 6 - VAT Collection"], intent: "legal_qa", notTransaction: true},
  {id: "legsec-016", documentType: "VAT Act 2052", documentTypeKey: "vat_act_2052", section: "Section 6 - VAT Collection and Payment", sectionKey: "section_6_vat_collection_and_payment", originalTextNe: "VAT दर्ता व्यवसायीले बिक्री गर्दा VAT असुल गरी मासिक रूपमा राजश्व खातामा जम्मा गर्नु पर्नेछ।", originalTextEn: "A VAT-registered business shall collect VAT on sales and deposit it to the revenue account monthly.", plainLanguageNe: "Bechda VAT collect garne ani mahine ko 25 gate samma tyo VAT sarkar lai bujhau.", plainLanguageEn: "Collect VAT on sales and deposit to government by 25th of each month.", practicalExample: "Monthly sales Rs 500,000, VAT 13% = Rs 65,000 → Deposit by 25th of next month", commonQuestions: ["VAT kasari calculate garne?", "VAT deposit na gare ke huncha?"], exceptions: ["Small businesses may file quarterly"], relatedSections: ["Section 7 - Input Tax Credit"], intent: "legal_qa", notTransaction: true},
  {id: "legsec-017", documentType: "VAT Act 2052", documentTypeKey: "vat_act_2052", section: "Section 7 - Input Tax Credit", sectionKey: "section_7_input_tax_credit", originalTextNe: "व्यवसायको लागि खरिद गर्दा तिरेको VAT (इनपुट VAT) लाई बिक्री गर्दा उठाएको VAT (आउटपुट VAT) बाट कट्टी गर्न पाइनेछ।", originalTextEn: "Input VAT paid on purchases for business may be deducted from output VAT collected on sales.", plainLanguageNe: "Kina gareko saman ko VAT (input) lai bechda collect gareko VAT (output) bata ghatayera net VAT matra bujhnu parcha.", plainLanguageEn: "You can deduct the VAT you paid on purchases (input VAT) from the VAT you collected on sales (output VAT), and pay only the net amount.", practicalExample: "Input VAT Rs 30,000, Output VAT Rs 50,000 → Pay net Rs 20,000", commonQuestions: ["Kun kun kura ma input VAT claim garna milcha?", "Input VAT claim garna ke chahincha?"], exceptions: ["Input VAT on personal items not claimable"], relatedSections: ["Section 8 - VAT Returns"], intent: "legal_qa", notTransaction: true},
  {id: "legsec-018", documentType: "VAT Act 2052", documentTypeKey: "vat_act_2052", section: "Section 8 - Filing VAT Returns", sectionKey: "section_8_filing_vat_returns", originalTextNe: "VAT दर्ता व्यवसायीले प्रत्येक महिनाको २५ गतेभित्र VAT विवरण पेश गर्नु पर्नेछ।", originalTextEn: "VAT-registered businesses shall file VAT returns by the 25th of each month.", plainLanguageNe: "Hare mahina ko 25 gate samma VAT return online bharnu parcha. Natra jariwana.", plainLanguageEn: "File VAT return by 25th of each month. Late filing attracts penalties.", practicalExample: "Return for July due by Aug 25", commonQuestions: ["Return online kaha bharne?", "Late filing ko kati penalty?"], exceptions: ["Quarterly filing for certain businesses"], relatedSections: ["Section 9 - Assessment"], intent: "legal_qa", notTransaction: true},
  {id: "legsec-019", documentType: "VAT Act 2052", documentTypeKey: "vat_act_2052", section: "Section 9 - Assessment and Penalty", sectionKey: "section_9_assessment_and_penalty", originalTextNe: "VAT विवरण नपेश गरेमा वा गलत विवरण पेश गरेमा कर अधिकृतले पुनः मूल्यांकन गरी जरिवाना लगाउन सक्छ।", originalTextEn: "If return is not filed or is incorrect, the tax officer may reassess and impose penalties.", plainLanguageNe: "Return nahalya ya galat halya bhane tax officer le check garera penalty lagauna sakcha.", plainLanguageEn: "Failure to file or incorrect filing may lead to reassessment and penalties by tax authorities.", practicalExample: "Underpaid VAT by Rs 10,000 → Penalty 50% of tax = Rs 5,000", commonQuestions: ["Penalty kati lagcha?", "Appeal garna milcha?"], exceptions: ["Penalty waived if voluntary disclosure"], relatedSections: ["Section 10 - Appeal"], intent: "legal_qa", notTransaction: true},
  {id: "legsec-020", documentType: "VAT Act 2052", documentTypeKey: "vat_act_2052", section: "Section 10 - Exempt Goods and Services", sectionKey: "section_10_exempt_goods_and_services", originalTextNe: "निर्दिष्ट वस्तु र सेवाहरू (जस्तै, शिक्षा, स्वास्थ्य) VAT बाट मुक्त हुनेछन्।", originalTextEn: "Specified goods and services (e.g., education, health) are exempt from VAT.", plainLanguageNe: "Kunai saman ra sewa (school, hospital) ma VAT lagdaina.", plainLanguageEn: "Some goods/services like education and healthcare are VAT-free.", practicalExample: "School fees – no VAT; Health services – no VAT", commonQuestions: ["Kun kun saman VAT exempt?", "Exempt ra zero-rated ma k farak?"], exceptions: ["Exemption applies only if provided by registered entities"], relatedSections: ["Section 11 - Zero-rated Supplies"], intent: "legal_qa", notTransaction: true},
  {id: "legsec-021", documentType: "VAT Act 2052", documentTypeKey: "vat_act_2052", section: "Section 11 - Zero-rated Supplies", sectionKey: "section_11_zero_rated_supplies", originalTextNe: "निर्यात गरिने वस्तु तथा सेवामा VAT दर शून्य प्रतिशत हुनेछ, तर इनपुट VAT कट्टी गर्न पाइनेछ।", originalTextEn: "Exported goods and services are zero-rated (0% VAT), but input VAT can be claimed.", plainLanguageNe: "Export ma VAT 0% lagcha, tara input VAT bhanne claim garna paucha.", plainLanguageEn: "Exports are zero-rated – you don't charge VAT, but you can still claim input VAT credits.", practicalExample: "Export sales Rs 1,000,000, input VAT Rs 50,000 → Can claim Rs 50,000 refund", commonQuestions: ["Zero-rated ra exempt ma k farak?", "Refund kasari paune?"], exceptions: ["Must have export documentation"], relatedSections: ["Section 10 - Exempt Goods"], intent: "legal_qa", notTransaction: true},
  {id: "legsec-022", documentType: "VAT Act 2052", documentTypeKey: "vat_act_2052", section: "Section 12 - VAT Refund", sectionKey: "section_12_vat_refund", originalTextNe: "यदि इनपुट VAT आउटपुट VAT भन्दा बढी भएमा सो फरक रकम फिर्ता पाउन सकिन्छ।", originalTextEn: "If input VAT exceeds output VAT, the excess amount may be refunded.", plainLanguageNe: "Input VAT output VAT bhanda badhi bhaye tyo farak sarkar le phirta dincha.", plainLanguageEn: "If you paid more VAT on purchases than you collected on sales, you can get a refund of the excess.", practicalExample: "Input VAT Rs 70,000, Output Rs 50,000 → Claim refund Rs 20,000", commonQuestions: ["Refund kasari claim garne?", "Refund pauna kati samay lagcha?"], exceptions: ["Refund may be adjusted against other tax dues"], relatedSections: ["Section 11 - Zero-rated Supplies"], intent: "legal_qa", notTransaction: true},
  {id: "legsec-023", documentType: "Company Act 2063", documentTypeKey: "company_act_2063", section: "Section 4 - Incorporation of Company", sectionKey: "section_4_incorporation_of_company", originalTextNe: "कम्पनी दर्ताको लागि आवेदन दिनु पर्नेछ र नाम स्वीकृत गर्नु पर्नेछ।", originalTextEn: "An application must be submitted for company registration and the name must be approved.", plainLanguageNe: "Company banuna lagi naam swikriti ra registration apply garnu parcha.", plainLanguageEn: "To form a company, you must apply for registration and get name approval.", practicalExample: "Apply with proposed name and MOA/AOA; get certificate of incorporation", commonQuestions: ["Kati din ma company register huncha?", "Kun documents chaincha?"], exceptions: ["Name must not be identical to existing company"], relatedSections: ["Section 5 - Memorandum and Articles"], intent: "legal_qa", notTransaction: true},
  {id: "legsec-024", documentType: "Company Act 2063", documentTypeKey: "company_act_2063", section: "Section 5 - Memorandum and Articles of Association", sectionKey: "section_5_memorandum_and_articles_of_association", originalTextNe: "कम्पनी दर्ताका लागि प्रबन्धपत्र र नियमावली पेश गर्नु पर्नेछ।", originalTextEn: "Memorandum and Articles of Association must be submitted for company registration.", plainLanguageNe: "Company register garda MOA ra AOA submit garnu parcha.", plainLanguageEn: "Submit MOA (objectives) and AOA (rules) for registration.", practicalExample: "MOA states business objectives; AOA contains internal management rules", commonQuestions: ["MOA ra AOA ma ke lekhnu parcha?", "Kati jana director chaincha?"], exceptions: ["One-person company may have simpler AOA"], relatedSections: ["Section 4 - Incorporation"], intent: "legal_qa", notTransaction: true},
  {id: "legsec-025", documentType: "Company Act 2063", documentTypeKey: "company_act_2063", section: "Section 6 - Directors and Their Duties", sectionKey: "section_6_directors_and_their_duties", originalTextNe: "प्रत्येक कम्पनीमा कम्तीमा एक जना सञ्चालक हुनु पर्नेछ र उसले कम्पनीको हितमा काम गर्नु पर्नेछ।", originalTextEn: "Every company shall have at least one director, who shall act in the best interests of the company.", plainLanguageNe: "Company ma kamti ma 1 director hunu parcha, ra usle company ko hit ma matra kaam garnu parcha.", plainLanguageEn: "Each company must have at least one director. The director must act in the company's best interests.", practicalExample: "Director decides on business strategies and ensures compliance", commonQuestions: ["Director ko duty k ho?", "Director lai salary dinu parcha?"], exceptions: ["Public companies need at least 3 directors"], relatedSections: ["Section 7 - Director's Liability"], intent: "legal_qa", notTransaction: true},
  {id: "legsec-026", documentType: "Company Act 2063", documentTypeKey: "company_act_2063", section: "Section 7 - Director's Liability", sectionKey: "section_7_director_s_liability", originalTextNe: "सञ्चालकले आफ्नो कर्तव्य पालना नगरेमा वा कम्पनीलाई नोक्सानी पुर्याएमा उसले क्षतिपूर्ति दिनु पर्नेछ।", originalTextEn: "A director who fails to perform duties or causes loss to the company shall be liable for compensation.", plainLanguageNe: "Director le duty palana nagarya ya company lai ghata diye bhane usle tyo ghata tirnu parcha.", plainLanguageEn: "Directors are personally liable if they breach duties or cause damage to the company.", practicalExample: "Director makes unauthorized loan causing loss → Must reimburse", commonQuestions: ["Director ko personal liability kati samma?", "Insurance le cover garcha?"], exceptions: ["Liability may be limited if acting in good faith"], relatedSections: ["Section 6 - Directors"], intent: "legal_qa", notTransaction: true},
  {id: "legsec-027", documentType: "Company Act 2063", documentTypeKey: "company_act_2063", section: "Section 8 - Share Capital and Shares", sectionKey: "section_8_share_capital_and_shares", originalTextNe: "कम्पनीको सेयर पूँजी सेयरमा विभाजन गरिनेछ र सेयरधनीहरूको दायित्व सीमित हुनेछ।", originalTextEn: "The share capital of the company shall be divided into shares, and shareholders' liability shall be limited.", plainLanguageNe: "Company ko paisa lai shares ma bhaag garincha, ra share dhani ko limit tinka shares ko amount samma matra.", plainLanguageEn: "Company capital is divided into shares; shareholders' liability is limited to unpaid share amount.", practicalExample: "Authorized capital Rs 1 crore, divided into 100,000 shares of Rs 100 each", commonQuestions: ["Share k ho?", "Shareholder ko liability kati ho?"], exceptions: ["Unlimited companies have unlimited liability"], relatedSections: ["Section 9 - Issue of Shares"], intent: "legal_qa", notTransaction: true},
  {id: "legsec-028", documentType: "Company Act 2063", documentTypeKey: "company_act_2063", section: "Section 9 - Issue of Shares", sectionKey: "section_9_issue_of_shares", originalTextNe: "कम्पनीले निर्देशिका (prospectus) जारी गरी सर्वसाधारणलाई सेयर बिक्री गर्न सक्छ।", originalTextEn: "A company may issue a prospectus and offer shares to the public.", plainLanguageNe: "Company le public lai share bechna prospectus nikalna sakcha.", plainLanguageEn: "A company can issue shares to the public through a prospectus.", practicalExample: "IPO issue of 500,000 shares at Rs 100 each", commonQuestions: ["IPO ma kasari apply garne?", "Minimum shares kati?"], exceptions: ["Private companies cannot issue shares to public"], relatedSections: ["Section 8 - Share Capital"], intent: "legal_qa", notTransaction: true},
  {id: "legsec-029", documentType: "Company Act 2063", documentTypeKey: "company_act_2063", section: "Section 10 - Annual General Meeting", sectionKey: "section_10_annual_general_meeting", originalTextNe: "प्रत्येक कम्पनीले प्रत्येक आर्थिक वर्षको अन्त्यमा वार्षिक साधारण सभा गर्नु पर्नेछ।", originalTextEn: "Every company shall hold an Annual General Meeting (AGM) at the end of each fiscal year.", plainLanguageNe: "Hare company le har sal AGM garnu parcha. Shareholders lai bulaera report sunaunu parcha.", plainLanguageEn: "Hold AGM yearly to present financials and elect directors.", practicalExample: "AGM within 6 months of year-end; shareholders vote on accounts", commonQuestions: ["AGM kab garne?", "AGM ma ke discuss garne?"], exceptions: ["One-person company may not need AGM"], relatedSections: ["Section 11 - Special Resolution"], intent: "legal_qa", notTransaction: true},
  {id: "legsec-030", documentType: "Company Act 2063", documentTypeKey: "company_act_2063", section: "Section 11 - Special Resolution", sectionKey: "section_11_special_resolution", originalTextNe: "कम्पनीको ठूलो निर्णय (जस्तै, नाम परिवर्तन, पूँजी वृद्धि) का लागि विशेष प्रस्ताव पारित गर्नु पर्नेछ।", originalTextEn: "Major decisions (e.g., change of name, increase of capital) require a special resolution.", plainLanguageNe: "Company ko thulo nirnaya (name change, capital badhaune) lai special resolution chahincha, jasma 75% shareholder ko sahamati.", plainLanguageEn: "Special resolution (75% votes) needed for major changes like name, capital, etc.", practicalExample: "Increase capital from Rs 1 crore to Rs 2 crore → Special resolution required", commonQuestions: ["Special resolution kasari pass garne?", "Kati percent chahincha?"], exceptions: ["Certain changes may not need special resolution if AOA allows"], relatedSections: ["Section 10 - AGM"], intent: "legal_qa", notTransaction: true},
  {id: "legsec-031", documentType: "Company Act 2063", documentTypeKey: "company_act_2063", section: "Section 12 - Audit and Accounts", sectionKey: "section_12_audit_and_accounts", originalTextNe: "प्रत्येक कम्पनीले आफ्नो लेखा अडिट गराउनु पर्नेछ र अडिटर नियुक्त गर्नु पर्नेछ।", originalTextEn: "Every company shall have its accounts audited and appoint an auditor.", plainLanguageNe: "Company ko account haru auditor le check garnu parcha, ra auditor appoint garnu parcha.", plainLanguageEn: "Every company must appoint an auditor and get accounts audited annually.", practicalExample: "Appoint a chartered accountant as auditor; submit audited financials to ROC", commonQuestions: ["Auditor kasaari chhane?", "Audit kab garne?"], exceptions: ["Small companies may be exempt from audit"], relatedSections: ["Section 13 - Financial Statements"], intent: "legal_qa", notTransaction: true},
  {id: "legsec-032", documentType: "Labor Act 2074", documentTypeKey: "labor_act_2074", section: "Section 10 - Employment Contract", sectionKey: "section_10_employment_contract", originalTextNe: "रोजगारीको सर्तहरू लिखित रूपमा उल्लेख गर्नु पर्नेछ र दुवै पक्षले हस्ताक्षर गर्नु पर्नेछ।", originalTextEn: "Terms of employment must be in writing and signed by both parties.", plainLanguageNe: "Job ko condition haru paper ma lekhera dui jana le signature garnu parcha.", plainLanguageEn: "Employment terms must be documented in a written contract signed by both employer and employee.", practicalExample: "Contract includes job role, salary, working hours, leave, termination", commonQuestions: ["Contract ma ke lekhnu parcha?", "Contract na bhaye ke huncha?"], exceptions: ["Oral contracts for casual work may be allowed"], relatedSections: ["Section 11 - Working Hours"], intent: "legal_qa", notTransaction: true},
  {id: "legsec-033", documentType: "Labor Act 2074", documentTypeKey: "labor_act_2074", section: "Section 11 - Working Hours", sectionKey: "section_11_working_hours", originalTextNe: "दैनिक कामको समय ८ घण्टा र साप्ताहिक ४८ घण्टा भन्दा बढी हुनु हुँदैन।", originalTextEn: "Daily working hours shall not exceed 8 hours and weekly hours shall not exceed 48 hours.", plainLanguageNe: "Hare din 8 ghanta, hapta ma 48 ghanta bhanda dherai kaam garna mildaina.", plainLanguageEn: "Maximum 8 hours/day and 48 hours/week.", practicalExample: "Work from 9am to 5pm with 1-hour lunch break = 7 hours? Actually 8 hours net, so 9-6 with 1 hour break.", commonQuestions: ["Break time pani count huncha?", "Overtime ma kati extra pay?"], exceptions: ["Certain industries (e.g., hospitality) may have different arrangements"], relatedSections: ["Section 12 - Overtime"], intent: "legal_qa", notTransaction: true},
  {id: "legsec-034", documentType: "Labor Act 2074", documentTypeKey: "labor_act_2074", section: "Section 12 - Overtime", sectionKey: "section_12_overtime", originalTextNe: "अतिरिक्त समयमा काम गराउँदा सामान्य ज्यालाको दोब्बर भत्ता दिनु पर्नेछ।", originalTextEn: "Overtime work shall be compensated at double the normal wage rate.", plainLanguageNe: "Regular time bhayeko kaam garema tyas ko double pay dinu parcha.", plainLanguageEn: "Overtime pay = 2x normal hourly rate.", practicalExample: "Normal hourly rate Rs 500; overtime hour = Rs 1,000", commonQuestions: ["Overtime kasari count garne?", "Overtime garna mann chaina bhane?"], exceptions: ["Some managerial staff may be exempt from overtime"], relatedSections: ["Section 11 - Working Hours"], intent: "legal_qa", notTransaction: true},
  {id: "legsec-035", documentType: "Labor Act 2074", documentTypeKey: "labor_act_2074", section: "Section 13 - Leave Entitlement", sectionKey: "section_13_leave_entitlement", originalTextNe: "कर्मचारीले वार्षिक १३ दिन सार्वजनिक बिदा, १२ दिन चाडपर्व बिदा, र १५ दिन बिरामी बिदा पाउनेछन्।", originalTextEn: "Employees are entitled to 13 days public holiday, 12 days festival leave, and 15 days sick leave per year.", plainLanguageNe: "Hare saal 13 din public holiday, 12 din festival leave, 15 din sick leave pauncha.", plainLanguageEn: "Annual leave: 13 public, 12 festival, 15 sick days.", practicalExample: "Employee takes 10 days festival leave; remaining 2 days to be encashed or carried over", commonQuestions: ["Leave carry forward huncha?", "Napaye paisa paucha?"], exceptions: ["Probation period may not get full leave"], relatedSections: ["Section 14 - Maternity Leave"], intent: "legal_qa", notTransaction: true},
  {id: "legsec-036", documentType: "Labor Act 2074", documentTypeKey: "labor_act_2074", section: "Section 14 - Maternity Leave", sectionKey: "section_14_maternity_leave", originalTextNe: "महिला कर्मचारीले सुत्केरी बिदा ६० दिन पाउनेछिन् र त्यस अवधिमा पूर्ण तलब पाउनेछिन्।", originalTextEn: "Female employees are entitled to 60 days maternity leave with full pay.", plainLanguageNe: "Mahila karmachari lai 60 din maternity leave paucha, tyo bela full salary dinu parcha.", plainLanguageEn: "60 days fully paid maternity leave for female employees.", practicalExample: "Employee takes maternity leave; receives salary as usual for 60 days", commonQuestions: ["Maternity leave pachi ke garnu parcha?", "Adoption ma pani paucha?"], exceptions: ["Only for employees who have worked for certain period"], relatedSections: ["Section 15 - Paternity Leave"], intent: "legal_qa", notTransaction: true},
  {id: "legsec-037", documentType: "Labor Act 2074", documentTypeKey: "labor_act_2074", section: "Section 15 - Paternity Leave", sectionKey: "section_15_paternity_leave", originalTextNe: "पुरुष कर्मचारीले आफ्नो बच्चा जन्मिएको १५ दिनभित्र १५ दिन पितृत्व बिदा पाउनेछन्।", originalTextEn: "Male employees are entitled to 15 days paternity leave within 15 days of childbirth.", plainLanguageNe: "Purush karmachari lai baccha janme pachi 15 din paternity leave paucha.", plainLanguageEn: "15 days paternity leave for male employees, to be taken soon after child's birth.", practicalExample: "Child born on Jan 1 → Take leave from Jan 2-16", commonQuestions: ["Paternity leave kaile line?", "Kun bela apply garne?"], exceptions: ["Leave may be granted only once per year"], relatedSections: ["Section 14 - Maternity Leave"], intent: "legal_qa", notTransaction: true},
  {id: "legsec-038", documentType: "Labor Act 2074", documentTypeKey: "labor_act_2074", section: "Section 16 - Termination of Employment", sectionKey: "section_16_termination_of_employment", originalTextNe: "रोजगारी समाप्त गर्नु अघि ३० दिनको नोटिस दिनु पर्नेछ वा सो बराबरको ज्याला दिनु पर्नेछ।", originalTextEn: "Employment termination requires 30 days' notice or pay in lieu of notice.", plainLanguageNe: "Job chodna ya nikalna lai 30 din agadi bhanu parcha, natra 30 din ko paisa tirnu parcha.", plainLanguageEn: "30 days' notice or 30 days' pay must be given for termination.", practicalExample: "Employer terminates without notice → Pays 30 days salary in lieu", commonQuestions: ["Notice period kati ho?", "Termination pay kasari calculate garne?"], exceptions: ["Summary dismissal for gross misconduct may not require notice"], relatedSections: ["Section 17 - Severance Pay"], intent: "legal_qa", notTransaction: true},
  {id: "legsec-039", documentType: "Labor Act 2074", documentTypeKey: "labor_act_2074", section: "Section 17 - Severance Pay", sectionKey: "section_17_severance_pay", originalTextNe: "रोजगारी समाप्त भएमा कर्मचारीले काम गरेको अवधिको आधारमा अलग्याउने पारिश्रमिक पाउनेछ।", originalTextEn: "Upon termination, the employee shall receive severance pay based on length of service.", plainLanguageNe: "Job chhode pachi kaam gareko barsa anusar severance pay paucha.", plainLanguageEn: "Severance pay = at least 30 days' salary for each year of service, plus remaining leave encashment.", practicalExample: "5 years service → 5 x 30 days = 150 days salary as severance", commonQuestions: ["Severance pay kati ho?", "Kaile paucha?"], exceptions: ["May be less if termination for cause"], relatedSections: ["Section 16 - Termination"], intent: "legal_qa", notTransaction: true},
  {id: "legsec-040", documentType: "Labor Act 2074", documentTypeKey: "labor_act_2074", section: "Section 18 - Prohibition of Discrimination", sectionKey: "section_18_prohibition_of_discrimination", originalTextNe: "रोजगारीमा जात, लिङ्ग, धर्म, क्षेत्र, वा अपांगताको आधारमा भेदभाव गर्न पाइँदैन।", originalTextEn: "Discrimination in employment on grounds of caste, gender, religion, region, or disability is prohibited.", plainLanguageNe: "Job ma jati, ling, dharma, thau, apangata ko aadhar ma bhedbhav garna paudaina.", plainLanguageEn: "No discrimination in hiring, promotion, or termination based on caste, gender, etc.", practicalExample: "Cannot reject applicant solely because of gender or caste", commonQuestions: ["Discrimination bhaye ke garne?", "Complaint kaha garne?"], exceptions: ["Affirmative action may be allowed for disadvantaged groups"], relatedSections: ["Section 19 - Grievance Procedure"], intent: "legal_qa", notTransaction: true},
  {id: "legsec-041", documentType: "Labor Act 2074", documentTypeKey: "labor_act_2074", section: "Section 19 - Grievance Procedure", sectionKey: "section_19_grievance_procedure", originalTextNe: "कर्मचारीले आफ्नो गुनासो लिखित रूपमा व्यवस्थापनलाई दिनु पर्नेछ र १५ दिनभित्र समाधान गर्नु पर्नेछ।", originalTextEn: "Employees shall submit grievances in writing to management, which shall resolve within 15 days.", plainLanguageNe: "Karmachari le kunai problem bhayeko paper ma management lai dinu, ra management le 15 din bhitra samadhan garnu.", plainLanguageEn: "Write a complaint to management; they must resolve within 15 days.", practicalExample: "Employee complains about harassment; management investigates and acts within 15 days", commonQuestions: ["Grievance kasari register garne?", "Samadhan na bhaye ke garne?"], exceptions: ["Urgent matters may be escalated immediately"], relatedSections: ["Section 20 - Labor Tribunal"], intent: "legal_qa", notTransaction: true},
  {id: "legsec-042", documentType: "Contract Clause - Employment", documentTypeKey: "contract_clause_employment", section: "Clause 5 - Confidentiality", sectionKey: "clause_5_confidentiality", originalTextNe: "कर्मचारीले रोजगारीको अवधिमा र पछि पनि कम्पनीको गोप्य जानकारी खुलाउनु हुँदैन।", originalTextEn: "The employee shall not disclose confidential information of the company during and after employment.", plainLanguageNe: "Job ma ra job chhode pachi pani company ko gopya kura kasaile bhandina.", plainLanguageEn: "Keep company secrets confidential, even after leaving.", practicalExample: "Employee signs NDA; cannot share trade secrets or client lists", commonQuestions: ["Confidentiality kati samma ko?", "Ullanghan bhaye ke huncha?"], exceptions: ["Information already public is not confidential"], relatedSections: ["Clause 6 - Non-compete"], intent: "legal_qa", notTransaction: true},
  {id: "legsec-043", documentType: "Contract Clause - Employment", documentTypeKey: "contract_clause_employment", section: "Clause 6 - Non-Compete", sectionKey: "clause_6_non_compete", originalTextNe: "रोजगारी समाप्त भएको १ वर्षसम्म कर्मचारीले प्रतिस्पर्धी कम्पनीमा काम गर्न वा आफ्नै प्रतिस्पर्धी व्यवसाय सुरु गर्न पाउँदैन।", originalTextEn: "The employee shall not work for a competitor or start a competing business for 1 year after termination.", plainLanguageNe: "Job chhode pachi 1 saal samma competitor company ma kaam garna paudaina, ani aafno competitor business suru garna paudaina.", plainLanguageEn: "Non-compete for 1 year after leaving; cannot join or start a competing business.", practicalExample: "Employee leaves IT firm; cannot join another IT firm for 1 year", commonQuestions: ["Non-compete enforceable ho?", "Kati distance samma?"], exceptions: ["May be void if too broad or unreasonable"], relatedSections: ["Clause 5 - Confidentiality"], intent: "legal_qa", notTransaction: true},
  {id: "legsec-044", documentType: "Contract Clause - Lease", documentTypeKey: "contract_clause_lease", section: "Clause 3 - Rent Payment", sectionKey: "clause_3_rent_payment", originalTextNe: "भाडादारले प्रत्येक महिनाको १ गतेभित्र भाडा तिर्नु पर्नेछ। ढिला गरेमा १०% जरिवाना लाग्नेछ।", originalTextEn: "The lessee shall pay rent by the 1st of each month. Late payment shall incur a 10% penalty.", plainLanguageNe: "Hare mahina ko 1 gate samma bhada tirnu parcha. Dherai bhaye 10% fine.", plainLanguageEn: "Pay rent by 1st of each month; late fee 10%.", practicalExample: "Rent Rs 20,000; if paid on 5th → pay Rs 22,000 (10% fine)", commonQuestions: ["Fine kati ho?", "Kun method ma tirne?"], exceptions: ["Grace period may be allowed in contract"], relatedSections: ["Clause 4 - Security Deposit"], intent: "legal_qa", notTransaction: true},
  {id: "legsec-045", documentType: "Contract Clause - Lease", documentTypeKey: "contract_clause_lease", section: "Clause 4 - Security Deposit", sectionKey: "clause_4_security_deposit", originalTextNe: "भाडादारले घरधनीलाई २ महिनाको भाडा बराबरको जमानत रकम जम्मा गर्नु पर्नेछ, जुन सम्झौता अन्त्यमा फिर्ता गरिनेछ।", originalTextEn: "The lessee shall deposit a security deposit equivalent to 2 months' rent, refundable at the end of the lease.", plainLanguageNe: "2 mahina ko bhada barabar ko security deposit rakhnu parcha, lease sakkepachi firta pauncha.", plainLanguageEn: "Pay 2 months rent as security deposit; refundable at lease end (less damages).", practicalExample: "Rent Rs 25,000 → Deposit Rs 50,000; returned after inspection", commonQuestions: ["Deposit kahile firta paucha?", "Kati katnu?"], exceptions: ["Deposit may be used to cover unpaid rent or damages"], relatedSections: ["Clause 3 - Rent"], intent: "legal_qa", notTransaction: true},
  {id: "legsec-046", documentType: "Contract Clause - Lease", documentTypeKey: "contract_clause_lease", section: "Clause 5 - Maintenance and Repairs", sectionKey: "clause_5_maintenance_and_repairs", originalTextNe: "घरधनीले प्रमुख मर्मत (छाना, पाइपलाइन) को खर्च बेहोर्नु पर्नेछ, र भाडादारले साना मर्मत (बत्ती, फिटिङ) को खर्च बेहोर्नु पर्नेछ।", originalTextEn: "The lessor shall bear major repairs (roof, pipes); the lessee shall bear minor repairs (lights, fittings).", plainLanguageNe: "Thulo mermat (chhana, pipeline) ghar dhani le garne; sano mermat (batti, fitting) bhadadar le garne.", plainLanguageEn: "Major repairs by owner, minor repairs by tenant.", practicalExample: "Leaking roof → owner pays; broken bulb → tenant pays", commonQuestions: ["Kun mermat ko paisa kasle tirne?", "Emergency mermat?"], exceptions: ["If damage caused by tenant, tenant pays"], relatedSections: ["Clause 6 - Termination"], intent: "legal_qa", notTransaction: true},
  {id: "legsec-047", documentType: "Contract Clause - Lease", documentTypeKey: "contract_clause_lease", section: "Clause 6 - Termination of Lease", sectionKey: "clause_6_termination_of_lease", originalTextNe: "कुनै पक्षले १ महिनाको पूर्व सूचना दिएर सम्झौता समाप्त गर्न सक्छ।", originalTextEn: "Either party may terminate the lease with 1 month's prior notice.", plainLanguageNe: "Pahile 1 mahina agadi bhanera lease todna milcha.", plainLanguageEn: "Terminate with 1 month notice.", practicalExample: "Tenant wants to leave; gives 30 days notice, vacates, gets deposit back", commonQuestions: ["Notice period kati ho?", "Notice na diye ke huncha?"], exceptions: ["If lease has fixed term, early termination may incur penalty"], relatedSections: ["Clause 4 - Security Deposit"], intent: "legal_qa", notTransaction: true},
  {id: "legsec-048", documentType: "Contract Clause - Sale", documentTypeKey: "contract_clause_sale", section: "Clause 7 - Price and Payment Terms", sectionKey: "clause_7_price_and_payment_terms", originalTextNe: "खरिदकर्ताले बिक्री मूल्यको ५०% पूर्वभुक्तानी र बाँकी ५०% डेलिभरीको १५ दिनभित्र तिर्नु पर्नेछ।", originalTextEn: "The buyer shall pay 50% advance and the remaining 50% within 15 days of delivery.", plainLanguageNe: "50% pehle dinu, baki 50% delivery pachi 15 din bhitra tirnu.", plainLanguageEn: "50% upfront, 50% within 15 days after delivery.", practicalExample: "Total Rs 100,000 → Pay Rs 50,000 now, Rs 50,000 on delivery+15 days", commonQuestions: ["Payment delay bhaye kati interest?", "Kun method ma tirne?"], exceptions: ["Cash discount for full payment upfront"], relatedSections: ["Clause 8 - Delivery"], intent: "legal_qa", notTransaction: true},
  {id: "legsec-049", documentType: "Contract Clause - Sale", documentTypeKey: "contract_clause_sale", section: "Clause 8 - Delivery", sectionKey: "clause_8_delivery", originalTextNe: "विक्रेताले खरिद आदेश प्राप्त भएको ३० दिनभित्र वस्तु डेलिभर गर्नु पर्नेछ। ढिला गरेमा ०.५% दैनिक जरिवाना।", originalTextEn: "The seller shall deliver goods within 30 days of purchase order. Late delivery incurs a daily penalty of 0.5% of the order value.", plainLanguageNe: "Order aayeko 30 din bhitra saman puraunai parcha. Dherai bhaye 0.5% din ko fine.", plainLanguageEn: "Deliver within 30 days; delay penalty 0.5% per day.", practicalExample: "Order Rs 500,000, delivery 10 days late → Penalty 500,000*0.5%*10 = 25,000", commonQuestions: ["Delivery time limit kati ho?", "Force majeure ma ke huncha?"], exceptions: ["Force majeure events may excuse delay"], relatedSections: ["Clause 7 - Payment"], intent: "legal_qa", notTransaction: true},
  {id: "legsec-050", documentType: "Contract Clause - Sale", documentTypeKey: "contract_clause_sale", section: "Clause 9 - Warranty", sectionKey: "clause_9_warranty", originalTextNe: "विक्रेताले बिक्री गरेको वस्तु १ वर्षसम्मको वारेन्टी प्रदान गर्नेछ। दोषपूर्ण वस्तुको मर्मत वा प्रतिस्थापन गरिनेछ।", originalTextEn: "The seller warrants the goods for 1 year. Defective goods will be repaired or replaced.", plainLanguageNe: "1 saal ko guarantee; saman bigriya bhane repair ya naya dinu parcha.", plainLanguageEn: "1-year warranty: repair or replace defective items.", practicalExample: "Product fails within 6 months → Seller repairs free of charge", commonQuestions: ["Warranty ma ke cover huncha?", "Claim kasari garne?"], exceptions: ["Warranty excludes damage due to misuse"], relatedSections: ["Clause 10 - Returns"], intent: "legal_qa", notTransaction: true},
  {id: "legsec-051", documentType: "Contract Clause - Sale", documentTypeKey: "contract_clause_sale", section: "Clause 10 - Returns and Refunds", sectionKey: "clause_10_returns_and_refunds", originalTextNe: "खरिदकर्ताले डेलिभरीको ७ दिनभित्र दोषपूर्ण वस्तु फिर्ता गर्न सक्छ र पूरा रकम फिर्ता पाउन सक्छ।", originalTextEn: "The buyer may return defective goods within 7 days of delivery and receive a full refund.", plainLanguageNe: "Saman aako 7 din bhitra bigriyeko saman firta garna milcha, paisa firta paucha.", plainLanguageEn: "Full refund for defective goods returned within 7 days.", practicalExample: "Return faulty laptop within 7 days → get full Rs 100,000 back", commonQuestions: ["Return policy kati ho?", "Shipping cost kasle tirne?"], exceptions: ["Customized goods may not be returnable"], relatedSections: ["Clause 9 - Warranty"], intent: "legal_qa", notTransaction: true},
  {id: "legsec-052", documentType: "Government Circular", documentTypeKey: "government_circular", section: "Circular No. 1/2078 - Tax Filing Deadlines", sectionKey: "circular_no_1_2078_tax_filing_deadlines", originalTextNe: "आर्थिक वर्ष २०७८/७९ को आयकर विवरण पेश गर्ने म्याद २०७९ माघ १५ गतेसम्म रहेको छ।", originalTextEn: "The deadline for filing income tax return for FY 2078/79 is extended to Magh 15, 2079 (January 30, 2023).", plainLanguageNe: "Income tax return bharna ko lagi time badayera Magh 15 samma diyeko cha.", plainLanguageEn: "Tax return filing deadline extended to Jan 30.", practicalExample: "Return must be filed by Jan 30, otherwise penalty", commonQuestions: ["Deadline kati ho?", "Extension chaincha bhane ke garne?"], exceptions: ["Individual taxpayers may have different deadlines"], relatedSections: ["Circular No. 2/2078 - Late Filing"], intent: "legal_qa", notTransaction: true},
  {id: "legsec-053", documentType: "Government Circular", documentTypeKey: "government_circular", section: "Circular No. 2/2078 - Late Filing Penalty", sectionKey: "circular_no_2_2078_late_filing_penalty", originalTextNe: "समयमा कर विवरण नपेश गर्ने करदातालाई १०,००० रुपैयाँ जरिवाना तथा बाँकी करमा १५% ब्याज लाग्नेछ।", originalTextEn: "Taxpayers failing to file returns on time shall be subject to a penalty of NPR 10,000 and interest at 15% on tax due.", plainLanguageNe: "Return time ma nahalne lai 10,000 jariwana ra baaki tax ma 15% byaaj lagcha.", plainLanguageEn: "Late filing: NPR 10,000 penalty + 15% interest on unpaid tax.", practicalExample: "Tax due Rs 50,000, filed 2 months late → Penalty 10,000 + interest 50,000*15%*2/12 = 1,250", commonQuestions: ["Penalty kati ho?", "Byaaj kati lagcha?"], exceptions: ["Penalty may be waived for first-time offenders"], relatedSections: ["Circular No. 1/2078"], intent: "legal_qa", notTransaction: true},
  {id: "legsec-054", documentType: "Government Circular", documentTypeKey: "government_circular", section: "Circular No. 3/2079 - VAT Compliance Checklist", sectionKey: "circular_no_3_2079_vat_compliance_checklist", originalTextNe: "VAT दर्ता व्यवसायीहरूले अनिवार्य रूपमा इलेक्ट्रोनिक बिलिङ प्रणाली अपनाउनु पर्नेछ र मासिक विवरण पेश गर्नु पर्नेछ।", originalTextEn: "VAT-registered businesses must adopt electronic billing system and file monthly returns.", plainLanguageNe: "VAT registered business le electronic bill system use garnu parcha, ani mahina ko return bharnu parcha.", plainLanguageEn: "Mandatory e-billing and monthly returns for VAT registered entities.", practicalExample: "Implement billing software; send electronic invoices to customers", commonQuestions: ["E-billing system kasari suru garne?", "Kehi exemption cha?"], exceptions: ["Small businesses may get extension"], relatedSections: ["Circular No. 4/2079 - E-billing"], intent: "legal_qa", notTransaction: true},
  {id: "legsec-055", documentType: "Government Circular", documentTypeKey: "government_circular", section: "Circular No. 4/2079 - E-billing Implementation", sectionKey: "circular_no_4_2079_e_billing_implementation", originalTextNe: "आर्थिक वर्ष २०७९/८० देखि सबै VAT दर्ता व्यवसायीले अनिवार्य रूपमा इलेक्ट्रोनिक बिलिङ गर्नु पर्नेछ।", originalTextEn: "From FY 2079/80, all VAT-registered businesses must implement electronic billing.", plainLanguageNe: "Yo aarthik barsa dekhi sabai le electronic bill garna parcha.", plainLanguageEn: "Mandatory e-billing for all from this fiscal year.", practicalExample: "Generate QR code invoices; customers can verify VAT", commonQuestions: ["E-billing ko lagi ke software?", "Penalty for non-compliance?"], exceptions: ["Business in remote areas may get exemption"], relatedSections: ["Circular No. 3/2079"], intent: "legal_qa", notTransaction: true},
  {id: "legsec-056", documentType: "Government Circular", documentTypeKey: "government_circular", section: "Circular No. 5/2079 - Tax Deduction at Source for Rental", sectionKey: "circular_no_5_2079_tax_deduction_at_source_for_rental", originalTextNe: "भाडा भुक्तानी गर्दा १०% TDS कट्टा गर्ने र राजश्व जम्मा गर्ने प्रक्रिया स्पष्ट पारिएको छ।", originalTextEn: "Clarification issued on deducting 10% TDS on rent payments and depositing to revenue.", plainLanguageNe: "Bhada ko 10% TDS kasari cut garne ra bujhaune, tyo process clear gariyeko cha.", plainLanguageEn: "Guidance on 10% TDS on rent: deduction and deposition process.", practicalExample: "Deduct TDS, deposit via e-payment within 25 days of month end", commonQuestions: ["TDS deposit kahile garne?", "Kun form use garne?"], exceptions: ["Residential rent below Rs 50,000 per month exempt"], relatedSections: ["Income Tax Act Section 88"], intent: "legal_qa", notTransaction: true},
  {id: "legsec-057", documentType: "Government Circular", documentTypeKey: "government_circular", section: "Circular No. 6/2080 - Social Security Contribution", sectionKey: "circular_no_6_2080_social_security_contribution", originalTextNe: "सबै नियोक्ताले कर्मचारीको सामाजिक सुरक्षा कोषमा ११% र कर्मचारीबाट ११% कट्टी गरी जम्मा गर्नु पर्नेछ।", originalTextEn: "All employers must contribute 11% to social security fund and deduct 11% from employee salary.", plainLanguageNe: "Employer le 11% ra employee ko 11% social security fund ma bujhau.", plainLanguageEn: "Employer 11% + employee 11% social security contribution.", practicalExample: "Salary Rs 50,000 → Employer pays Rs 5,500, employee pays Rs 5,500", commonQuestions: ["Contribution kab garne?", "Exemption cha?"], exceptions: ["Certain temporary employees may be excluded"], relatedSections: ["Circular No. 7/2080 - SSF"], intent: "legal_qa", notTransaction: true},
  {id: "legsec-058", documentType: "Government Circular", documentTypeKey: "government_circular", section: "Circular No. 7/2080 - SSF Registration Deadline", sectionKey: "circular_no_7_2080_ssf_registration_deadline", originalTextNe: "सबै नियोक्ताले सामाजिक सुरक्षा कोषमा दर्ता गर्ने अन्तिम मिति २०८० असार १५ गते रहेको छ।", originalTextEn: "Deadline for employers to register with Social Security Fund is Ashad 15, 2080 (June 29, 2023).", plainLanguageNe: "SSF ma register garna last date Ashad 15 ho.", plainLanguageEn: "Register with SSF by June 29.", practicalExample: "Submit registration documents to SSF by the deadline", commonQuestions: ["Register nagare ke huncha?", "Late fee?"], exceptions: ["New businesses must register within 30 days of establishment"], relatedSections: ["Circular No. 6/2080"], intent: "legal_qa", notTransaction: true},
  {id: "legsec-059", documentType: "Government Circular", documentTypeKey: "government_circular", section: "Circular No. 8/2080 - Tax Rates for FY 2080/81", sectionKey: "circular_no_8_2080_tax_rates_for_fy_2080_81", originalTextNe: "आगामी आर्थिक वर्ष २०८०/८१ को लागि आयकर दरहरू यथावत राखिएको छ।", originalTextEn: "Income tax rates for the upcoming FY 2080/81 remain unchanged from previous year.", plainLanguageNe: "Naya barsa ko income tax rates pahile jasto nai cha.", plainLanguageEn: "Tax rates unchanged for next fiscal year.", practicalExample: "Same slab rates: 1%,10%,20%,30%", commonQuestions: ["New rates kati ho?", "Kunai change cha?"], exceptions: ["Rebates for senior citizens remain"], relatedSections: ["Circular No. 9/2080 - Rebates"], intent: "legal_qa", notTransaction: true},
  {id: "legsec-060", documentType: "Government Circular", documentTypeKey: "government_circular", section: "Circular No. 9/2080 - Tax Rebates for Senior Citizens", sectionKey: "circular_no_9_2080_tax_rebates_for_senior_citizens", originalTextNe: "७५ वर्षभन्दा माथिका करदातालाई आयकरमा १०% थप छुट दिइनेछ।", originalTextEn: "Taxpayers above 75 years shall receive an additional 10% discount on income tax.", plainLanguageNe: "75 barsa mathi ko lai tax ma 10% discount.", plainLanguageEn: "10% extra rebate for senior citizens aged 75+.", practicalExample: "Tax liability Rs 100,000 → after rebate Rs 90,000", commonQuestions: ["Rebate kasari claim garne?", "Age proof chaincha?"], exceptions: ["Only for resident individuals"], relatedSections: ["Circular No. 8/2080"], intent: "legal_qa", notTransaction: true},
  {id: "legsec-061", documentType: "Government Circular", documentTypeKey: "government_circular", section: "Circular No. 10/2080 - e-Payment of Taxes", sectionKey: "circular_no_10_2080_e_payment_of_taxes", originalTextNe: "सबै कर भुक्तानी अनलाइन माध्यमबाट गर्न अनिवार्य गरिएको छ। बैंक काउन्टरबाट भुक्तानी स्वीकार नगर्ने।", originalTextEn: "All tax payments must be made online. Bank counter payments will no longer be accepted.", plainLanguageNe: "Sabai tax online tirnu parcha. Bank ma gayera tirna mildaina.", plainLanguageEn: "Mandatory online tax payment; cash/cheque at bank counters not accepted.", practicalExample: "Use IRD's online portal to pay taxes", commonQuestions: ["Online payment kasari garne?", "Payment failed bhane ke garne?"], exceptions: ["Rural areas may have offline options"], relatedSections: ["Circular No. 3/2079"], intent: "legal_qa", notTransaction: true},
];

